        head = tk.Frame(win, bg=BG_PANEL, padx=14, pady=10); head.pack(fill=tk.X)
        tk.Label(head, text="⏪ Back-From-The-Future", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 15, "bold")).pack(side=tk.LEFT)
