            st = self._load_handoff_state() or {}
            if st.get("vision_last_watched", "") == date.today().isoformat():
                return
            self.set_status("🌤 Watch your Vision Board before your shift — see "
                            "the life you're building, vividly.")
            self._flash_vision_button()
