    # ---- Session Start wizard ------------------------------------------
    def open_session_start_wizard(self) -> None:
        """Popup form of the Session Start panel. The panel is normally
        embedded at the bottom of the dashboard (see _build_session_start_panel,
        built once in __init__); this modal popup is kept for completeness and
        manual reopen. Single-instance."""
        if self._session_start_win is not None:
            try:
                if self._session_start_win.winfo_exists():
                    self._session_start_win.lift()
                    self._session_start_win.focus_force()
                    return
            except tk.TclError:
                pass
            self._session_start_win = None

        win = tk.Toplevel(self.root)
        self._session_start_win = win
        win.title("🎯  Session Start")
        # Screen-fitted so the richer, tabbed layout never runs off a small
        # display (usable height can be ~617px on this laptop).
        try:
            sw = win.winfo_screenwidth(); sh = win.winfo_screenheight()
        except tk.TclError:
            sw, sh = 1280, 800
        w = min(880, max(560, sw - 80))
        h = min(720, max(500, sh - 110))
        x = max(0, (sw - w) // 2); y = max(0, (sh - h) // 2 - 24)
        win.geometry(f"{w}x{h}+{x}+{y}")
        win.minsize(560, 480)
        win.configure(bg=BG_DARK)
        # win.transient(self.root)  # disabled: hides Min/Max buttons on Windows
        try:
            win.grab_set()  # modal
        except tk.TclError:
            pass

        def _close():
            self._session_start_win = None
            try:
                win.destroy()
            except tk.TclError:
                pass
        win.protocol("WM_DELETE_WINDOW", _close)
        self._build_session_start_panel(win, dismiss=_close)

    def _build_session_start_panel(self, parent, dismiss=None) -> None:
        """Build the tabbed Session Start UI (Start / Wheel of Life / Goals)
        into `parent`. Shows last session's handoff message, prefills the
        primary-task field from last session's "next task", and on Begin
        records the session start in HANDOFF_STATE.

        `dismiss` distinguishes the two homes for this panel:
        - popup mode (dismiss=a close callback): adds a "Skip for now" button
          and closes the window on Begin.
        - inline mode (dismiss=None): the panel is embedded at the bottom of
          the dashboard and is always visible — no Skip, and Begin just saves
          (the panel stays put)."""
        inline = dismiss is None
        state = self._load_handoff_state()

        header = tk.Frame(parent, bg=BG_PANEL, padx=14, pady=12)
        header.pack(fill=tk.X)
        tk.Label(header, text="🎯  Session Start", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        tk.Label(header, text=date.today().strftime("%A · %B %d, %Y"),
                 bg=BG_PANEL, fg=FG_MUTED, font=("Segoe UI", 10)
                 ).pack(side=tk.RIGHT)

        # ---- Tabs: Start / Wheel of Life / Goals (the Ziglar Performance
        # Planner pieces), each in its own panel. ------------------------
        tabbar = tk.Frame(parent, bg=BG_PANEL, padx=10)
        tabbar.pack(fill=tk.X, pady=(0, 8))
        content = tk.Frame(parent, bg=BG_DARK)
        content.pack(fill=tk.BOTH, expand=True)
        ss_frames: dict = {}
        ss_buttons: dict = {}

        def _show_ss(key):
            for f in ss_frames.values():
                f.pack_forget()
            ss_frames[key].pack(fill=tk.BOTH, expand=True)
            for k, b in ss_buttons.items():
                b.configure(bg=ACCENT_SLATE if k == key else BG_INPUT,
                            fg="white" if k == key else FG_TEXT)

        for key, label in (("start", "🎯 Start"),
                           ("wheel", "☸ Wheel of Life"),
                           ("goals", "🎯 Goals")):
            b = tk.Button(tabbar, text=label,
                          command=lambda k=key: _show_ss(k),
                          font=("Segoe UI", 10, "bold"), bg=BG_INPUT, fg=FG_TEXT,
                          activebackground=ACCENT_SLATE, activeforeground="white",
                          relief=tk.FLAT, padx=10, pady=6, cursor="hand2",
                          borderwidth=0)
            b.pack(side=tk.LEFT, padx=(0, 3))
            ss_buttons[key] = b
            ss_frames[key] = tk.Frame(content, bg=BG_DARK)

        # 🎯 Matrix — a LAUNCHER tab (not an inline build). The Matrix is a
        # heavy stateful tab (4 quadrant editors + timer + autosave handlers);
        # building it twice would conflict on self._eisenhower_widgets. So this
        # tab opens the Study workspace and shows the existing Matrix tab.
        def _go_matrix():
            try:
                self.open_study_workspace()
                self._show_study_tab("matrix")
            except Exception as e:
                self.set_status(f"Could not open Matrix: {e}")
        tk.Button(tabbar, text="🎯 Matrix", command=_go_matrix,
                  font=("Segoe UI", 10, "bold"), bg=BG_INPUT, fg=FG_TEXT,
                  activebackground=ACCENT_SLATE, activeforeground="white",
                  relief=tk.FLAT, padx=10, pady=6, cursor="hand2",
                  borderwidth=0).pack(side=tk.LEFT, padx=(0, 3))

        # The original Session Start flow becomes the "Start" panel.
        body = tk.Frame(ss_frames["start"], bg=BG_DARK, padx=18, pady=12)
        body.pack(fill=tk.BOTH, expand=True)

        # ---- Mic accuracy (Fast / Accurate / Best) — sets the dictation
        # quality for the 🎤 buttons below (and app-wide; it's a shared
        # setting). Guard the var: the state block resets it to None and this
        # panel builds at the end of __init__. -----------------------------
        acc_row = tk.Frame(body, bg=BG_DARK)
        acc_row.pack(fill=tk.X, pady=(0, 8))
        tk.Label(acc_row, text="🎤 Mic accuracy:", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 9, "bold")).pack(side=tk.LEFT)
        if self._whisper_quality_var is None:
            self._whisper_quality_var = tk.StringVar(value="Accurate")
        _ss_acc = tk.OptionMenu(acc_row, self._whisper_quality_var,
                                "Fast", "Accurate", "Best",
                                command=self._set_mic_quality)
        _style_optionmenu(_ss_acc)
        _ss_acc.configure(width=10, font=("Segoe UI", 9))
        _ss_acc.pack(side=tk.LEFT, padx=(6, 0))
        tk.Button(acc_row, text="🗣 Voice Memory", command=self.open_voice_memory,
                  font=("Segoe UI", 9, "bold"), bg=ACCENT_SLATE, fg="white",
                  activebackground=ACCENT_SLATE, relief=tk.FLAT, padx=8, pady=2,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT, padx=(12, 0))

        # ---- Last session summary — shows the notes you recorded, and
        # refreshes live as you record more (see auto-save below). ----------
        tk.Label(body, text="Last session", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 9, "bold")).pack(anchor=tk.W, pady=(0, 4))
        summary_lbl = tk.Label(
            body, text=self._format_handoff_message(state or {}),
            bg=BG_INPUT, fg=FG_TEXT, font=("Segoe UI", 10),
            padx=10, pady=8, wraplength=500, justify=tk.LEFT, anchor=tk.W)
        summary_lbl.pack(fill=tk.X, pady=(0, 14))

        def _refresh_summary():
            try:
                summary_lbl.configure(text=self._format_handoff_message(
                    self._load_handoff_state() or {}))
            except tk.TclError:
                pass

        # 🎤 Voice dictation: clicking a field makes it the mic target
        # (FocusIn), and its 🎤 button focuses it and starts/stops listening —
        # same pattern as Study Notes. The buttons are registered in
        # self._session_start_mic_btns so _start_mic/_stop_mic flip them to a
        # red "■ Stop" while listening (the feedback every other mic gives).
        self._session_start_mic_btns = []

        def _ss_mic(widget):
            if self.is_listening:
                self.toggle_mic()
                return
            try:
                widget.focus_set()
            except tk.TclError:
                pass
            self._set_mic_target(widget)
            self.toggle_mic()

        # ---- Primary task -----
        pt_head = tk.Frame(body, bg=BG_DARK)
        pt_head.pack(fill=tk.X)
        tk.Label(pt_head, text="One primary task for this session",
                 bg=BG_DARK, fg=FG_TEXT, font=("Segoe UI", 11, "bold")
                 ).pack(side=tk.LEFT)
        _pt_mic = tk.Button(pt_head, text="🎤", command=lambda: _ss_mic(task_entry),
                            font=("Segoe UI", 10, "bold"), bg=ACCENT_MIC, fg="white",
                            activebackground=ACCENT_MIC, relief=tk.FLAT, padx=8, pady=2,
                            cursor="hand2", borderwidth=0)
        _pt_mic.pack(side=tk.RIGHT)
        self._session_start_mic_btns.append(_pt_mic)
        tk.Label(body,
                 text="(The Sentinel spec is strict — pick ONE focus.)",
                 bg=BG_DARK, fg=FG_MUTED, font=("Segoe UI", 9, "italic")
                 ).pack(anchor=tk.W)
        primary_task_var = tk.StringVar()
        if state and state.get("next_session_primary_task"):
            primary_task_var.set(state["next_session_primary_task"])
        task_entry = tk.Entry(
            body, textvariable=primary_task_var,
            bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
            font=("Segoe UI", 11), relief=tk.FLAT, bd=0,
        )
        task_entry.pack(fill=tk.X, ipady=6, pady=(4, 14))
        task_entry.bind("<FocusIn>",
                        lambda _e: self._set_mic_target(task_entry), add="+")
        self._attach_clipboard_menu(
            task_entry, clear_cmd=lambda: self._clear_input(task_entry),
            clear_label="Clear", track_for_mic=False)

        # ---- Session notes -----
        sn_head = tk.Frame(body, bg=BG_DARK)
        sn_head.pack(fill=tk.X)
        tk.Label(sn_head, text="Session notes",
                 bg=BG_DARK, fg=FG_TEXT, font=("Segoe UI", 11, "bold")
                 ).pack(side=tk.LEFT)
        _sn_mic = tk.Button(sn_head, text="🎤", command=lambda: _ss_mic(notes_text),
                            font=("Segoe UI", 10, "bold"), bg=ACCENT_MIC, fg="white",
                            activebackground=ACCENT_MIC, relief=tk.FLAT, padx=8, pady=2,
                            cursor="hand2", borderwidth=0)
        _sn_mic.pack(side=tk.RIGHT)
        self._session_start_mic_btns.append(_sn_mic)
        tk.Label(body,
                 text="(Anything you want to remember for this session — "
                      "saved with your handoff.)",
                 bg=BG_DARK, fg=FG_MUTED, font=("Segoe UI", 9, "italic")
                 ).pack(anchor=tk.W)
        notes_text = tk.Text(
            body, height=5,
            bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
            font=("Segoe UI", 10), relief=tk.FLAT, bd=0, wrap=tk.WORD,
        )
        notes_text.pack(fill=tk.BOTH, expand=True, pady=(4, 14))
        notes_text.bind("<FocusIn>",
                        lambda _e: self._set_mic_target(notes_text), add="+")
        self._attach_clipboard_menu(
            notes_text, clear_cmd=lambda: self._clear_input(notes_text),
            clear_label="Clear", track_for_mic=False)
        if state and state.get("session_notes"):
            notes_text.insert("1.0", state["session_notes"])
        try:
            notes_text.edit_modified(False)   # don't let the prefill auto-fire
        except tk.TclError:
            pass

        # Auto-save BOTH the primary task and the session notes as you record
        # them (debounced ~0.8s) and refresh the "Last session" box live — so
        # whatever you put in EITHER field shows up there and is waiting for
        # you at the next session start.
        _save_after = {"id": None}

        def _save_session_fields():
            _save_after["id"] = None
            cur = self._load_handoff_state() or {}
            cur["session_primary_task"] = primary_task_var.get().strip()
            cur["session_notes"] = notes_text.get("1.0", tk.END).strip()
            self._save_handoff_state(cur)
            _refresh_summary()

        def _schedule_save(*_):
            if _save_after["id"] is not None:
                try:
                    self.root.after_cancel(_save_after["id"])
                except Exception:
                    pass
            _save_after["id"] = self.root.after(800, _save_session_fields)

        def _notes_modified(_e=None):
            try:
                notes_text.edit_modified(False)
            except tk.TclError:
                pass
            _schedule_save()
        notes_text.bind("<<Modified>>", _notes_modified, add="+")
        primary_task_var.trace_add("write", _schedule_save)

        # ---- Buttons -----
        btn_row = tk.Frame(body, bg=BG_DARK)
        btn_row.pack(fill=tk.X, pady=(12, 0))

        def _begin():
            cur = self._load_handoff_state() or {}
            cur["session_start_iso"]   = datetime.now().isoformat(timespec="seconds")
            cur["session_start_date"]  = date.today().isoformat()
            cur["session_primary_task"] = primary_task_var.get().strip()
            cur["session_notes"] = notes_text.get("1.0", tk.END).strip()
            self._save_handoff_state(cur)
            _refresh_summary()
            task = primary_task_var.get().strip() or "(none)"
            self.set_status(
                f"🎯 Session started — {task}. Set your focus timer in Do Now.")
            if dismiss is not None:
                dismiss()
            # Open the Study workspace on the 🎯 Matrix tab and land in the
            # Do Now quadrant, where the focus timer lives — set the timer
            # there for this session (a gentle flash fires when it ends).
            try:
                self.open_study_workspace()
                self._show_study_tab("matrix")
                w = (getattr(self, "_eisenhower_widgets", {}) or {}).get("do")
                if w is not None:
                    w.focus_set()
            except Exception:
                pass

        tk.Button(btn_row, text="Begin Session  ▶", command=_begin,
                  bg=ACCENT_GREEN, fg="white",
                  font=("Segoe UI", 11, "bold"),
                  relief=tk.FLAT, padx=18, pady=8,
                  cursor="hand2", borderwidth=0
                  ).pack(side=tk.LEFT, padx=(0, 8))
        if dismiss is not None:
            tk.Button(btn_row, text="Skip for now", command=dismiss,
                      bg=ACCENT_SLATE, fg="white",
                      font=("Segoe UI", 10),
                      relief=tk.FLAT, padx=12, pady=6,
                      cursor="hand2", borderwidth=0
                      ).pack(side=tk.LEFT)

        # Build the two Ziglar panels, then reveal the Start panel first.
        self._build_wheel_panel(ss_frames["wheel"],
                                goto_goals=lambda: _show_ss("goals"))
        self._build_goals_panel(ss_frames["goals"])
        _show_ss("start")

        if not inline:
            task_entry.focus_set()

    # ---- Session End wizard --------------------------------------------
    def open_session_end_wizard(self) -> None:
        """Capture tasks completed/remaining/blockers + next session's
        primary task + end energy, write HANDOFF_STATE.json so the next
        Session Start wizard can pick up where this one left off."""
        if self._session_end_win is not None:
            try:
                if self._session_end_win.winfo_exists():
                    self._session_end_win.lift()
                    self._session_end_win.focus_force()
                    return
            except tk.TclError:
                pass
            self._session_end_win = None

        state = self._load_handoff_state() or {}
        win = tk.Toplevel(self.root)
        self._session_end_win = win
        win.title("⏹  Session End")
        win.geometry("620x680")
        win.minsize(520, 560)
        win.configure(bg=BG_DARK)
        # win.transient(self.root)  # disabled: hides Min/Max buttons on Windows
        try:
            win.grab_set()
        except tk.TclError:
            pass

        header = tk.Frame(win, bg=BG_PANEL, padx=14, pady=12)
        header.pack(fill=tk.X)
        tk.Label(header, text="⏹  Session End", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        tk.Label(header, text=date.today().strftime("%A · %B %d, %Y"),
                 bg=BG_PANEL, fg=FG_MUTED, font=("Segoe UI", 10)
                 ).pack(side=tk.RIGHT)

        body = tk.Frame(win, bg=BG_DARK, padx=18, pady=12)
        body.pack(fill=tk.BOTH, expand=True)

        primary_task = (state.get("session_primary_task") or "").strip()
        if primary_task:
            tk.Label(body, text=f"Today's primary task: {primary_task}",
                     bg=BG_DARK, fg=FG_MUTED,
                     font=("Segoe UI", 10, "italic"),
                     wraplength=540, justify=tk.LEFT, anchor=tk.W
                     ).pack(fill=tk.X, pady=(0, 8))

        def _text_block(label: str, height: int = 4) -> tk.Text:
            tk.Label(body, text=label, bg=BG_DARK, fg=FG_TEXT,
                     font=("Segoe UI", 10, "bold")
                     ).pack(anchor=tk.W, pady=(8, 2))
            t = tk.Text(body, height=height,
                        bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                        font=("Segoe UI", 10), relief=tk.FLAT, bd=0,
                        wrap=tk.WORD)
            t.pack(fill=tk.X)
            return t

        completed = _text_block("Tasks completed this session", 4)
        remaining = _text_block("Tasks remaining / unfinished", 3)
        blockers  = _text_block("Blockers (be specific)",        2)

        tk.Label(body, text="Next session's primary task",
                 bg=BG_DARK, fg=FG_TEXT, font=("Segoe UI", 10, "bold")
                 ).pack(anchor=tk.W, pady=(10, 2))
        next_task_var = tk.StringVar()
        tk.Entry(body, textvariable=next_task_var,
                 bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                 font=("Segoe UI", 11), relief=tk.FLAT, bd=0
                 ).pack(fill=tk.X, ipady=6)

        btn_row = tk.Frame(body, bg=BG_DARK)
        btn_row.pack(fill=tk.X, pady=(14, 0))

        def _close():
            self._session_end_win = None
            try:
                win.destroy()
            except tk.TclError:
                pass

        def _save():
            now = datetime.now().isoformat(timespec="seconds")
            data = {
                "date":                       date.today().isoformat(),
                "session_start_iso":          state.get("session_start_iso"),
                "session_start_date":         state.get("session_start_date"),
                "session_end_iso":            now,
                "session_primary_task":       primary_task,
                "tasks_completed":            completed.get("1.0", tk.END).strip(),
                "tasks_remaining":            remaining.get("1.0", tk.END).strip(),
                "blockers":                   blockers.get("1.0", tk.END).strip(),
                "next_session_primary_task":  next_task_var.get().strip(),
                "session_notes":              state.get("session_notes"),
            }
            data["handoff_message"] = self._format_handoff_message(data)
            self._save_handoff_state(data)
            nxt = next_task_var.get().strip() or "(none)"
            self.set_status(f"⏹ Handoff saved — next task: {nxt}")
            _close()

        tk.Button(btn_row, text="Save Handoff  ✓", command=_save,
                  bg=ACCENT_GREEN, fg="white",
                  font=("Segoe UI", 11, "bold"),
                  relief=tk.FLAT, padx=18, pady=8,
                  cursor="hand2", borderwidth=0
                  ).pack(side=tk.LEFT, padx=(0, 8))
        tk.Button(btn_row, text="Cancel", command=_close,
                  bg=ACCENT_SLATE, fg="white",
                  font=("Segoe UI", 10),
                  relief=tk.FLAT, padx=12, pady=6,
                  cursor="hand2", borderwidth=0
                  ).pack(side=tk.LEFT)

        win.protocol("WM_DELETE_WINDOW", _close)
        completed.focus_set()

    # ---- Three-Zone Library metadata helpers ----------------------------
    # Each library file `foo.docx` gets a sidecar `foo.docx.meta.json`
    # carrying its zone + cognitive_load + breadcrumbs. The Sentinel Prime
    # Network spec defines the schema; see the Forge-Stack-A1 snapshot for
    # the source of truth.
    def _meta_path_for(self, file_path: str) -> str:
        return file_path + META_SUFFIX

    def _doc_id_for(self, file_path: str, area: str = "LIBRARY") -> str:
        """Apply the Sentinel naming standard:
        BOOKREADER-<AREA>-<slug>_<YYYY-MM-DD>_v001."""
        stem = Path(file_path).stem
        slug = re.sub(r"[^a-z0-9]+", "_", stem.lower()).strip("_") or "item"
        return f"BOOKREADER-{area}-{slug}_{date.today().isoformat()}_v001"

    def _load_meta(self, file_path: str) -> dict:
        """Read the sidecar; lazy-create a default if missing so the file
        immediately participates in zone filtering."""
        p = self._meta_path_for(file_path)
        if os.path.exists(p):
            try:
                with open(p, "r", encoding="utf-8") as f:
                    data = json.load(f)
                if data.get("zone") not in LIBRARY_ZONES:
                    data["zone"] = LIBRARY_ZONE_DEFAULT
                if not isinstance(data.get("cognitive_load"), int):
                    data["cognitive_load"] = LIBRARY_ZONE_LOAD_DEFAULT[data["zone"]]
                return data
            except (OSError, json.JSONDecodeError):
                pass
        meta = {
            "doc_id":         self._doc_id_for(file_path),
            "zone":           LIBRARY_ZONE_DEFAULT,
            "cognitive_load": LIBRARY_ZONE_LOAD_DEFAULT[LIBRARY_ZONE_DEFAULT],
            "source_book":    None,
            "timestamp":      datetime.now().isoformat(timespec="seconds"),
            "tags":           [],
        }
        self._save_meta(file_path, meta)
        return meta

    def _save_meta(self, file_path: str, meta: dict) -> None:
        try:
            with open(self._meta_path_for(file_path), "w", encoding="utf-8") as f:
                json.dump(meta, f, indent=2, ensure_ascii=False)
        except OSError:
            pass  # Non-fatal: zone filtering will fall back to defaults

    def _set_zone(self, file_path: str, zone: str) -> None:
        """Migrate a library file to a new zone. Snaps cognitive_load into
        the destination zone's range if it currently falls outside it
        (e.g., moving an active load=9 book to RED resets it to load=2)."""
        if zone not in LIBRARY_ZONES:
            return
        meta = self._load_meta(file_path)
        meta["zone"] = zone
        current = int(meta.get("cognitive_load") or 0)
        lo, hi = LIBRARY_ZONE_LOAD_RANGE[zone]
        if not (lo <= current <= hi):
            meta["cognitive_load"] = LIBRARY_ZONE_LOAD_DEFAULT[zone]
        self._save_meta(file_path, meta)

    # ---- Library --------------------------------------------------------
    # The library is just LIBRARY_DIR on disk, scanned recursively for files
    # whose extension is in SUPPORTED_EXTS. Persistence is automatic (it's
    # a folder), and there's no artificial limit on count or size — it'll
    # hold as much as your disk and OneDrive plan can take.
    def open_library(self) -> None:
        """Open (or focus) the Library window."""
        if self._library_win is not None:
            try:
                if self._library_win.winfo_exists():
                    self._library_win.lift()
                    self._library_win.focus_force()
                    return
            except Exception:
                pass
            self._library_win = None

        try:
            os.makedirs(LIBRARY_DIR, exist_ok=True)
        except Exception as e:
            messagebox.showerror("Library folder unavailable",
                                 f"Could not create {LIBRARY_DIR}:\n{e}")
            return

        win = tk.Toplevel(self.root)
        self._library_win = win
        win.title("📚 Library")
        # Size the window to FIT the screen and center it, so nothing (the
        # Pages list, the action buttons) ever runs off the bottom edge.
        try:
            sw = win.winfo_screenwidth()
            sh = win.winfo_screenheight()
        except tk.TclError:
            sw, sh = 1280, 800
        w = min(1280, max(760, sw - 60))
        h = min(860, max(480, sh - 96))    # use more of the screen height
        x = max(0, (sw - w) // 2)
        y = max(0, (sh - h) // 2 - 30)
        win.geometry(f"{w}x{h}+{x}+{y}")
        win.minsize(560, 380)
        win.configure(bg=BG_DARK)
        # NOT transient: a transient window only gets a Close (X) button.
        # A normal top-level window gets the full title-bar controls —
        # minimize (—), maximize/restore (the two-panes icon), and close.

        # Drag-and-drop: drop files from Explorer onto the Library
        # window to add them. tkinterdnd2 hands us a single string with
        # paths possibly braced and space-separated — `tk.splitlist`
        # untangles that.
        if HAS_DND:
            try:
                win.drop_target_register(DND_FILES)
                def _on_drop(event):
                    raw = event.data
                    try:
                        paths = list(self.root.tk.splitlist(raw))
                    except tk.TclError:
                        paths = [raw]
                    paths = [p for p in paths if p]
                    if paths:
                        self._library_import_paths(paths)
                win.dnd_bind("<<Drop>>", _on_drop)
            except (tk.TclError, AttributeError):
                pass  # DnD unavailable; user still has the + Add files… button

        def _on_close():
            self._library_win = None
            win.destroy()
        win.protocol("WM_DELETE_WINDOW", _on_close)

        # Header
        header = tk.Frame(win, bg=BG_PANEL, padx=14, pady=12)
        header.pack(fill=tk.X)
        tk.Label(header, text="📚 Library", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        self._library_stats_var = tk.StringVar(value="")
        tk.Label(header, textvariable=self._library_stats_var, bg=BG_PANEL,
                 fg=FG_MUTED, font=("Segoe UI", 10)).pack(side=tk.RIGHT)

        # Reading toolbar at the very top: highlight color, highlight the
        # current selection, and the read-aloud voice — the same controls as
        # the main reader, acting on the Library's reading pane. Colour/voice
        # share the reader's variables so the two stay in sync.
        lib_tools = tk.Frame(win, bg=BG_PANEL, padx=10, pady=5)
        lib_tools.pack(fill=tk.X)
        tk.Label(lib_tools, text="Color:", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 10, "bold")).pack(side=tk.LEFT, padx=(0, 4))
        lib_color_menu = tk.OptionMenu(
            lib_tools, self.highlight_color_var,
            *list(self.HIGHLIGHT_COLORS.keys()))
        _style_optionmenu(lib_color_menu)
        lib_color_menu.configure(width=7, font=("Segoe UI", 10, "bold"))
        lib_color_menu.pack(side=tk.LEFT, padx=(0, 8))
        tk.Button(
            lib_tools, text="🖍  Highlight selection",
            command=lambda: self._library_highlight_selection(
                self.highlight_color_var.get()),
            font=("Segoe UI", 10, "bold"),
            bg=ACCENT_AMBER, fg="white", activebackground=ACCENT_AMBER,
            relief=tk.FLAT, padx=10, pady=4, cursor="hand2", borderwidth=0,
        ).pack(side=tk.LEFT, padx=(0, 6))
        tk.Button(
            lib_tools, text="✕ Unhighlight",
            command=self._library_remove_highlight,
            font=("Segoe UI", 10, "bold"),
            bg=ACCENT_SLATE, fg="white", activebackground=ACCENT_SLATE,
            relief=tk.FLAT, padx=10, pady=4, cursor="hand2", borderwidth=0,
        ).pack(side=tk.LEFT, padx=(0, 10))
        tk.Label(lib_tools, text="Voice:", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 10, "bold")).pack(side=tk.LEFT, padx=(4, 4))
        lib_voice_menu = tk.OptionMenu(
            lib_tools, self.voice_var, *self.available_voices,
            command=self._on_voice_change)
        _style_optionmenu(lib_voice_menu)
        lib_voice_menu.configure(width=13, font=("Segoe UI", 10, "bold"))
        lib_voice_menu.pack(side=tk.LEFT, padx=(0, 8))

        # Path hint
        path_hint = tk.Label(
            win,
            text=(f"Folder: {LIBRARY_DIR}    "
                  "(Word, Google Docs exported as Word/PDF, PDF, RTF, HTML, TXT, MD) "
                  + ("· Drop files here to add them" if HAS_DND else "")),
            anchor=tk.W, bg=BG_DARK, fg=FG_MUTED,
            font=("Segoe UI", 9), padx=14, pady=4,
        )
        path_hint.pack(fill=tk.X)

        # (Zones removed — the Library is a plain book list + reader now.)
        self._library_zone_filter = None
        self._library_zone_filter_btns = {}

        # Search
        search_row = tk.Frame(win, bg=BG_DARK, padx=14, pady=8)
        search_row.pack(fill=tk.X)
        tk.Label(search_row, text="Search:", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 11)).pack(side=tk.LEFT, padx=(0, 6))
        self._library_search_var = tk.StringVar()
        search_entry = tk.Entry(
            search_row, textvariable=self._library_search_var,
            bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
            font=("Segoe UI", 11), relief=tk.FLAT, bd=0,
        )
        search_entry.pack(side=tk.LEFT, fill=tk.X, expand=True, ipady=5)
        self._library_search_var.trace_add(
            "write", lambda *_: self._refresh_library_list()
        )

        # Action row — packed at the BOTTOM and BEFORE the list area so it can
        # never be clipped off the bottom edge on a short screen.
        btn_row = tk.Frame(win, bg=BG_DARK, padx=14, pady=10)
        btn_row.pack(side=tk.BOTTOM, fill=tk.X)

        def lbtn(parent, text, cmd, color):
            return tk.Button(
                parent, text=text, command=cmd,
                font=("Segoe UI", 10, "bold"),
                bg=color, fg="white", activebackground=color,
                relief=tk.FLAT, padx=10, pady=5, cursor="hand2", borderwidth=0,
            )

        lbtn(btn_row, "🔊  Read aloud", self._library_read_aloud,
             ACCENT_GREEN).pack(side=tk.LEFT, padx=(0, 6))
        lbtn(btn_row, "■  Stop",        self.stop_reading,
             ACCENT_SLATE).pack(side=tk.LEFT, padx=(0, 14))
        lbtn(btn_row, "+  Add files…",  self._library_add_files,
             ACCENT_GREEN).pack(side=tk.LEFT, padx=(0, 6))
        lbtn(btn_row, "🗑  Remove",      self._library_remove_selected,
             ACCENT_RED).pack(side=tk.LEFT, padx=6)
        lbtn(btn_row, "📂  Open folder", self._library_open_folder,
             ACCENT_SLATE).pack(side=tk.LEFT, padx=6)
        lbtn(btn_row, "🔄  Refresh",     self._refresh_library_list,
             ACCENT_SLATE).pack(side=tk.LEFT, padx=6)
        lbtn(btn_row, "✨  Ask Library", self._library_ask_platform,
             ACCENT_PURPLE).pack(side=tk.LEFT, padx=(12, 6))
        lbtn(btn_row, "Open in reader", self._open_selected_library_book,
             ACCENT_CYAN).pack(side=tk.RIGHT, padx=(6, 0))
        lbtn(btn_row, "Close", _on_close,
             ACCENT_SLATE).pack(side=tk.RIGHT, padx=6)

        # Two-pane list, e-Sword style: Book Name on the left, Chapter on
        # the right. Click a book → chapters populate. Double-click a
        # chapter (or hit "Open in reader") to open the book at that
        # chapter. Both panes are ttk.Treeviews themed for the dark
        # palette.
        list_frame = tk.Frame(win, bg=BG_DARK, padx=14, pady=4)
        list_frame.pack(fill=tk.BOTH, expand=True)

        style = ttk.Style(win)
        try:
            style.theme_use(style.theme_use())  # keep current theme
        except Exception:
            pass
        style.configure(
            "Library.Treeview",
            background=BG_INPUT, fieldbackground=BG_INPUT, foreground=FG_TEXT,
            rowheight=24, borderwidth=0, font=("Segoe UI", 11),
        )
        style.configure(
            "Library.Treeview.Heading",
            background=BG_PANEL, foreground=FG_TEXT,
            font=("Segoe UI", 10, "bold"), relief=tk.FLAT, borderwidth=0,
        )
        style.map(
            "Library.Treeview",
            background=[("selected", ACCENT_CYAN)],
            foreground=[("selected", "white")],
        )
        style.map(
            "Library.Treeview.Heading",
            background=[("active", BG_PANEL)],
        )

        # Thick, raised, colored sashes so the dividers are easy to grab and
        # drag — the user can resize every area to taste.
        panes = tk.PanedWindow(
            list_frame, orient=tk.HORIZONTAL, bg=ACCENT_SLATE,
            sashrelief=tk.RAISED, sashwidth=8, borderwidth=0,
        )
        panes.pack(fill=tk.BOTH, expand=True)

        # A chunky, clearly-visible scrollbar ("slider") used by every list
        # so each one is easy to see and drag up and down.
        def slider(parent, command):
            return tk.Scrollbar(
                parent, command=command, width=18,
                troughcolor=BG_PANEL, bg=ACCENT_SLATE,
                activebackground=ACCENT_CYAN, relief=tk.FLAT, borderwidth=0,
            )

        # Let the mouse wheel scroll a list when the pointer is over it, so
        # scrolling works without having to grab the slider thumb.
        def wheel(widget):
            widget.bind(
                "<MouseWheel>",
                lambda e: (widget.yview_scroll(
                    int(-1 * (e.delta / 120)), "units"), "break")[1],
                add="+",
            )

        # ---- Left pane: book list ---------------------------------------
        books_frame = tk.Frame(panes, bg=BG_DARK)
        self._library_tree = ttk.Treeview(
            books_frame,
            columns=("name",),
            show="headings",
            style="Library.Treeview",
            selectmode="browse",
        )
        self._library_tree.heading("name", text="Book Name", anchor=tk.W)
        self._library_tree.column("name", anchor=tk.W, width=320, stretch=True)
        books_sb = slider(books_frame, self._library_tree.yview)
        self._library_tree.configure(yscrollcommand=books_sb.set)
        books_sb.pack(side=tk.RIGHT, fill=tk.Y)
        wheel(self._library_tree)
        self._library_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        # ---- Right side: in-window reading view -------------------------
        # Book title at the top, a chapters + pages navigator on the left,
        # and the readable book text on the right.
        read_frame = tk.Frame(panes, bg=BG_DARK)
        self._library_title_label = tk.Label(
            read_frame, text="Select a book on the left to read it here",
            bg=BG_DARK, fg=FG_TEXT, font=("Segoe UI", 12, "bold"),
            anchor=tk.W, padx=6, justify=tk.LEFT, wraplength=560,
        )
        self._library_title_label.pack(fill=tk.X, pady=(0, 4))

        read_split = tk.PanedWindow(
            read_frame, orient=tk.HORIZONTAL, bg=ACCENT_SLATE,
            sashrelief=tk.RAISED, sashwidth=8, borderwidth=0,
        )
        read_split.pack(fill=tk.BOTH, expand=True)

        # Navigator: Chapters over Pages in their OWN draggable vertical
        # split, so the two start equal and you can resize each by dragging
        # the divider between them.
        nav_split = tk.PanedWindow(
            read_split, orient=tk.VERTICAL, bg=ACCENT_SLATE,
            sashrelief=tk.RAISED, sashwidth=8, borderwidth=0,
        )

        # ---- Chapters (top) ---------------------------------------------
        chapters_section = tk.Frame(nav_split, bg=BG_DARK)
        tk.Label(chapters_section, text="Chapters", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 10, "bold"), anchor=tk.W, padx=8, pady=4
                 ).pack(fill=tk.X)
        ch_holder = tk.Frame(chapters_section, bg=BG_DARK)
        ch_holder.pack(fill=tk.BOTH, expand=True)
        self._library_chapter_tree = ttk.Treeview(
            ch_holder, columns=("chapter",), show="headings",
            style="Library.Treeview", selectmode="browse", height=4,
        )
        self._library_chapter_tree.heading("chapter", text="#  Chapter", anchor=tk.W)
        self._library_chapter_tree.column("chapter", anchor=tk.W, width=180, stretch=True)
        ch_sb = slider(ch_holder, self._library_chapter_tree.yview)
        self._library_chapter_tree.configure(yscrollcommand=ch_sb.set)
        ch_sb.pack(side=tk.RIGHT, fill=tk.Y)
        self._library_chapter_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        wheel(self._library_chapter_tree)

        # ---- Pages (bottom) ---------------------------------------------
        pages_section = tk.Frame(nav_split, bg=BG_DARK)
        tk.Label(pages_section, text="Pages", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 10, "bold"), anchor=tk.W, padx=8, pady=4
                 ).pack(fill=tk.X)
        pg_holder = tk.Frame(pages_section, bg=BG_DARK)
        pg_holder.pack(fill=tk.BOTH, expand=True)
        self._library_pages_tree = ttk.Treeview(
            pg_holder, columns=("page",), show="headings",
            style="Library.Treeview", selectmode="browse", height=4,
        )
        self._library_pages_tree.heading("page", text="Page", anchor=tk.W)
        self._library_pages_tree.column("page", anchor=tk.W, width=90, stretch=True)
        pg_sb = slider(pg_holder, self._library_pages_tree.yview)
        self._library_pages_tree.configure(yscrollcommand=pg_sb.set)
        pg_sb.pack(side=tk.RIGHT, fill=tk.Y)
        self._library_pages_tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        wheel(self._library_pages_tree)

        nav_split.add(chapters_section, minsize=70, stretch="always")
        nav_split.add(pages_section,    minsize=70, stretch="always")

        # The reading area — the book text, readable right here.
        text_holder = tk.Frame(read_split, bg=BG_DARK)
        self._library_read_text = scrolledtext.ScrolledText(
            text_holder, wrap=tk.WORD, bg=BG_INPUT, fg=FG_TEXT,
            insertbackground=FG_TEXT, font=(self.font_family, self.font_size),
            relief=tk.FLAT, bd=0, padx=12, pady=10, height=10, width=40,
        )
        self._library_read_text.pack(fill=tk.BOTH, expand=True)
        # Yellow follow-along highlight for Read aloud (same as the boards).
        _yellow = self.HIGHLIGHT_COLORS.get("Yellow", "#fde047")
        self._library_read_text.tag_configure(
            "reading", background=_yellow, foreground="#0f172a")
        self._library_read_text.tag_raise("reading", "sel")
        self._attach_clipboard_menu(self._library_read_text)

        read_split.add(nav_split,   minsize=150, stretch="always")
        read_split.add(text_holder, minsize=280, stretch="always")

        panes.add(books_frame, minsize=140, stretch="always")
        panes.add(read_frame,  minsize=340, stretch="always")

        # Bindings: select a book → load it into the reading view; a chapter
        # or page click jumps the reading area there. Double-click still
        # opens the book in the main reader for the full-screen experience.
        self._library_tree.bind(
            "<<TreeviewSelect>>", lambda _e: self._library_show_selected_book())
        self._library_tree.bind(
            "<Double-Button-1>", lambda _e: self._open_selected_library_book())
        self._library_tree.bind(
            "<Return>", lambda _e: self._open_selected_library_book())
        self._library_chapter_tree.bind(
            "<<TreeviewSelect>>", lambda _e: self._library_jump_to_chapter())
        self._library_pages_tree.bind(
            "<<TreeviewSelect>>", lambda _e: self._library_jump_to_page())

        # Show every book in the folder (no zones).
        self._library_zone_filter = None
        self._refresh_library_list()
        # Auto-open the LARGEST file (most likely a real book with plenty of
        # chapters/pages) so the reading area, Chapters and Pages are
        # populated right away — that's what makes the sliders appear and be
        # draggable (an empty or short list has nothing to scroll).
        try:
            items = self._library_items
            if items:
                biggest = max(range(len(items)), key=lambda i: items[i][2])
                iid = str(biggest)
                if self._library_tree.exists(iid):
                    self._library_tree.selection_set(iid)
                    self._library_tree.see(iid)
                    self._library_tree.focus(iid)
                    self._library_show_selected_book()
        except Exception:
            pass

        # Give the panes sensible starting proportions once the window has a
        # real size: a slim book list, a medium navigator, the rest reading;
        # Chapters and Pages split evenly. The user can drag any divider.
        def _init_sashes():
            try:
                win.update_idletasks()
                total_w = panes.winfo_width()
                if total_w > 1:
                    panes.sash_place(0, int(total_w * 0.24), 1)
                rf_w = read_frame.winfo_width()
                if rf_w > 1:
                    read_split.sash_place(0, min(240, int(rf_w * 0.30)), 1)
                nav_h = nav_split.winfo_height()
                if nav_h > 1:
                    nav_split.sash_place(0, 1, nav_h // 2)
            except Exception:
                pass
        win.after(150, _init_sashes)
        search_entry.focus_set()

    # ---- Ask Library (cross-excerpt AI search via the platform) --------
    # Calls the Sentinel Forge FastAPI service at
    # http://127.0.0.1:8000/api/library/ask. The service scans every
    # saved excerpt's body + metadata and returns the top matches with
    # snippets, scores, and matched terms. This is a feature the
    # standalone reader can't provide on its own — single-file
    # search is local; cross-library search needs the platform.

    PLATFORM_ASK_URL = "http://127.0.0.1:8000/api/library/ask"

    def _library_ask_platform(self) -> None:
        """Send the current search box (or a prompt) to /api/library/ask."""
        # Use whatever's typed in the search box; if empty, ask for it.
        question = ""
        if self._library_search_var is not None:
            question = (self._library_search_var.get() or "").strip()
        if len(question) < 2:
            from tkinter import simpledialog
            question = simpledialog.askstring(
                "✨ Ask Your Library",
                "Search across every saved excerpt at once.\n\n"
                "Examples:\n"
                "  • wisdom honor\n"
                "  • bushido\n"
                "  • cognitive architecture\n"
                "  • Mycenaean Sea Peoples\n\n"
                "What are you looking for?",
                parent=self._library_win,
            )
            if not question:
                return
            question = question.strip()
            if len(question) < 2:
                return

        if self._library_stats_var is not None:
            self._library_stats_var.set("✨ Asking your library…")

        def _worker() -> None:
            result: dict | None = None
            err: tuple[str, str] | None = None
            try:
                import urllib.request
                import urllib.error
                payload = json.dumps({"question": question, "top_k": 10}).encode("utf-8")
                req = urllib.request.Request(
                    self.PLATFORM_ASK_URL,
                    data=payload,
                    headers={"Content-Type": "application/json"},
                    method="POST",
                )
                with urllib.request.urlopen(req, timeout=10) as resp:
                    result = json.loads(resp.read().decode("utf-8"))
            except urllib.error.URLError as e:
                err = ("connection", str(e))
            except Exception as e:                          # pragma: no cover
                err = ("other", str(e))
            self.root.after(0, lambda: self._library_ask_done(question, result, err))

        threading.Thread(target=_worker, daemon=True).start()

    def _library_ask_done(self, question: str,
                          result: dict | None,
                          err: tuple[str, str] | None) -> None:
        """Tk-thread callback: render Ask Library results or show error."""
        if self._library_stats_var is not None:
            self._library_stats_var.set("")
        if err is not None:
            kind, msg = err
            if kind == "connection":
                messagebox.showinfo(
                    "Sentinel Forge Dashboard not running",
                    "✨ Ask Library uses the Sentinel Forge platform service to\n"
                    "search across every excerpt you've ever saved.\n\n"
                    "Double-click the “Sentinel Forge Dashboard” icon on your\n"
                    "Desktop to start the service, then click Ask Library again.",
                    parent=self._library_win,
                )
            else:
                messagebox.showerror(
                    "Ask Library failed",
                    f"Unexpected error from the platform:\n\n{msg}",
                    parent=self._library_win,
                )
            return
        if not result:
            return
        self._show_ask_results(question, result)

    def _show_ask_results(self, question: str, result: dict) -> None:
        """Open a Toplevel showing the top matches as scrollable cards."""
        parent = self._library_win or self.root
        rw = tk.Toplevel(parent)
        rw.title(f"✨ Ask Library — {question[:60]}")
        rw.geometry("780x600")
        rw.minsize(520, 360)
        rw.configure(bg=BG_DARK)
        rw.transient(parent)

        # Header
        hdr = tk.Frame(rw, bg=BG_PANEL, padx=14, pady=10)
        hdr.pack(fill=tk.X)
        tk.Label(hdr, text=f"✨  {question}", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 13, "bold")).pack(side=tk.LEFT)
        tk.Label(
            hdr,
            text=f"{result.get('matched', 0)} match(es) / {result.get('total_searched', 0)} searched",
            bg=BG_PANEL, fg=FG_MUTED, font=("Segoe UI", 10),
        ).pack(side=tk.RIGHT)

        # Synthesis
        synth = result.get("answer_synthesis", "") or ""
        if synth:
            tk.Label(
                rw, text=synth, bg=BG_DARK, fg=ACCENT_CYAN,
                font=("Segoe UI", 10, "italic"),
                wraplength=720, justify=tk.LEFT,
                padx=14, pady=8, anchor="w",
            ).pack(fill=tk.X)

        # Scrollable list of match cards
        body = tk.Frame(rw, bg=BG_DARK)
        body.pack(fill=tk.BOTH, expand=True, padx=14, pady=4)
        canvas = tk.Canvas(body, bg=BG_DARK, highlightthickness=0)
        vscroll = ttk.Scrollbar(body, orient=tk.VERTICAL, command=canvas.yview)
        inner = tk.Frame(canvas, bg=BG_DARK)
        canvas.configure(yscrollcommand=vscroll.set)
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        vscroll.pack(side=tk.RIGHT, fill=tk.Y)
        canvas_window = canvas.create_window((0, 0), window=inner, anchor="nw")
        def _on_inner_config(_e: tk.Event) -> None:
            canvas.configure(scrollregion=canvas.bbox("all"))
        def _on_canvas_config(e: tk.Event) -> None:
            canvas.itemconfigure(canvas_window, width=e.width)
        inner.bind("<Configure>", _on_inner_config)
        canvas.bind("<Configure>", _on_canvas_config)

        matches = result.get("matches", []) or []
        if not matches:
            tk.Label(
                inner,
                text="No matches yet. Try broader terms, or save more excerpts.",
                bg=BG_DARK, fg=FG_MUTED, font=("Segoe UI", 11),
                pady=24,
            ).pack()
        else:
            for m in matches:
                self._render_ask_match(inner, m, rw)

        # Footer
        ftr = tk.Frame(rw, bg=BG_DARK)
        ftr.pack(fill=tk.X, padx=14, pady=10)
        tk.Button(
            ftr, text="Close", command=rw.destroy,
            font=("Segoe UI", 10, "bold"),
            bg=ACCENT_SLATE, fg="white", activebackground=ACCENT_SLATE,
            relief=tk.FLAT, padx=14, pady=6, cursor="hand2", borderwidth=0,
        ).pack(side=tk.RIGHT)

    def _render_ask_match(self, parent: tk.Widget, m: dict, owner_win: tk.Toplevel) -> None:
        """Render one Ask Library match as a clickable card."""
        zone = (m.get("zone") or "GREEN").upper()
        zone_color = LIBRARY_ZONE_COLOR.get(zone, ACCENT_SLATE)
        src_full = m.get("source_book") or ""
        src_label = os.path.basename(src_full) if src_full else (m.get("doc_id") or "unknown")
        score = m.get("score", 0)
        hits = m.get("hits", []) or []
        snippet = (m.get("snippet") or "").strip()
        filename = m.get("filename", "")

        card = tk.Frame(parent, bg=BG_PANEL, padx=10, pady=8,
                        highlightthickness=1, highlightbackground="#334155")
        card.pack(fill=tk.X, pady=4)

        head = tk.Frame(card, bg=BG_PANEL)
        head.pack(fill=tk.X)
        tk.Label(
            head, text=src_label, bg=BG_PANEL, fg=FG_TEXT,
            font=("Segoe UI", 11, "bold"), anchor="w",
        ).pack(side=tk.LEFT)
        tk.Label(
            head, text=f"{zone}  ·  score {score}",
            bg=BG_PANEL, fg=zone_color, font=("Segoe UI", 9, "bold"),
        ).pack(side=tk.RIGHT)

        if snippet:
            tk.Label(
                card, text=snippet, bg=BG_PANEL, fg=FG_MUTED,
                font=("Segoe UI", 10), justify=tk.LEFT,
                wraplength=700, anchor="w",
            ).pack(fill=tk.X, pady=(4, 2))

        meta = tk.Frame(card, bg=BG_PANEL)
        meta.pack(fill=tk.X, pady=(2, 0))
        if hits:
            tk.Label(
                meta, text="matched: " + ", ".join(hits),
                bg=BG_PANEL, fg=ACCENT_CYAN,
                font=("Segoe UI", 9, "italic"), anchor="w",
            ).pack(side=tk.LEFT)
        if filename:
            tk.Label(
                meta, text=filename, bg=BG_PANEL, fg=FG_MUTED,
                font=("Segoe UI", 8), anchor="e",
            ).pack(side=tk.RIGHT)

    def _scan_library(self) -> list[tuple[str, str, int, float]]:
        """Walk LIBRARY_DIR recursively, skipping the Commentaries
        subfolder so commentaries never show up in the regular library
        list. Returns [(relative_path, absolute_path, size, mtime), ...]
        sorted by path."""
        found: list[tuple[str, str, int, float]] = []
        if not os.path.isdir(LIBRARY_DIR):
            return found
        commentaries_abs = os.path.abspath(COMMENTARIES_DIR).lower()
        for root_dir, dirs, files in os.walk(LIBRARY_DIR):
            # Mutating `dirs` in-place tells os.walk not to recurse into
            # them — this is the canonical way to skip a subtree.
            dirs[:] = [
                d for d in dirs
                if os.path.abspath(os.path.join(root_dir, d)).lower()
                   != commentaries_abs
            ]
            for name in files:
                if not name.lower().endswith(SUPPORTED_EXTS):
                    continue
                full = os.path.join(root_dir, name)
                try:
                    st = os.stat(full)
                except OSError:
                    continue
                rel = os.path.relpath(full, LIBRARY_DIR)
                found.append((rel, full, st.st_size, st.st_mtime))
        found.sort(key=lambda r: r[0].lower())
        return found

    def _refresh_library_list(self) -> None:
        if self._library_tree is None or self._library_stats_var is None:
            return
        tree = self._library_tree
        tree.delete(*tree.get_children())
        # Wrap the whole scan/render in try/except so a single bad
        # sidecar or unicode hiccup doesn't leave the user staring at
        # an empty-looking window with no explanation.
        try:
            scanned = self._scan_library()
        except Exception as e:                              # pragma: no cover
            self._library_stats_var.set(f"⚠ Scan failed: {e}")
            tree.insert("", tk.END, iid="err",
                        values=(f"⚠  Library scan failed: {e}",))
            return
        items = list(scanned)
        scanned_count = len(items)
        q = (self._library_search_var.get() if self._library_search_var else "").strip().lower()
        if q:
            items = [it for it in items if q in it[0].lower()]
        # Attach metadata (creates default sidecars on first scan) and
        # apply the zone filter if one is active.
        try:
            metas = [self._load_meta(full) for _rel, full, _s, _m in items]
        except Exception as e:                              # pragma: no cover
            metas = [{} for _ in items]
            self._library_stats_var.set(f"⚠ Some metadata could not be read: {e}")
        zone_filter = self._library_zone_filter
        if zone_filter:
            paired = [(it, m) for it, m in zip(items, metas)
                       if m.get("zone") == zone_filter]
            items = [it for it, _ in paired]
            metas = [m  for _,  m in paired]
        # If everything was filtered out but the folder has files,
        # tell the user instead of showing a void.
        if not items and scanned_count > 0:
            hint = (
                f"  📋  {scanned_count} file(s) in folder — "
                f"none match the current "
                + ("zone filter '" + zone_filter + "'" if zone_filter else "search")
                + ". Click 'All' to clear the filter."
            )
            tree.insert("", tk.END, iid="hint", values=(hint,))
            if self._library_stats_var is not None:
                self._library_stats_var.set(
                    f"0 of {scanned_count} shown — filter: "
                    + (zone_filter or "search:'" + q + "'")
                )
            return
        if not items and scanned_count == 0:
            tree.insert("", tk.END, iid="empty",
                        values=("  📂  Folder is empty. Drop books here or use + Add files…",))
            if self._library_stats_var is not None:
                self._library_stats_var.set("0 books in folder")
            return
        self._library_items = items
        self._library_item_metas = metas
        total_bytes = sum(it[2] for it in items)
        for idx, ((rel, _full, _size, _mtime), meta) in enumerate(zip(items, metas)):
            stem = Path(rel).stem
            # Friendly labels for saved excerpts: instead of the long
            # technical filename "BOOKREADER-EXCERPT-a2_..._v001", show
            # "📝 from a2 · 18:48" so the user can recognize their save.
            # Source book and timestamp come from the sidecar metadata.
            if stem.startswith("BOOKREADER-EXCERPT-") and meta.get("source_book"):
                src_stem = Path(meta["source_book"]).stem
                ts = meta.get("timestamp", "")
                # Show HH:MM if we can parse the ISO timestamp
                short_ts = ""
                try:
                    short_ts = datetime.fromisoformat(ts).strftime("%Y-%m-%d %H:%M")
                except (ValueError, TypeError):
                    short_ts = ts[:16].replace("T", " ")
                display = f"📝 from {src_stem} · {short_ts}"
            else:
                display = stem
            tree.insert("", tk.END, iid=str(idx), values=(display,))
        # Clear the chapter pane since the book selection is gone.
        if self._library_chapter_tree is not None:
            self._library_chapter_tree.delete(*self._library_chapter_tree.get_children())
        self._library_chapters = []
        self._library_current_book_idx = None
        n = len(items)
        filter_note = f" — filtered: {zone_filter}" if zone_filter else ""
        self._library_stats_var.set(
            f"{n} book{'s' if n != 1 else ''} — "
            f"{self._format_size(total_bytes)} total{filter_note}"
        )

    def _library_set_zone_filter(self, zone: str | None) -> None:
        """Apply (or clear) the zone filter and re-render."""
        self._library_zone_filter = zone
        active_key = zone or "__ALL__"
        for key, btn in self._library_zone_filter_btns.items():
            try:
                btn.configure(relief=tk.SUNKEN if key == active_key else tk.FLAT)
            except tk.TclError:
                pass
        self._refresh_library_list()

    def _library_migrate_selected(self, zone: str) -> None:
        """Move the currently selected book to a new zone and refresh."""
        if self._library_tree is None:
            return
        sel = self._library_tree.selection()
        if not sel:
            messagebox.showinfo(
                "Nothing selected",
                "Click a book in the list, then click a zone button "
                "(→ 🟢 / → 🟡 / → 🔴) to migrate it.",
            )
            return
        idx = int(sel[0])
        if idx >= len(self._library_items):
            return
        _rel, full, _s, _m = self._library_items[idx]
        self._set_zone(full, zone)
        self.set_status(
            f"Moved {os.path.basename(full)} → {LIBRARY_ZONE_EMOJI[zone]} {zone}"
        )
        self._refresh_library_list()

    def _library_show_selected_book(self) -> None:
        """Load the selected book into the in-window reading view: title at
        the top, chapters (numbered) + page numbers on the left, and the
        readable book text on the right. Re-uses the same
        `_extract_text_with_chapters` path the main reader uses."""
        if self._library_tree is None:
            return
        ch_tree = self._library_chapter_tree
        pg_tree = self._library_pages_tree
        rt = self._library_read_text
        sel = self._library_tree.selection()
        if not sel:
            self._library_current_book_idx = None
            return
        try:
            idx = int(sel[0])
        except ValueError:
            return  # a hint/empty row, not a real book
        if idx >= len(self._library_items):
            self._library_current_book_idx = None
            return
        # Don't re-parse a 500-page PDF when the same row is re-selected.
        if self._library_current_book_idx == idx and self._library_chapters:
            return
        self._library_current_book_idx = idx
        _rel, full, _size, _mtime = self._library_items[idx]
        title = Path(full).stem
        if self._library_title_label is not None:
            self._library_title_label.configure(text=title)
        self.set_status(f"Opening {os.path.basename(full)}…")
        try:
            self.root.update_idletasks()
        except tk.TclError:
            pass
        try:
            text, chapters = self._extract_text_with_chapters(full)
        except Exception as e:
            text, chapters = (f"(Could not read this book: {e})", [])
        self._library_chapters = chapters

        # Fill the reading area.
        if rt is not None:
            rt.delete("1.0", tk.END)
            rt.insert("1.0", text)
            rt.see("1.0")

        # Chapters: numbered "1.  Title".
        if ch_tree is not None:
            ch_tree.delete(*ch_tree.get_children())
            if chapters:
                for c_idx, (label, _off) in enumerate(chapters):
                    ch_tree.insert("", tk.END, iid=str(c_idx),
                                   values=(f"{c_idx + 1}.  {label}",))
            else:
                ch_tree.insert("", tk.END, iid="none",
                               values=("(no chapters detected)",))

        # Pages: synthetic, evenly sized (most formats have no real pages).
        self._library_page_offsets = [off for _n, off in self._library_paginate(text)]
        if pg_tree is not None:
            pg_tree.delete(*pg_tree.get_children())
            for p_idx in range(len(self._library_page_offsets)):
                pg_tree.insert("", tk.END, iid=str(p_idx),
                               values=(f"Page {p_idx + 1}",))

        self.set_status(
            f"{title} — {len(chapters)} chapter(s), "
            f"{len(self._library_page_offsets)} page(s)")

    @staticmethod
    def _library_paginate(text: str, chars_per_page: int = 1800
                          ) -> list[tuple[int, int]]:
        """Split text into synthetic, evenly-sized pages. Most book formats
        (txt/docx/md) carry no real page breaks, so we approximate roughly one
        paperback page worth of characters each. Returns [(page_no, offset)]."""
        n = len(text)
        if n == 0:
            return [(1, 0)]
        out: list[tuple[int, int]] = []
        pos, num = 0, 1
        while pos < n:
            out.append((num, pos))
            pos += chars_per_page
            num += 1
        return out

    def _library_jump_to_chapter(self) -> None:
        """Click a chapter → scroll the reading area to it."""
        ct = self._library_chapter_tree
        if ct is None:
            return
        sel = ct.selection()
        if not sel:
            return
        try:
            c_idx = int(sel[0])
        except ValueError:
            return
        if 0 <= c_idx < len(self._library_chapters):
            self._library_scroll_read_to(self._library_chapters[c_idx][1])

    def _library_jump_to_page(self) -> None:
        """Click a page number → scroll the reading area to it."""
        pt = self._library_pages_tree
        if pt is None:
            return
        sel = pt.selection()
        if not sel:
            return
        try:
            p_idx = int(sel[0])
        except ValueError:
            return
        if 0 <= p_idx < len(self._library_page_offsets):
            self._library_scroll_read_to(self._library_page_offsets[p_idx])

    def _library_scroll_read_to(self, char_offset: int) -> None:
        rt = self._library_read_text
        if rt is None:
            return
        try:
            tk_idx = rt.index(f"1.0 + {int(char_offset)} chars")
            rt.see(tk_idx)
            rt.mark_set(tk.INSERT, tk_idx)
            rt.focus_set()
        except tk.TclError:
            pass

    def _library_read_aloud(self) -> None:
        """Read the book in the Library's reading pane aloud, with the yellow
        follow-along highlight tracking inside that pane. Reads the selection
        if one exists, otherwise from the top of the book."""
        rt = self._library_read_text
        if rt is None or not rt.get("1.0", tk.END).strip():
            messagebox.showinfo(
                "Read aloud", "Open a book in the Library first, then click "
                "🔊 Read aloud.")
            return
        if self.is_reading:
            self.stop_reading()
        self._read_widget = rt
        # No selection → start from the top of the book.
        try:
            has_sel = bool(rt.tag_ranges(tk.SEL))
        except tk.TclError:
            has_sel = False
        if not has_sel:
            rt.mark_set(tk.INSERT, "1.0")
        rt.focus_set()
        self.read_aloud()

    def _library_highlight_selection(self, color_name: str = "Yellow") -> None:
        """Color-highlight the current selection in the Library reading pane.
        Clears the selection afterwards so the colour is immediately visible
        (otherwise the blue selection sits on top and hides it)."""
        rt = self._library_read_text
        if rt is None:
            return
        try:
            s_idx = rt.index(tk.SEL_FIRST)
            e_idx = rt.index(tk.SEL_LAST)
            text = rt.get(s_idx, e_idx)
        except tk.TclError:
            messagebox.showinfo(
                "Nothing selected",
                "Select some text in the reading pane first, then click a "
                "highlight colour (Yellow / Indigo / Teal).")
            return
        if not text.strip():
            return
        color = color_name if color_name in self.HIGHLIGHT_COLORS else "Yellow"
        color_hex = self.HIGHLIGHT_COLORS[color]
        tag = f"hl_{color.lower()}"
        try:
            rt.tag_configure(tag, background=color_hex, foreground="#0f172a")
            rt.tag_add(tag, s_idx, e_idx)
            # Colour above the selection, read-aloud guide above the colour.
            rt.tag_raise(tag, "sel")
            try:
                rt.tag_raise("reading", tag)
            except tk.TclError:
                pass
            # Drop the selection so the new colour shows right away.
            rt.tag_remove(tk.SEL, "1.0", tk.END)
        except tk.TclError:
            pass
        self.set_status(f"🖍 Highlighted in {color}.")

    def _library_remove_highlight(self) -> None:
        """Remove colour highlights. Works whether or not text is selected:
        it clears the WHOLE highlighted run(s) overlapping the selection, or —
        if nothing is selected — the highlight under the cursor. If neither
        finds a highlight, offers to clear them all."""
        rt = self._library_read_text
        if rt is None:
            return
        # Target range: the selection if there is one, else the cursor spot.
        try:
            t0 = rt.index(tk.SEL_FIRST)
            t1 = rt.index(tk.SEL_LAST)
        except tk.TclError:
            ins = rt.index(tk.INSERT)
            t0, t1 = ins, f"{ins}+1c"

        removed = False
        for cname in self.HIGHLIGHT_COLORS:
            tag = f"hl_{cname.lower()}"
            ranges = rt.tag_ranges(tag)
            # Walk each (start, end) run; remove any run that overlaps target.
            for i in range(0, len(ranges), 2):
                r0, r1 = ranges[i], ranges[i + 1]
                if rt.compare(r0, "<", t1) and rt.compare(t0, "<", r1):
                    rt.tag_remove(tag, r0, r1)
                    removed = True

        try:
            rt.tag_remove(tk.SEL, "1.0", tk.END)
        except tk.TclError:
            pass

        if removed:
            self.set_status("Highlight removed.")
            return
        # Nothing under the selection/cursor — offer to clear the whole book.
        if messagebox.askyesno(
                "Remove highlights",
                "No highlight here.\n\nRemove ALL highlights in this book?"):
            for cname in self.HIGHLIGHT_COLORS:
                rt.tag_remove(f"hl_{cname.lower()}", "1.0", tk.END)
            self.set_status("All highlights removed.")

    @staticmethod
    def _format_size(b: float) -> str:
        for unit in ("B", "KB", "MB", "GB"):
            if b < 1024 or unit == "GB":
                if unit == "B":
                    return f"{int(b):,} B"
                return f"{b:,.1f} {unit}"
            b /= 1024.0
        return f"{b:.1f} GB"

    def _library_add_files(self) -> None:
        """Copy one or more files into LIBRARY_DIR. Auto-renames on
        collision so we never silently overwrite an existing book."""
        paths = filedialog.askopenfilenames(
            title="Add books to your library",
            initialdir=os.path.expanduser("~"),
            filetypes=[
                ("All supported", "*.txt *.md *.docx *.pdf *.rtf *.html *.htm"),
                ("Word",          "*.docx"),
                ("PDF",           "*.pdf"),
                ("Text / Markdown", "*.txt *.md"),
                ("RTF",           "*.rtf"),
                ("HTML",          "*.html *.htm"),
                ("All files",     "*.*"),
            ],
        )
        if not paths:
            return
        self._library_import_paths(paths)

    def _library_import_paths(self, paths: list[str] | tuple[str, ...]) -> None:
        """Shared import path used by both the file dialog and the
        drag-and-drop drop handler. Validates each path, copies into
        LIBRARY_DIR with collision-renaming, and seeds the sidecar."""
        try:
            os.makedirs(LIBRARY_DIR, exist_ok=True)
        except Exception as e:
            messagebox.showerror("Library folder unavailable", str(e))
            return
        added = 0
        skipped: list[str] = []
        lib_abs = os.path.abspath(LIBRARY_DIR).lower()
        for src in paths:
            # Drops sometimes hand us folders. Walk shallow for any
            # supported files inside; deeper recursion would surprise
            # the user.
            if os.path.isdir(src):
                for child in os.listdir(src):
                    childpath = os.path.join(src, child)
                    if (os.path.isfile(childpath)
                            and childpath.lower().endswith(SUPPORTED_EXTS)):
                        paths = list(paths) + [childpath]
                continue
            if not os.path.isfile(src):
                skipped.append(f"{os.path.basename(src)} (not a file)")
                continue
            if not src.lower().endswith(SUPPORTED_EXTS):
                skipped.append(f"{os.path.basename(src)} (unsupported format)")
                continue
            # If the user picks a file already inside the library, don't
            # copy it next to itself — just leave it where it is.
            src_abs = os.path.abspath(src).lower()
            if src_abs.startswith(lib_abs + os.sep) or src_abs == lib_abs:
                skipped.append(f"{os.path.basename(src)} (already in library)")
                continue
            dest = os.path.join(LIBRARY_DIR, os.path.basename(src))
            base, ext = os.path.splitext(dest)
            n = 1
            while os.path.exists(dest):
                dest = f"{base} ({n}){ext}"
                n += 1
            try:
                shutil.copy2(src, dest)
                # Seed default sidecar (zone=GREEN, load=8) so the new
                # book is visible under the active zone immediately.
                self._load_meta(dest)
                added += 1
            except Exception as e:
                skipped.append(f"{os.path.basename(src)} ({e})")
        self._refresh_library_list()
        msg = f"Added {added} file{'s' if added != 1 else ''} to the library."
        if skipped:
            msg += "\n\nSkipped:\n  • " + "\n  • ".join(skipped[:12])
            if len(skipped) > 12:
                msg += f"\n  • …and {len(skipped) - 12} more"
        messagebox.showinfo("Library updated", msg)

    def _library_remove_selected(self) -> None:
        if self._library_tree is None:
            return
        sel = self._library_tree.selection()
        if not sel:
            messagebox.showinfo("Nothing selected",
                                "Click a book in the list, then click Remove.")
            return
        idx = int(sel[0])
        if idx >= len(self._library_items):
            return
        rel, full, _size, _mtime = self._library_items[idx]
        if HAS_SEND2TRASH:
            confirm_msg = (f"Send this file to the Recycle Bin?\n\n{rel}\n\n"
                            "You can restore it from the Recycle Bin if needed.")
        else:
            confirm_msg = (f"Permanently delete this file from disk?\n\n{rel}\n\n"
                            "This cannot be undone. "
                            "(Install send2trash to get Recycle Bin support: "
                            "pip install send2trash)")
        if not messagebox.askyesno("Remove from library?", confirm_msg):
            return
        try:
            if HAS_SEND2TRASH:
                # send2trash needs forward-slashes-resistant absolute paths
                # on Windows; normpath fixes mixed separators in case the
                # path was rebuilt from a saved sidecar.
                send2trash(os.path.normpath(full))
            else:
                os.unlink(full)
        except Exception as e:
            messagebox.showerror("Could not remove", str(e))
            return
        # Sweep the sidecar too — Recycle Bin or unlink, same path.
        meta_p = self._meta_path_for(full)
        if os.path.exists(meta_p):
            try:
                if HAS_SEND2TRASH:
                    send2trash(os.path.normpath(meta_p))
                else:
                    os.unlink(meta_p)
            except (OSError, Exception):
                pass
        self._refresh_library_list()

    def _open_selected_library_book(self) -> None:
        if self._library_tree is None:
            return
        sel = self._library_tree.selection()
        if not sel:
            messagebox.showinfo("Nothing selected",
                                "Click a book in the list, then click Open.")
            return
        idx = int(sel[0])
        if idx >= len(self._library_items):
            return
        _rel, full, _size, _mtime = self._library_items[idx]
        self._load_book(full)
        # If a chapter is selected on the right, jump to its offset after
        # loading. Use the main reader's chapter navigator so its
        # selection stays in sync too.
        if (self._library_chapter_tree is not None
                and self._library_chapters):
            c_sel = self._library_chapter_tree.selection()
            if c_sel and c_sel[0] != "none":
                try:
                    c_idx = int(c_sel[0])
                except ValueError:
                    c_idx = -1
                if 0 <= c_idx < len(self._library_chapters):
                    _label, offset = self._library_chapters[c_idx]
                    try:
                        tk_idx = self._tk_index_for_offset(offset)
                        self.text_area.mark_set(tk.INSERT, tk_idx)
                        self.text_area.see(tk_idx)
                        try:
                            self.chapter_listbox.selection_clear(0, tk.END)
                            self.chapter_listbox.selection_set(c_idx)
                            self.chapter_listbox.see(c_idx)
                        except (tk.TclError, AttributeError):
                            pass
                    except tk.TclError:
                        pass
        try:
            if self._library_win is not None:
                self._library_win.destroy()
        except Exception:
            pass
        self._library_win = None

    def _library_open_folder(self) -> None:
        """Pop the library folder open in Explorer so the user can drag
        files in directly, organize into subfolders, etc."""
        try:
            os.startfile(LIBRARY_DIR)  # type: ignore[attr-defined]
        except Exception as e:
            messagebox.showerror("Could not open folder", str(e))

    # ---- Commentary pane -----------------------------------------------
    # Commentaries are stored separately from regular books (in
    # COMMENTARIES_DIR). The Library scan above prunes that subfolder,
    # so books and commentaries never mix. A loaded commentary is shown
    # in the middle pane of the right column, read-only.

    def open_commentary_picker(self) -> None:
        """Modal picker over the Commentaries/ folder. Add new
        commentaries from disk, remove existing ones, or open one in
        the commentary pane."""
        try:
            os.makedirs(COMMENTARIES_DIR, exist_ok=True)
        except Exception as e:
            messagebox.showerror("Commentary folder unavailable",
                                 f"Could not create {COMMENTARIES_DIR}:\n{e}")
            return

        dlg = tk.Toplevel(self.root)
        dlg.title("📑 Commentaries")
        dlg.geometry("680x500")
        dlg.minsize(440, 320)
        dlg.configure(bg=BG_DARK)
        dlg.transient(self.root)
        dlg.grab_set()

        header = tk.Frame(dlg, bg=BG_PANEL, padx=14, pady=12)
        header.pack(fill=tk.X)
        tk.Label(header, text="📑 Commentaries", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        stats_var = tk.StringVar(value="")
        tk.Label(header, textvariable=stats_var, bg=BG_PANEL, fg=FG_MUTED,
                 font=("Segoe UI", 10)).pack(side=tk.RIGHT)

        tk.Label(
            dlg,
            text=f"Folder: {COMMENTARIES_DIR}   "
                 "(kept separate from your regular library — no mixing)",
            anchor=tk.W, bg=BG_DARK, fg=FG_MUTED,
            font=("Segoe UI", 9), padx=14, pady=4,
        ).pack(fill=tk.X)

        list_frame = tk.Frame(dlg, bg=BG_DARK, padx=14, pady=4)
        list_frame.pack(fill=tk.BOTH, expand=True)
        lb = tk.Listbox(
            list_frame, bg=BG_INPUT, fg=FG_TEXT,
            selectbackground=ACCENT_CYAN, selectforeground="white",
            font=("Consolas", 11),
            activestyle="none", relief=tk.FLAT, bd=0,
            highlightthickness=0,
        )
        sb = tk.Scrollbar(list_frame, command=lb.yview)
        lb.configure(yscrollcommand=sb.set)
        sb.pack(side=tk.RIGHT, fill=tk.Y)
        lb.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        items_ref: dict = {"items": []}

        def refresh() -> None:
            lb.delete(0, tk.END)
            items: list[tuple[str, str, int, float]] = []
            try:
                names = sorted(os.listdir(COMMENTARIES_DIR), key=str.lower)
            except OSError:
                names = []
            for name in names:
                full = os.path.join(COMMENTARIES_DIR, name)
                if not os.path.isfile(full):
                    continue
                if not name.lower().endswith(SUPPORTED_EXTS):
                    continue
                try:
                    st = os.stat(full)
                except OSError:
                    continue
                items.append((name, full, st.st_size, st.st_mtime))
            items_ref["items"] = items
            total = sum(it[2] for it in items)
            for name, _f, size, mtime in items:
                size_str = self._format_size(size)
                date_str = datetime.fromtimestamp(mtime).strftime("%Y-%m-%d")
                display = name if len(name) <= 48 else name[:45] + "…"
                lb.insert(tk.END,
                          f" {display:<48} {size_str:>10}   {date_str}")
            stats_var.set(
                f"{len(items)} commentar{'ies' if len(items) != 1 else 'y'}"
                f" — {self._format_size(total)} total"
            )

        def open_selected() -> None:
            sel = lb.curselection()
            if not sel:
                messagebox.showinfo("Nothing selected",
                                      "Pick a commentary to open.", parent=dlg)
                return
            _n, full, _s, _m = items_ref["items"][sel[0]]
            self._load_commentary(full)
            dlg.destroy()

        def add_files() -> None:
            paths = filedialog.askopenfilenames(
                title="Add commentaries",
                initialdir=os.path.expanduser("~"),
                filetypes=[
                    ("All supported", "*.txt *.md *.docx *.pdf *.rtf *.html *.htm"),
                    ("Word",          "*.docx"),
                    ("PDF",           "*.pdf"),
                    ("Text / Markdown", "*.txt *.md"),
                    ("RTF",           "*.rtf"),
                    ("HTML",          "*.html *.htm"),
                    ("All files",     "*.*"),
                ],
                parent=dlg,
            )
            if not paths:
                return
            try:
                os.makedirs(COMMENTARIES_DIR, exist_ok=True)
            except Exception as e:
                messagebox.showerror("Commentary folder unavailable",
                                       str(e), parent=dlg)
                return
            added = 0
            skipped: list[str] = []
            lib_abs = os.path.abspath(COMMENTARIES_DIR).lower()
            for src in paths:
                if not src.lower().endswith(SUPPORTED_EXTS):
                    skipped.append(f"{os.path.basename(src)} (unsupported)")
                    continue
                src_abs = os.path.abspath(src).lower()
                if src_abs.startswith(lib_abs + os.sep) or src_abs == lib_abs:
                    skipped.append(
                        f"{os.path.basename(src)} (already in commentaries)")
                    continue
                dest = os.path.join(COMMENTARIES_DIR, os.path.basename(src))
                base, ext = os.path.splitext(dest)
                n = 1
                while os.path.exists(dest):
                    dest = f"{base} ({n}){ext}"
                    n += 1
                try:
                    shutil.copy2(src, dest)
                    added += 1
                except Exception as e:
                    skipped.append(f"{os.path.basename(src)} ({e})")
            refresh()
            msg = f"Added {added} commentar{'ies' if added != 1 else 'y'}."
            if skipped:
                msg += "\n\nSkipped:\n  • " + "\n  • ".join(skipped[:12])
            messagebox.showinfo("Commentaries updated", msg, parent=dlg)

        def remove_selected() -> None:
            sel = lb.curselection()
            if not sel:
                messagebox.showinfo(
                    "Nothing selected",
                    "Pick a commentary to remove.", parent=dlg)
                return
            name, full, _s, _m = items_ref["items"][sel[0]]
            if not messagebox.askyesno(
                "Remove from commentaries?",
                f"Permanently delete this file from disk?\n\n{name}\n\n"
                "This cannot be undone.", parent=dlg):
                return
            try:
                os.unlink(full)
            except Exception as e:
                messagebox.showerror("Could not remove", str(e), parent=dlg)
                return
            # If the deleted file was the one currently loaded, clear the pane.
            if self._commentary_file and \
                    os.path.abspath(self._commentary_file) == os.path.abspath(full):
                self._clear_commentary()
            refresh()

        def open_folder() -> None:
            try:
                os.startfile(COMMENTARIES_DIR)  # type: ignore[attr-defined]
            except Exception as e:
                messagebox.showerror("Could not open folder",
                                       str(e), parent=dlg)

        row = tk.Frame(dlg, bg=BG_DARK, padx=14, pady=12)
        row.pack(fill=tk.X)
        def b(text, cmd, color):
            return tk.Button(row, text=text, command=cmd,
                             font=("Segoe UI", 11, "bold"),
                             bg=color, fg="white", activebackground=color,
                             relief=tk.FLAT, padx=14, pady=8,
                             cursor="hand2", borderwidth=0)
        b("+  Add commentaries…", add_files,       ACCENT_GREEN
          ).pack(side=tk.LEFT, padx=(0, 6))
        b("🗑  Remove",            remove_selected, ACCENT_RED
          ).pack(side=tk.LEFT, padx=6)
        b("📂  Open folder",       open_folder,     ACCENT_SLATE
          ).pack(side=tk.LEFT, padx=6)
        b("🔄  Refresh",           refresh,         ACCENT_SLATE
          ).pack(side=tk.LEFT, padx=6)
        b("Open in pane",          open_selected,   ACCENT_CYAN
          ).pack(side=tk.RIGHT, padx=(6, 0))
        b("Close",                 dlg.destroy,     ACCENT_SLATE
          ).pack(side=tk.RIGHT, padx=6)

        lb.bind("<Double-Button-1>", lambda _e: open_selected())
        lb.bind("<Return>", lambda _e: open_selected())

        refresh()
        # If empty, immediately offer to add files — saves a click on
        # first use.
        if not items_ref["items"]:
            if messagebox.askyesno(
                "Commentary library empty",
                "There are no commentaries yet.\n\nAdd one now?",
                parent=dlg,
            ):
                add_files()
        lb.focus_set()

    def _load_commentary(self, path: str) -> None:
        """Read `path` and display its text in the commentary pane."""
        try:
            text, _chs = self._extract_text_with_chapters(path)
        except Exception as e:
            messagebox.showerror(
                "Could not read commentary", f"{e}\n\nFile: {path}")
            return
        name = Path(path).stem
        self._commentary_file = path
        self.commentary_title_var.set(f"📑  {name}")
        w = self.commentary_area
        if w is None:   # Commentary tab not open; state is saved for next open
            self.set_status(f"📑 Loaded commentary: {name}")
            return
        w.configure(state=tk.NORMAL)
        w.delete("1.0", tk.END)
        w.insert("1.0", text)
        w.see("1.0")
        w.configure(state=tk.DISABLED)
        self.set_status(f"📑 Loaded commentary: {name}")

    def _clear_commentary(self) -> None:
        """Empty the commentary pane."""
        self._commentary_file = None
        self.commentary_title_var.set("📑  Commentary")
        w = self.commentary_area
        if w is None:   # Commentary tab not open; nothing on screen to clear
            self.set_status("Commentary cleared.")
            return
        w.configure(state=tk.NORMAL)
        w.delete("1.0", tk.END)
        w.configure(state=tk.DISABLED)
        self.set_status("Commentary cleared.")

    # ---- Read aloud — main-thread pyttsx3 with PowerShell fallback ------
    def _rw(self):
        """The widget read-aloud reads from and highlights into. Defaults to
        the main reading board; the Prompt Library redirects it to its own
        Prompt/Response box."""
        return self._read_widget if self._read_widget is not None else self.text_area

    def read_aloud(self) -> None:
        # Wrap the whole entry point — historically a crash here left
        # is_reading=True and the UI looked frozen. Any uncaught error
        # now resets state and surfaces a status message.
        try:
            self._read_aloud_inner()
        except Exception as e:
            self.is_reading = False
            self.set_status(f"Read aloud failed: {e}")
            try:
                messagebox.showerror(
                    "Read aloud crashed",
                    f"The speech engine raised an exception:\n\n{e}\n\n"
                    "The app is still running — try again, or select a "
                    "smaller passage first.",
                )
            except tk.TclError:
                pass

    def _read_aloud_inner(self) -> None:
        if self.tts_mode == "none":
            messagebox.showerror(
                "Read aloud could not start",
                "Both the Python speech engine and PowerShell speech are "
                "unavailable on this machine. Click OK to dismiss.\n\n"
                "What you can try:\n"
                "  • Open Windows Settings → Time & Language → Speech and "
                "verify a voice is installed.\n"
                "  • Restart Sentinel Forge and try again.",
            )
            return
        if self.is_reading:
            return

        # Reading start point — three tiers, in order of priority:
        #   1. If the user highlighted text, read just that selection.
        #   2. Else read from the INSERT cursor (wherever the user
        #      last clicked) to the end. This lets the user click into
        #      the book to set a resume point, take a Note, then click
        #      🔊 Read aloud to pick up where they left off.
        #   3. If the cursor's at the very top (typical right after
        #      opening a book), this naturally reads the whole book.
        # IMPORTANT: do NOT strip the text — chunk offsets are computed
        # relative to `speech_start_idx`, so leading whitespace must be
        # preserved or the yellow highlight lands in the wrong place.
        rw = self._rw()
        try:
            text = rw.get(tk.SEL_FIRST, tk.SEL_LAST)
            speech_start_idx = rw.index(tk.SEL_FIRST)
            start_label = "selection"
        except tk.TclError:
            try:
                speech_start_idx = rw.index(tk.INSERT)
            except tk.TclError:
                speech_start_idx = "1.0"
            text = rw.get(speech_start_idx, tk.END)
            start_label = ("top of book" if speech_start_idx == "1.0"
                           else f"cursor (line {speech_start_idx.split('.')[0]})")
        if not text.strip():
            messagebox.showinfo(
                "Nothing to read",
                "Open a book first, or click further up in the text — "
                "the cursor is past the end of the content.",
            )
            return

        # Long-book guard. Passing 100k+ chars to engine.say() in one shot
        # tends to hang SAPI or take 30+ seconds to compute spans before
        # the first word is spoken. Ask the user before we go for it.
        HARD_CAP = 60_000
        if len(text) > HARD_CAP:
            ok = messagebox.askyesno(
                "Read the whole book?",
                f"This is a long passage ({len(text):,} characters). "
                "Reading the whole thing in one go can make the app feel "
                "frozen for a while at the start, and some voices hang on "
                "very long input.\n\n"
                "Recommended: highlight a paragraph or chapter and click "
                "🔊 Read aloud again.\n\n"
                "Continue anyway?",
            )
            if not ok:
                return

        self.is_reading = True
        _vlog(f"read_aloud  tts_mode={self.tts_mode!r}  current_piper_voice={self.current_piper_voice!r}  voice_var={self.voice_var.get()!r}  text_len={len(text)}")
        # Status now shows WHICH engine is active so the user can tell at
        # a glance whether they're getting Piper neural voice or a SAPI
        # fallback. Engine name is upper-cased for visibility.
        engine_label = {
            "piper":      f"Piper neural · {self.voice_var.get()}",
            "powershell": "PowerShell SAPI (Windows voice)",
            "pyttsx3":    "pyttsx3 SAPI (Windows voice)",
            "none":       "no engine",
        }.get(self.tts_mode, self.tts_mode)
        self.set_status(
            f"🔊 [{engine_label}] Reading from {start_label} "
            f"({len(text):,} chars)… click ■ Stop to end"
        )

        if self.tts_mode == "piper":
            try:
                self._speak_piper(text, speech_start_idx)
            except Exception as e:
                # Surface why Piper fell back, not just silently log it.
                msg = f"⚠ Piper setup failed: {e} — falling back to Windows voice"
                print(f"[book_reader] {msg}", file=sys.stderr)
                self.set_status(msg)
                self.tts_mode = "powershell"
                self._speak_powershell(text, speech_start_idx)
        elif self.tts_mode == "pyttsx3":
            try:
                self._speak_pyttsx3(text, speech_start_idx)
            except Exception as e:
                # pyttsx3 setup failed — fall through to PowerShell so
                # the user still gets audio.
                print(f"[book_reader] _speak_pyttsx3 failed, "
                      f"falling back to PowerShell: {e}",
                      file=sys.stderr)
                self.tts_mode = "powershell"
                self._speak_powershell(text, speech_start_idx)
        else:
            self._speak_powershell(text, speech_start_idx)

    # ---- pyttsx3 path — main-thread iterate() with started-word ---------
    def _speak_pyttsx3(self, text: str, speech_start_idx: str) -> None:
        """Speak via pyttsx3 entirely on the main thread.

        Uses `engine.startLoop(False)` + `engine.iterate()` driven by Tk's
        `after()` so SAPI events run on the same thread that owns the COM
        engine. Hooks `started-word` to highlight the current word (or its
        containing sentence / paragraph, per the user's choice).

        The previous worker-thread design called `engine.say()` from a
        different thread than `pyttsx3.init()`. On Windows SAPI that
        causes the engine to play audio but silently drop event callbacks
        — the "voice works, no highlight" symptom we hit before.
        """
        # Compute spans lazily — only the granularity currently selected
        # gets built up front. The other two are computed on demand if
        # the user changes the highlight unit mid-read. This used to
        # freeze the main thread for many seconds on a whole book; now
        # only the active granularity bears that cost.
        self._tts_speech_text = text
        self._tts_speech_start_idx = speech_start_idx
        self._word_spans      = []
        self._sentence_spans  = []
        self._paragraph_spans = []
        current_unit = self._current_unit()
        active_spans = self._compute_spans(text, speech_start_idx, current_unit)
        if current_unit == "Word":
            self._word_spans = active_spans
        elif current_unit == "Paragraph":
            self._paragraph_spans = active_spans
        else:
            self._sentence_spans = active_spans
        if not active_spans:
            self._on_speech_done()
            return

        # Disconnect any handlers left over from a previous read.
        for tok_attr in ("_tts_word_token", "_tts_end_token"):
            tok = getattr(self, tok_attr, None)
            if tok is not None:
                try: self.tts_engine.disconnect(tok)
                except Exception: pass
                setattr(self, tok_attr, None)

        def on_word(name, location, length):
            # Gate on is_reading so a late callback after Stop doesn't
            # re-apply the tag we just cleared.
            if not self.is_reading:
                return
            try:
                self._highlight_at_offset(int(location))
            except Exception:
                pass

        def on_end(name, completed):
            # Defer to main-thread tick so we don't tear down the engine
            # loop from inside its own callback.
            self.root.after(0, self._finish_pyttsx3_reading)

        try:
            self._tts_word_token = self.tts_engine.connect("started-word", on_word)
            self._tts_end_token  = self.tts_engine.connect("finished-utterance", on_end)
            self.tts_engine.say(text)
            self.tts_engine.startLoop(False)
        except Exception as e:
            # If startLoop isn't usable, fall back to the PowerShell path so
            # the user still gets audio AND highlighting.
            print(f"[book_reader] pyttsx3 startLoop failed: {e}; using PowerShell.",
                  file=sys.stderr)
            self.tts_mode = "powershell"
            self._speak_powershell(text, speech_start_idx)
            return
        self._tts_iter_after_id = self.root.after(10, self._tts_iterate)

    def _tts_iterate(self) -> None:
        """Drive the pyttsx3 event loop from Tk's main loop."""
        if not self.is_reading:
            return
        try:
            self.tts_engine.iterate()
        except Exception as e:
            self._on_speech_error(f"pyttsx3 iterate failed: {e}")
            return
        self._tts_iter_after_id = self.root.after(20, self._tts_iterate)

    def _highlight_at_offset(self, char_offset: int) -> None:
        """Find the span at the user-chosen unit that contains `char_offset`
        and apply the reading tag to it."""
        unit = self.highlight_unit_var.get() if hasattr(self, "highlight_unit_var") else "Sentence"
        # Lazy span computation — the read-aloud start path only builds
        # spans for the granularity active at the time. If the user
        # changes the unit mid-read, the new granularity's spans are
        # built on first highlight callback.
        if unit == "Word" and not self._word_spans:
            self._word_spans = self._compute_spans(
                getattr(self, "_tts_speech_text", "") or "",
                getattr(self, "_tts_speech_start_idx", "1.0"),
                "Word",
            )
        elif unit == "Sentence" and not self._sentence_spans:
            self._sentence_spans = self._compute_spans(
                getattr(self, "_tts_speech_text", "") or "",
                getattr(self, "_tts_speech_start_idx", "1.0"),
                "Sentence",
            )
        elif unit == "Paragraph" and not self._paragraph_spans:
            self._paragraph_spans = self._compute_spans(
                getattr(self, "_tts_speech_text", "") or "",
                getattr(self, "_tts_speech_start_idx", "1.0"),
                "Paragraph",
            )
        if unit == "Word":
            spans = self._word_spans
        elif unit == "Paragraph":
            spans = self._paragraph_spans
        else:
            spans = self._sentence_spans
        for char_s, char_e, tk_s, tk_e in spans:
            if char_s <= char_offset < char_e:
                self._highlight_range(tk_s, tk_e)
                return

    def _highlight_range(self, start: str, end: str) -> None:
        """Move the reading guide to `start..end` and scroll to it.
        Always called on the main thread."""
        try:
            rw = self._rw()
            rw.tag_remove("reading", "1.0", tk.END)
            rw.tag_add("reading", start, end)
            rw.see(start)
        except tk.TclError as e:
            self.set_status(f"Highlight error: {e}")

    def _compute_spans(self, text: str, start_index: str, unit: str
                       ) -> list[tuple[int, int, str, str]]:
        """Return [(char_start, char_end, tk_start, tk_end), ...] for the
        requested granularity within `text`, anchored at `start_index`."""
        if unit == "Word":
            pattern = re.compile(r"\S+")
        elif unit == "Paragraph":
            # One or more non-blank lines; blank lines separate paragraphs.
            pattern = re.compile(r"[^\n]+(?:\n[^\n]+)*")
        else:  # Sentence
            pattern = re.compile(
                r"\S[^\n]*?(?:[.!?]+[\"')\]]?(?=\s|$)|(?=\n)|$)",
                re.MULTILINE,
            )
        spans: list[tuple[int, int, str, str]] = []
        for m in pattern.finditer(text):
            s, e = m.span()
            if not text[s:e].strip():
                continue
            try:
                rw = self._rw()
                tk_s = rw.index(f"{start_index} + {s} chars")
                tk_e = rw.index(f"{start_index} + {e} chars")
            except tk.TclError:
                continue
            spans.append((s, e, tk_s, tk_e))
        return spans

    def _finish_pyttsx3_reading(self) -> None:
        """Speech ended — tear down the loop and clear the highlight."""
        self._teardown_tts_loop()
        try:
            self._rw().tag_remove("reading", "1.0", tk.END)
        except tk.TclError:
            pass
        self._on_speech_done()

    def _teardown_tts_loop(self) -> None:
        """Cancel the iterate poller, end the engine loop, and disconnect
        callbacks. Safe to call multiple times."""
        if self._tts_iter_after_id is not None:
            try: self.root.after_cancel(self._tts_iter_after_id)
            except Exception: pass
            self._tts_iter_after_id = None
        if self._pump_after_id is not None:
            try: self.root.after_cancel(self._pump_after_id)
            except Exception: pass
            self._pump_after_id = None
        try: self.tts_engine.endLoop()
        except Exception: pass
        for tok_attr in ("_tts_word_token", "_tts_end_token"):
            tok = getattr(self, tok_attr, None)
            if tok is not None:
                try: self.tts_engine.disconnect(tok)
                except Exception: pass
                setattr(self, tok_attr, None)

    def _on_speech_done(self) -> None:
        self.is_reading = False
        self._read_widget = None
        self._matrix_set_read_btn(False)
        self.set_status("Done reading.")

    def _on_speech_error(self, msg: str) -> None:
        self.is_reading = False
        self._read_widget = None
        self._matrix_set_read_btn(False)
        self.set_status(f"Read aloud error: {msg}")

    # ---- Piper path: neural voice, chunked highlighting ------------------
    def _speak_piper(self, text: str, speech_start_idx: str) -> None:
        """Speak via Piper neural TTS. Same chunked-highlight worker
        pattern as the PowerShell path:
          1. Split text into spans at the current highlight unit.
          2. Worker thread loops the spans, runs `piper.exe` per span
             (feeding text on stdin, capturing wav to a temp file), and
             plays the wav via Python's stdlib `winsound`.
          3. Before each span starts speaking, the worker pushes a
             ("highlight", tk_s, tk_e) event onto a queue; the main
             thread drains it via the same `_pump_highlights` after()
             poller the PowerShell path uses.
          4. Stop button sets is_reading=False and PURGEs the current
             winsound playback so audio cuts immediately.
        """
        import winsound
        chunks = self._compute_spans(text, speech_start_idx, self._current_unit())
        if not chunks:
            self._on_speech_done()
            return
        self._highlight_queue = queue.Queue()
        # Reuse the SAPI path's queue poller — events are identical
        # ("highlight" / "done" / "error"). The original code referenced
        # _pump_highlights which never existed; that AttributeError was
        # caught by read_aloud's except clause and silently flipped every
        # Piper read into a SAPI fallback (the "only one voice plays" bug).
        self._pump_after_id = self.root.after(50, self._ps_poll_queue)

        def _run() -> None:
            for char_s, char_e, tk_s, tk_e in chunks:
                if not self.is_reading:
                    break
                chunk_text = text[char_s:char_e].strip()
                if not chunk_text:
                    continue
                self._highlight_queue.put(("highlight", tk_s, tk_e))
                wav_path = None
                try:
                    fd, wav_path = tempfile.mkstemp(suffix=".wav")
                    os.close(fd)
                    # Piper reads text from stdin, writes wav to file.
                    # Capture stderr so subprocess failures are visible
                    # (Piper logs voice-load + RTF info to stderr on
                    # success; a non-zero exit means real trouble).
                    _vlog(f"  piper.Popen  --model {self.current_piper_voice!r}  chunk_len={len(chunk_text)}")
                    proc = subprocess.Popen(
                        [PIPER_EXE, "--model", self.current_piper_voice,
                          "--output_file", wav_path],
                        stdin=subprocess.PIPE,
                        stdout=subprocess.DEVNULL,
                        stderr=subprocess.PIPE,
                        creationflags=getattr(subprocess, "CREATE_NO_WINDOW", 0),
                    )
                    self._ps_proc = proc  # reuse the kill-switch slot
                    try:
                        _stdout, _stderr = proc.communicate(
                            input=chunk_text.encode("utf-8"), timeout=60,
                        )
                    except subprocess.TimeoutExpired:
                        proc.kill()
                        continue
                    finally:
                        self._ps_proc = None
                    if proc.returncode != 0:
                        err_tail = (_stderr or b"").decode("utf-8", "replace")[-400:]
                        self._highlight_queue.put((
                            "error",
                            f"piper.exe exit {proc.returncode}: {err_tail}",
                        ))
                        return
                    if not self.is_reading:
                        break
                    if os.path.exists(wav_path) and os.path.getsize(wav_path) > 44:
                        # SND_FILENAME blocks until the wav finishes. We
                        # honor Stop by calling PlaySound(None, SND_PURGE)
                        # from stop_reading() — winsound interrupts.
                        try:
                            winsound.PlaySound(
                                wav_path,
                                winsound.SND_FILENAME | winsound.SND_NODEFAULT,
                            )
                        except RuntimeError:
                            pass  # PURGE was called from stop_reading
                except Exception as e:
                    self._highlight_queue.put(("error", str(e)))
                    return
                finally:
                    if wav_path and os.path.exists(wav_path):
                        try: os.unlink(wav_path)
                        except Exception: pass
            self._highlight_queue.put(("done",))

        self._tts_thread = threading.Thread(target=_run, daemon=True)
        self._tts_thread.start()

    # ---- PowerShell path: also highlights per chunk ---------------------
    def _speak_powershell(self, text: str, speech_start_idx: str) -> None:
        """Speak via PowerShell's System.Speech.Synthesis, one chunk at a
        time, so the same reading guide that the pyttsx3 path uses still
        works when we fall back to PowerShell.

        A worker thread runs PowerShell synchronously per chunk and
        pushes ``("highlight", tk_start, tk_end)`` events onto a thread-safe
        queue; the main thread drains the queue via a Tk after() poller
        and applies the reading tag from there. Direct Tk calls from
        the worker would race the main loop on Python 3.13 / Windows.
        """
        chunks = self._compute_spans(text, speech_start_idx, self._current_unit())
        if not chunks:
            self._on_speech_done()
            return
        self._highlight_queue = queue.Queue()

        def _run():
            for char_s, char_e, tk_s, tk_e in chunks:
                if not self.is_reading:
                    break
                chunk_text = text[char_s:char_e].strip()
                if not chunk_text:
                    continue
                self._highlight_queue.put(("highlight", tk_s, tk_e))
                tmp = None
                try:
                    fd, tmp = tempfile.mkstemp(suffix=".txt", text=False)
                    os.close(fd)
                    with open(tmp, "w", encoding="utf-8") as f:
                        f.write(chunk_text)
                    ps_cmd = (
                        "Add-Type -AssemblyName System.Speech; "
                        f"$t = Get-Content -Raw -Encoding UTF8 -LiteralPath '{tmp}'; "
                        "$s = New-Object System.Speech.Synthesis.SpeechSynthesizer; "
                        "$s.Speak($t)"
                    )
                    _vlog(f"  SAPI.Popen   chunk_len={len(chunk_text)}  tmp={tmp!r}")
                    # Capture stderr so SAPI failures surface in the
                    # status bar instead of producing silent no-audio.
                    proc = subprocess.Popen(
                        ["powershell", "-NoProfile", "-Command", ps_cmd],
                        stdin=subprocess.DEVNULL,
                        stdout=subprocess.DEVNULL,
                        stderr=subprocess.PIPE,
                        creationflags=getattr(subprocess, "CREATE_NO_WINDOW", 0),
                    )
                    self._ps_proc = proc
                    _stderr_bytes = b""
                    try:
                        _, _stderr_bytes = proc.communicate(timeout=120)
                    except subprocess.TimeoutExpired:
                        proc.kill()
                        _, _stderr_bytes = proc.communicate()
                        self._highlight_queue.put((
                            "error",
                            "Microsoft System voice timed out after 120s. "
                            "SAPI may be busy with another process.",
                        ))
                        return
                    self._ps_proc = None
                    if proc.returncode != 0:
                        err_tail = (_stderr_bytes or b"").decode("utf-8", "replace").strip()[-500:]
                        if not err_tail:
                            err_tail = ("PowerShell exited with code "
                                        f"{proc.returncode} but produced no stderr.")
                        self._highlight_queue.put((
                            "error",
                            f"Microsoft System voice failed: {err_tail}",
                        ))
                        return
                except Exception as e:
                    self._highlight_queue.put(("error", str(e)))
                    return
                finally:
                    if tmp and os.path.exists(tmp):
                        try: os.unlink(tmp)
                        except Exception: pass
            self._highlight_queue.put(("done",))

        self._tts_thread = threading.Thread(target=_run, daemon=True)
        self._tts_thread.start()
        self._ps_poll_queue()

    def _current_unit(self) -> str:
        return self.highlight_unit_var.get() if hasattr(self, "highlight_unit_var") else "Sentence"

    def _ps_poll_queue(self) -> None:
        """Drain the PowerShell-path highlight queue on the main thread."""
        try:
            while True:
                msg = self._highlight_queue.get_nowait()
                tag = msg[0]
                if tag == "highlight":
                    _, tk_s, tk_e = msg
                    self._highlight_range(tk_s, tk_e)
                elif tag == "done":
                    self._finish_ps_reading()
                    return
                elif tag == "error":
                    self._on_speech_error(msg[1])
                    return
        except queue.Empty:
            pass
        if self.is_reading:
            self._pump_after_id = self.root.after(40, self._ps_poll_queue)

    def _finish_ps_reading(self) -> None:
        if self._pump_after_id is not None:
            try: self.root.after_cancel(self._pump_after_id)
            except Exception: pass
            self._pump_after_id = None
        try:
            self._rw().tag_remove("reading", "1.0", tk.END)
        except tk.TclError:
            pass
        self._on_speech_done()

    def stop_reading(self) -> None:
        if not self.is_reading:
            return
        self.is_reading = False
        if self.tts_mode == "pyttsx3" and self.tts_engine is not None:
            try:
                self.tts_engine.stop()
            except Exception:
                pass
            self._teardown_tts_loop()
        else:
            if self._ps_proc is not None:
                try: self._ps_proc.terminate()
                except Exception: pass
                self._ps_proc = None
            # Piper mode plays via winsound — PURGE interrupts the
            # currently-playing wav. No-op for PowerShell mode.
            if self.tts_mode == "piper":
                try:
                    import winsound
                    winsound.PlaySound(None, winsound.SND_PURGE)
                except Exception:
                    pass
            if self._pump_after_id is not None:
                try: self.root.after_cancel(self._pump_after_id)
                except Exception: pass
                self._pump_after_id = None
        try:
            self._rw().tag_remove("reading", "1.0", tk.END)
        except tk.TclError:
            pass
        self._read_widget = None
        self._matrix_set_read_btn(False)
        self.set_status("Stopped.")

    # ---- Microphone / voice note ---------------------------------------
    # Single mic stack: on-device faster-whisper (Whisper STT) fed by
    # sounddevice for capture and noisereduce for noise suppression.
    # See requirements.txt and the README's "Voice dictation (Whisper)"
    # section — this is the canonical and only dictation path.

    def toggle_mic(self) -> None:
        """Mic button handler — start listening if off, stop if on."""
        if self.is_listening:
            self._stop_mic()
            return
        if self.is_reading:
            messagebox.showinfo(
                "Stop reading first",
                "Read aloud is currently playing through the speakers, "
                "which the microphone would pick up. Click ■ Stop, then "
                "press 🎤 Voice note again.",
            )
            return
        self._start_mic()

    def _start_mic(self) -> None:
        """Start dictation. Whisper-only — on-device faster-whisper with
        sounddevice capture. If Whisper isn't installed, we tell the user
        how to install it instead of silently falling back to a worse mic."""
        if not HAS_WHISPER:
            messagebox.showerror(
                "Voice dictation unavailable",
                "Voice dictation needs the Whisper stack:\n\n"
                "    py -3 -m pip install faster-whisper sounddevice "
                "numpy noisereduce\n\n"
                "(See requirements.txt — these are the only supported "
                "microphone components.)")
            return
        self._mic_queue = queue.Queue()
        self.is_listening = True

        # Mic UI: red "Stop" while recording.
        self.mic_btn.configure(text="■  Stop mic", bg=ACCENT_RED,
                               activebackground=ACCENT_RED)
        for _attr in ("_matrix_mic_btn", "_study_notes_mic_btn",
                      "_journal_mic_btn", "_planner_mic_btn", "_goals_mic_btn"):
            _mmb = getattr(self, _attr, None)
            if _mmb is not None:
                try:
                    _mmb.configure(text="■ Stop", bg=ACCENT_RED,
                                   activebackground=ACCENT_RED)
                except tk.TclError:
                    pass
        for _ssb in getattr(self, "_session_start_mic_btns", []):
            try:
                _ssb.configure(text="■ Stop", bg=ACCENT_RED,
                               activebackground=ACCENT_RED)
            except tk.TclError:
                pass

        # Lock the dictation target for this listening session. We use
        # whichever text widget the user last clicked into — falls back
        # to Notes if nothing has been focused yet, or if the previous
        # target (e.g. a Matrix quadrant) has since been destroyed.
        target = getattr(self, "_mic_target", None) or self.notes_area
        try:
            if not target.winfo_exists():
                target = self.notes_area
        except (tk.TclError, AttributeError):
            target = self.notes_area
        self._mic_active_target = target
        try:
            target.focus_set()
            if isinstance(target, (tk.Entry, ttk.Entry)):
                # Entry widgets (e.g. the Planner day boxes) don't have
                # Text's mark_set/see — position the caret at the end instead.
                target.icursor(tk.END)
            else:
                target.mark_set(tk.INSERT, tk.INSERT)
                target.see(tk.INSERT)
        except (tk.TclError, AttributeError):
            pass
        target_name = self._mic_target_label(target)
        self._mic_target_name = target_name

        # Whisper-only: capture audio + transcribe with faster-whisper.
        self._whisper_stop = threading.Event()
        self._mic_thread = threading.Thread(
            target=self._whisper_record_loop, daemon=True)
        self._mic_thread.start()
        self.set_status(
            f"🎤 Starting Whisper… dictation will go to {target_name}.")
        self._mic_poll_after_id = self.root.after(50, self._mic_poll_queue)

    def _ensure_whisper_model(self):
        """Load the Whisper model once (thread-safe). Returns the model."""
        if self._whisper_model is None:
            with self._whisper_lock:
                if self._whisper_model is None:
                    from faster_whisper import WhisperModel
                    t0 = time.time()
                    self._whisper_model = WhisperModel(
                        self._whisper_model_name, device="cpu",
                        compute_type="int8")
                    _vlog(f"mic: whisper model loaded in {time.time()-t0:.1f}s")
        return self._whisper_model

    def _set_mic_quality(self, val: str) -> None:
        """Switch the speech model: Fast=base.en, Accurate=small.en,
        Best=medium.en (more accurate, slower, ~1.5 GB first-time download)."""
        mapping = {"Fast": "base.en", "Accurate": "small.en", "Best": "medium.en"}
        name = mapping.get(val, "small.en")
        if name == self._whisper_model_name:
            return
        if self.is_listening:
            self._stop_mic()
        self._whisper_model_name = name
        self._whisper_model = None   # force reload of the new model
        note = " (large download the first time)" if val == "Best" else ""
        self.set_status(f"🎤 Mic accuracy: {val} — loading {name}{note}…")
        self._preload_whisper()

    def _preload_whisper(self) -> None:
        """Warm the Whisper model in the background at startup so the first
        🎤 click doesn't pause to load it."""
        if not HAS_WHISPER:
            return

        def _load():
            try:
                self._ensure_whisper_model()
                _vlog("mic: model pre-warmed at startup")
            except Exception as e:
                _vlog(f"mic: preload failed: {e}")
        threading.Thread(target=_load, daemon=True).start()

    def _whisper_record_loop(self) -> None:
        """Capture mic audio CONTINUOUSLY (callback) and transcribe phrases with
        faster-whisper. Capture runs in PortAudio's own thread, so audio is
        never dropped while a phrase is being transcribed — fixing words lost
        between phrases. Quiet mics are gain-boosted before recognition."""
        try:
            import numpy as np
            import sounddevice as sd
            import queue as _q
            from faster_whisper import WhisperModel
        except Exception as e:
            self._mic_queue.put(("error", f"Whisper unavailable: {e}"))
            return
        try:
            import noisereduce as _nr
        except Exception:
            _nr = None
        SR = 16000
        FRAME = int(SR * 0.1)      # 100 ms blocks
        MAX_SIL = 1.0              # trailing silence (s) that ends a phrase
        MAX_UTT = 18.0             # force-flush a very long phrase (s)
        MIN_UTT = 0.25             # ignore blips shorter than this (s)
        try:
            self._ensure_whisper_model()
        except Exception as e:
            self._mic_queue.put(("error", f"Could not load Whisper model: {e}"))
            return

        def _rms(c):
            return float(np.sqrt(np.mean(c * c)) + 1e-12)

        def _process(frames, dur):
            """Denoise → gain-normalize → transcribe → emit a buffered phrase."""
            if not frames:
                return
            audio = np.concatenate(frames)
            if len(audio) < int(SR * MIN_UTT):
                return
            if _nr is not None and self._mic_denoise:
                try:
                    audio = _nr.reduce_noise(
                        y=audio, sr=SR, stationary=True,
                        prop_decrease=0.9).astype(np.float32)
                except Exception:
                    pass
            # Boost quiet mics: normalize peak toward ~0.3 (cap the gain so we
            # don't amplify pure noise to absurd levels).
            peak = float(np.max(np.abs(audio))) if len(audio) else 0.0
            if 0 < peak < 0.3:
                audio = (audio * min(8.0, 0.3 / peak)).astype(np.float32)
            text = self._whisper_transcribe(audio)
            _vlog(f"mic: phrase {dur:.1f}s peak={peak:.4f} -> {text!r}")
            if text:
                self._mic_queue.put(("text", text))

        audio_q: "queue.Queue" = _q.Queue()

        def _cb(indata, _frames, _t, status):
            try:
                audio_q.put(indata[:, 0].copy())
            except Exception:
                pass

        # RELIABLE design: record EVERYTHING from the moment the stream opens
        # (no gate that can drop quiet/early speech). Energy is used only to
        # decide *when* to flush a chunk for transcription — on a pause, or a
        # max length, or when the user clicks Stop. Whisper's own VAD trims any
        # silence inside each chunk, so whatever you say always gets typed.
        FLUSH_SIL = 1.4            # pause (s) that flushes a chunk for liveness
        MAX_BUF = 16.0            # also flush if a chunk gets this long (s)
        buf, sil, had_sound, loud = [], 0.0, False, 0.0
        SIL_THRESH = 0.01         # provisional; refined after a few frames
        stop = self._whisper_stop
        calib, calibrated = [], False
        try:
            with sd.InputStream(samplerate=SR, channels=1, dtype="float32",
                                blocksize=FRAME, callback=_cb):
                self._mic_queue.put(("ready",))
                while stop is not None and not stop.is_set():
                    try:
                        chunk = audio_q.get(timeout=0.2)
                    except _q.Empty:
                        continue
                    buf.append(chunk)                 # ALWAYS keep the audio
                    r = _rms(chunk)
                    loud = max(loud, r)
                    # Calibrate the pause threshold from the first ~0.4s.
                    if not calibrated:
                        calib.append(r)
                        if len(calib) >= 4:
                            floor = float(np.median(calib))
                            SIL_THRESH = max(0.008, min(0.05, floor * 3.0 + 0.005))
                            calibrated = True
                            _vlog(f"mic: floor={floor:.5f} flush_thresh={SIL_THRESH:.5f}")
                    if r > SIL_THRESH:
                        sil = 0.0
                        had_sound = True
                    else:
                        sil += len(chunk) / SR
                    dur = sum(len(c) for c in buf) / SR
                    # Flush on a clear pause after speech, or on max length.
                    if (had_sound and sil >= FLUSH_SIL) or dur >= MAX_BUF:
                        frames, buf, sil, had_sound = buf, [], 0.0, False
                        _process(frames, dur)
                # On Stop: transcribe everything still buffered (so a short or
                # quiet utterance is never lost).
                if buf:
                    _process(buf, sum(len(c) for c in buf) / SR)
                _vlog(f"mic: stopped. loudest frame RMS this session={loud:.5f} "
                      f"(flush threshold {SIL_THRESH:.5f})")
        except Exception as e:
            _vlog(f"mic: ERROR {type(e).__name__}: {e}")
            self._mic_queue.put(("error", f"Microphone: {e}"))
            return
        self._mic_queue.put(("done",))

    def _whisper_transcribe(self, audio) -> str:
        """Transcribe one audio phrase to text. Beam search (beam_size=5) for
        better accuracy — affordable now that capture is continuous."""
        try:
            kwargs = dict(language="en", beam_size=5, vad_filter=True)
            # Bias toward the user's learned vocabulary (names/jargon) so they
            # come out spelled their way — the Voice Memory feeding STT.
            prompt = self._voice_vocab_prompt()
            if prompt:
                kwargs["initial_prompt"] = prompt
            segments, _ = self._whisper_model.transcribe(audio, **kwargs)
            return " ".join(s.text.strip() for s in segments).strip()
        except Exception:
            return ""

    def _mic_poll_queue(self) -> None:
        """Drain the mic queue on the main thread and apply updates."""
        if not self.is_listening:
            return
        try:
            while True:
                msg = self._mic_queue.get_nowait()
                kind = msg[0]
                if kind == "text":
                    self._append_dictation(msg[1])
                elif kind == "ready":
                    target_name = getattr(self, "_mic_target_name", "Notes")
                    self.set_status(
                        f"🎤 Listening… dictating into {target_name}. "
                        "Click ■ Stop mic to finish.")
                elif kind == "error":
                    self._stop_mic(error=msg[1])
                    return
                elif kind == "done":
                    # Process exited unexpectedly — treat as stop.
                    self._stop_mic()
                    return
        except queue.Empty:
            pass
        self._mic_poll_after_id = self.root.after(50, self._mic_poll_queue)

    # ---- Voice Memory: personal dictation corrections -------------------
    def _load_voice_corrections(self) -> None:
        """Load the Voice Memory dictionary and compile a single matcher.
        Keys are lowercased; the regex is word-bounded and case-insensitive,
        longest phrases first so multi-word fixes beat single-word ones."""
        pairs: dict = {}
        try:
            for heard, meant in self._db_query(
                    "SELECT heard, meant FROM voice_corrections"):
                if heard:
                    pairs[heard.lower()] = meant
        except Exception:
            pairs = {}
        self._voice_corrections = pairs
        self._voice_corr_re = None
        if pairs:
            keys = sorted(pairs.keys(), key=len, reverse=True)
            alt = "|".join(re.escape(k) for k in keys)
            try:
                self._voice_corr_re = re.compile(
                    r"(?<!\w)(" + alt + r")(?!\w)", re.IGNORECASE)
            except re.error:
                self._voice_corr_re = None

    def _apply_voice_corrections(self, text: str) -> str:
        """Replace learned mis-hearings in a dictated phrase, then bump the
        hit count of each correction that fired."""
        rex = getattr(self, "_voice_corr_re", None)
        if not rex or not text:
            return text
        applied: set = set()

        def _sub(m):
            key = m.group(1).lower()
            repl = self._voice_corrections.get(key)
            if repl is None:
                return m.group(0)
            applied.add(key)
            return repl

        out = rex.sub(_sub, text)
        for key in applied:
            try:
                self._db_exec(
                    "UPDATE voice_corrections SET hits = hits + 1, updated_at=? "
                    "WHERE heard=?", (datetime.now().isoformat(), key))
            except Exception:
                pass
        return out

    def _voice_vocab_prompt(self) -> str:
        """A short prompt of the user's vocabulary (the distinct 'meant'
        terms) to bias Whisper toward their words/names. Capped so it stays a
        gentle nudge, not a context dump."""
        vals = list(dict.fromkeys(self._voice_corrections.values()))
        if not vals:
            return ""
        return (", ".join(vals))[:220]

    # ---- Spelling Helper (offline suggestions + phonetic match) ---------
    def _get_spellchecker(self):
        """Lazily load pyspellchecker (offline). Returns the instance or None
        if the package isn't installed."""
        if self._spell_tried:
            return self._spellchecker
        self._spell_tried = True
        try:
            from spellchecker import SpellChecker
            self._spellchecker = SpellChecker()
        except Exception:
            self._spellchecker = None
        return self._spellchecker

    def _get_phonetic_index(self, sp) -> dict:
        """Build (once) a {phonetic_key: [words]} index over the most common
        words, so 'sounds-like' spellings find the real word."""
        if self._phonetic_index is not None:
            return self._phonetic_index
        idx: dict = {}
        try:
            items = sp.word_frequency.dictionary.items()
            top = sorted(items, key=lambda kv: kv[1], reverse=True)[:80000]
            for word, _cnt in top:
                k = _phonetic_key(word)
                if k:
                    idx.setdefault(k, []).append(word)
        except Exception:
            idx = {}
        self._phonetic_index = idx
        return idx

    def _spell_suggestions(self, query: str, limit: int = 8) -> list:
        """Correct-spelling candidates for a typed (mis)spelling — combining
        edit-distance (pyspellchecker) and phonetic ('sounds-like') matches,
        ranked by how common the word is."""
        sp = self._get_spellchecker()
        if sp is None:
            return []
        q = re.sub(r"[^a-z]", "", (query or "").lower())
        if not q:
            return []
        cands: set = set()
        try:
            cands |= (sp.candidates(q) or set())
        except Exception:
            pass
        try:
            best = sp.correction(q)
            if best:
                cands.add(best)
        except Exception:
            pass
        try:
            idx = self._get_phonetic_index(sp)
            cands |= set(idx.get(_phonetic_key(q), [])[:40])
        except Exception:
            pass
        try:
            if q in sp:                 # the typed word is itself valid
                cands.add(q)
        except Exception:
            pass

        def _freq(w):
            try:
                return sp.word_frequency[w]
            except Exception:
                return 0
        qk = _phonetic_key(q)
        # Rank exact sound-alikes first (what a phonetic speller actually
        # wants), then by how common the word is.
        def _rank(w):
            return (1 if _phonetic_key(w) == qk else 0, _freq(w))
        return sorted({c for c in cands if c}, key=_rank, reverse=True)[:limit]

    def _speak_word(self, text: str) -> None:
        """Speak a single word/phrase aloud (Windows System.Speech, fire-and-
        forget) so the user can confirm a spelling by ear. Independent of the
        main read-aloud so it never disturbs a reading session."""
        text = (text or "").strip()
        if not text or getattr(self, "is_reading", False):
            return
        safe = text.replace("'", "''")
        ps = ("Add-Type -AssemblyName System.Speech; "
              "$s = New-Object System.Speech.Synthesis.SpeechSynthesizer; "
              f"$s.Speak('{safe}')")
        try:
            prev = getattr(self, "_word_speak_proc", None)
            if prev is not None and prev.poll() is None:
                try:
                    prev.terminate()
                except Exception:
                    pass
            self._word_speak_proc = subprocess.Popen(
                ["powershell", "-NoProfile", "-Command", ps],
                stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                creationflags=getattr(subprocess, "CREATE_NO_WINDOW", 0))
        except Exception:
            pass

    def _word_picture(self, word: str):
        """Return the picture-dictionary emoji for a word, or None. Only
        depictable common words have one (that's how a picture dictionary
        works)."""
        return PICTURE_DICT.get(re.sub(r"[^a-z]", "", (word or "").lower()))

    def open_voice_memory(self) -> None:
        """🗣 Voice Memory editor — the personal dictation correction
        dictionary. Add 'when it hears X, write Y' fixes (auto-applied to ALL
        dictation), teach the last mis-heard phrase in one click, and remove
        fixes. Offline; stored in the voice_corrections table."""
        existing = getattr(self, "_voice_memory_win", None)
        if existing is not None:
            try:
                if existing.winfo_exists():
                    existing.lift(); existing.focus_force(); return
            except tk.TclError:
                pass

        win = tk.Toplevel(self.root)
        self._voice_memory_win = win
        win.title("🗣 Voice Memory")
        try:
            sw = win.winfo_screenwidth(); sh = win.winfo_screenheight()
        except tk.TclError:
            sw, sh = 1280, 800
        w = min(640, max(480, sw - 80)); h = min(620, max(440, sh - 120))
        win.geometry(f"{w}x{h}+{max(0,(sw-w)//2)}+{max(0,(sh-h)//2-24)}")
        win.minsize(480, 440)
        win.configure(bg=BG_DARK)
        # win.transient(self.root)  # disabled: hides Min/Max buttons on Windows

        def _close():
            self._voice_memory_win = None
            try:
                win.destroy()
            except tk.TclError:
                pass
        win.protocol("WM_DELETE_WINDOW", _close)

        head = tk.Frame(win, bg=BG_PANEL, padx=14, pady=10)
        head.pack(fill=tk.X)
        tk.Label(head, text="🗣 Voice Memory", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        tk.Label(win, text="When the mic keeps hearing a word wrong, teach it the "
                 "fix here. It's applied to everything you dictate and improves "
                 "as you add more — like a voice profile that learns your words.",
                 bg=BG_DARK, fg=FG_MUTED, wraplength=w - 36, justify=tk.LEFT,
                 font=("Segoe UI", 9)).pack(anchor="w", padx=14, pady=(8, 4))

        # ---- bottom button bar (pinned) ----
        foot = tk.Frame(win, bg=BG_DARK)
        foot.pack(side=tk.BOTTOM, fill=tk.X, padx=14, pady=10)

        # ---- add / teach row (just above the footer) ----
        addf = tk.Frame(win, bg=BG_DARK, padx=14)
        addf.pack(side=tk.BOTTOM, fill=tk.X, pady=(0, 2))
        heard_var = tk.StringVar(); meant_var = tk.StringVar()
        r1 = tk.Frame(addf, bg=BG_DARK); r1.pack(fill=tk.X, pady=(6, 2))
        tk.Label(r1, text="When it hears:", width=13, anchor="w", bg=BG_DARK,
                 fg=FG_TEXT, font=("Segoe UI", 10, "bold")).pack(side=tk.LEFT)
        he = tk.Entry(r1, textvariable=heard_var, bg=BG_INPUT, fg=FG_TEXT,
                      insertbackground=FG_TEXT, relief=tk.FLAT, font=("Segoe UI", 11))
        he.pack(side=tk.LEFT, fill=tk.X, expand=True, ipady=3)
        r2 = tk.Frame(addf, bg=BG_DARK); r2.pack(fill=tk.X, pady=2)
        tk.Label(r2, text="Write instead:", width=13, anchor="w", bg=BG_DARK,
                 fg=FG_TEXT, font=("Segoe UI", 10, "bold")).pack(side=tk.LEFT)
        me = tk.Entry(r2, textvariable=meant_var, bg=BG_INPUT, fg=FG_TEXT,
                      insertbackground=FG_TEXT, relief=tk.FLAT, font=("Segoe UI", 11))
        me.pack(side=tk.LEFT, fill=tk.X, expand=True, ipady=3)
        for _e in (he, me):
            self._attach_clipboard_menu(
                _e, clear_cmd=(lambda w=_e: self._clear_input(w)),
                clear_label="Clear", track_for_mic=False)

        # ---- list of corrections ----
        listwrap = tk.Frame(win, bg=BG_DARK, padx=14)
        listwrap.pack(side=tk.TOP, fill=tk.BOTH, expand=True, pady=(4, 0))
        lb = tk.Listbox(listwrap, bg=BG_INPUT, fg=FG_TEXT, relief=tk.FLAT, bd=0,
                        font=("Segoe UI", 11), selectbackground=ACCENT_SLATE,
                        selectforeground="white", activestyle="none",
                        highlightthickness=0)
        sb = tk.Scrollbar(listwrap, command=lb.yview, width=14)
        lb.configure(yscrollcommand=sb.set)
        sb.pack(side=tk.RIGHT, fill=tk.Y)
        lb.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        ids: list = []

        def _refresh():
            lb.delete(0, tk.END); ids.clear()
            try:
                rows = self._db_query(
                    "SELECT id, heard, meant, hits FROM voice_corrections "
                    "ORDER BY hits DESC, meant ASC")
            except Exception:
                rows = []
            if not rows:
                lb.insert(tk.END, "  (no corrections yet — add one below)")
                ids.append(None)
                return
            for rid, heard, meant, hits in rows:
                lb.insert(tk.END, f"  “{heard}”   →   {meant}    ({hits}×)")
                ids.append((rid, heard, meant))

        def _add():
            h = heard_var.get().strip(); m = meant_var.get().strip()
            if not h or not m:
                self.set_status("Fill in both: what it hears, and what to write.")
                return
            now = datetime.now().isoformat()
            try:
                if self._db_query("SELECT id FROM voice_corrections WHERE heard=?",
                                  (h.lower(),)):
                    self._db_exec("UPDATE voice_corrections SET meant=?, "
                                  "updated_at=? WHERE heard=?", (m, now, h.lower()))
                else:
                    self._db_exec("INSERT INTO voice_corrections "
                                  "(heard,meant,hits,created_at,updated_at) "
                                  "VALUES (?,?,0,?,?)", (h.lower(), m, now, now))
            except Exception as e:
                messagebox.showerror("Could not save", str(e))
                return
            heard_var.set(""); meant_var.set("")
            self._load_voice_corrections(); _refresh()
            self.set_status(f"🗣 Voice Memory: it will now write “{m}”.")
            he.focus_set()

        def _fix_last():
            last = (getattr(self, "_last_dictation", "") or "").strip()
            if not last:
                self.set_status("Dictate something first, then click Fix last.")
                return
            heard_var.set(last); meant_var.set("")
            me.focus_set()

        def _delete():
            sel = lb.curselection()
            if not sel:
                self.set_status("Pick a correction in the list to delete.")
                return
            item = ids[sel[0]] if sel[0] < len(ids) else None
            if not item:
                return
            try:
                self._db_exec("DELETE FROM voice_corrections WHERE id=?", (item[0],))
            except Exception as e:
                messagebox.showerror("Could not delete", str(e))
                return
            self._load_voice_corrections(); _refresh()

        he.bind("<Return>", lambda _e: (me.focus_set(), "break")[1])
        me.bind("<Return>", lambda _e: (_add(), "break")[1])

        tk.Button(addf, text="➕ Add / update", command=_add,
                  font=("Segoe UI", 10, "bold"), bg=ACCENT_GREEN, fg="white",
                  activebackground=ACCENT_GREEN, relief=tk.FLAT, padx=12, pady=4,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT, pady=(6, 0))
        tk.Button(addf, text="🎤 Fix last heard", command=_fix_last,
                  font=("Segoe UI", 10, "bold"), bg=ACCENT_MIC, fg="white",
                  activebackground=ACCENT_MIC, relief=tk.FLAT, padx=12, pady=4,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT, padx=(8, 0),
                                                      pady=(6, 0))

        tk.Button(foot, text="🗑 Delete selected", command=_delete,
                  font=("Segoe UI", 10), bg=ACCENT_RED, fg="white",
                  activebackground=ACCENT_RED, relief=tk.FLAT, padx=12, pady=5,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT)
        tk.Button(foot, text="Close", command=_close,
                  font=("Segoe UI", 10), bg=ACCENT_SLATE, fg="white",
                  activebackground=ACCENT_SLATE, relief=tk.FLAT, padx=12, pady=5,
                  cursor="hand2", borderwidth=0).pack(side=tk.RIGHT)

        # ---- Spelling Helper + picture dictionary: type how a word SOUNDS,
        # get correct spellings (with a picture for common words) you can hear
        # and click into the "Write instead" box above. ---------------------
        spellf = tk.Frame(win, bg=BG_DARK, padx=14)
        spellf.pack(side=tk.BOTTOM, fill=tk.X, pady=(0, 2))
        sh_head = tk.Frame(spellf, bg=BG_DARK)
        sh_head.pack(fill=tk.X, pady=(6, 0))
        tk.Label(sh_head, text="✏️ Spell it — type how it sounds:", bg=BG_DARK,
                 fg=FG_TEXT, font=("Segoe UI", 10, "bold")).pack(side=tk.LEFT)
        sound_var = tk.StringVar()
        sh_in = tk.Entry(sh_head, textvariable=sound_var, bg=BG_INPUT, fg=FG_TEXT,
                         insertbackground=FG_TEXT, relief=tk.FLAT,
                         font=("Segoe UI", 11))
        sh_in.pack(side=tk.LEFT, fill=tk.X, expand=True, padx=(8, 6), ipady=3)
        self._attach_clipboard_menu(
            sh_in, clear_cmd=lambda: self._clear_input(sh_in),
            clear_label="Clear", track_for_mic=False)
        say_letters = tk.BooleanVar(value=False)

        # Picture-dictionary display — a big symbol + the word for depictable
        # common words (🐶 dog, 🧀 cheese), updated live as you type.
        picf = tk.Frame(spellf, bg=BG_DARK)
        picf.pack(fill=tk.X)
        pic_lbl = tk.Label(picf, text="", bg=BG_DARK, fg=FG_TEXT,
                           font=("Segoe UI Emoji", 40))
        pic_lbl.pack(side=tk.LEFT, padx=(0, 10))
        picword = tk.Label(picf, text="", bg=BG_DARK, fg=ACCENT_CYAN,
                           font=("Segoe UI", 14, "bold"))
        picword.pack(side=tk.LEFT)

        def _show_picture(word):
            pic = self._word_picture(word)
            pic_lbl.configure(text=pic or "")
            picword.configure(text=(word if pic else ""))

        sugg_wrap = tk.Frame(spellf, bg=BG_DARK)
        sugg_wrap.pack(fill=tk.X, pady=(4, 2))

        def _find_spellings(*_):
            for c in sugg_wrap.winfo_children():
                c.destroy()
            q = sound_var.get().strip()
            if not q:
                return
            if self._get_spellchecker() is None:
                tk.Label(sugg_wrap, text="(Spelling suggestions need the "
                         "pyspellchecker add-on installed.)", bg=BG_DARK,
                         fg=FG_MUTED, font=("Segoe UI", 9, "italic")
                         ).pack(anchor="w")
                return
            self.set_status("✏️ Finding spellings…")
            sugg = self._spell_suggestions(q)
            if not sugg:
                tk.Label(sugg_wrap, text="No close matches — try spelling it a "
                         "little differently.", bg=BG_DARK, fg=FG_MUTED,
                         font=("Segoe UI", 9, "italic")).pack(anchor="w")
                self.set_status("No close spelling matches.")
                return
            self.set_status(f"✏️ {len(sugg)} suggestion(s) — click to use, 🔊 to hear.")
            for word in sugg:
                pic = self._word_picture(word)
                chip = tk.Frame(sugg_wrap, bg=BG_PANEL)
                chip.pack(side=tk.LEFT, padx=(0, 6), pady=2)
                tk.Button(chip, text=(f"{pic} {word}" if pic else word),
                          command=lambda w=word: (meant_var.set(w),
                                                  _show_picture(w), me.focus_set()),
                          font=("Segoe UI", 10, "bold"), bg=BG_PANEL, fg=FG_TEXT,
                          activebackground=ACCENT_SLATE, activeforeground="white",
                          relief=tk.FLAT, padx=6, pady=2, cursor="hand2",
                          borderwidth=0).pack(side=tk.LEFT)
                tk.Button(chip, text="🔊", command=lambda w=word: self._speak_word(w),
                          font=("Segoe UI", 9), bg=BG_PANEL, fg=ACCENT_GREEN,
                          activebackground=BG_PANEL, relief=tk.FLAT, padx=3, pady=2,
                          cursor="hand2", borderwidth=0).pack(side=tk.LEFT)

        def _on_key(ev=None):
            _show_picture(sound_var.get().strip())
            if (say_letters.get() and ev is not None
                    and getattr(ev, "char", "") and ev.char.isalpha()):
                self._speak_word(ev.char)

        tk.Button(sh_head, text="🔎 Find", command=_find_spellings,
                  font=("Segoe UI", 9, "bold"), bg=ACCENT_CYAN, fg="white",
                  activebackground=ACCENT_CYAN, relief=tk.FLAT, padx=8, pady=2,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT)
        tk.Button(sh_head, text="🔊 Hear",
                  command=lambda: self._speak_word(sound_var.get()),
                  font=("Segoe UI", 9, "bold"), bg=ACCENT_GREEN, fg="white",
                  activebackground=ACCENT_GREEN, relief=tk.FLAT, padx=8, pady=2,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT, padx=(6, 0))
        tk.Checkbutton(sh_head, text="say letters", variable=say_letters,
                       bg=BG_DARK, fg=FG_MUTED, selectcolor=BG_INPUT,
                       activebackground=BG_DARK, activeforeground=FG_TEXT,
                       font=("Segoe UI", 9)).pack(side=tk.LEFT, padx=(8, 0))
        sh_in.bind("<KeyRelease>", _on_key)
        sh_in.bind("<Return>", lambda _e: (_find_spellings(), "break")[1])

        _refresh()
        he.focus_set()

    def _append_dictation(self, text: str) -> None:
        """Insert a recognized phrase at the active target's cursor with
        smart spacing (don't double-space; trailing space so the next
        phrase flows on). The target is whichever text widget had focus
        when the user clicked 🎤 — Notes by default, Reader if they
        clicked into the reader first. Learned Voice Memory corrections are
        applied first, and the raw phrase is remembered for 'Fix last'."""
        text = text.strip()
        if not text:
            return
        self._last_dictation = text                      # raw heard
        text = self._apply_voice_corrections(text)
        target = getattr(self, "_mic_active_target", None) or self.notes_area
        # Entry widgets (e.g. the Planner day boxes) take plain end-insertion.
        if isinstance(target, (tk.Entry, ttk.Entry)):
            try:
                cur = target.get()
                lead = "" if (not cur or cur.endswith(" ")) else " "
                target.insert(tk.END, lead + text + " ")
            except tk.TclError:
                pass
            return
        try:
            prev_char = target.get("insert -1c", "insert")
        except tk.TclError:
            prev_char = ""
        leading = "" if (prev_char == "" or prev_char.isspace()) else " "
        try:
            target.insert(tk.INSERT, leading + text + " ")
            target.see(tk.INSERT)
        except tk.TclError:
            # Widget gone (window closed mid-dictation) — bail quietly.
            pass
        # If we just wrote to Notes, _on_notes_modified will pick it up and
        # debounce-save to disk. Reader writes are session-only.

    def _stop_mic(self, error: str | None = None) -> None:
        """Tear down the Whisper capture thread and reset the mic UI."""
        self.is_listening = False
        if self._mic_poll_after_id is not None:
            try: self.root.after_cancel(self._mic_poll_after_id)
            except Exception: pass
            self._mic_poll_after_id = None
        # Stop the Whisper capture thread if it's running.
        if self._whisper_stop is not None:
            self._whisper_stop.set()
            th = self._mic_thread
            if th is not None and th.is_alive() and th is not threading.current_thread():
                try: th.join(timeout=4)
                except Exception: pass
            self._whisper_stop = None
            # Drain any final recognized text the thread queued as it stopped,
            # so the last phrase isn't lost once polling ends.
            if self._mic_queue is not None:
                try:
                    while True:
                        msg = self._mic_queue.get_nowait()
                        if msg and msg[0] == "text":
                            self._append_dictation(msg[1])
                except Exception:
                    pass
            # If dictation was going into a Planner day box, add it as a note
            # for that day automatically (so "talk -> note on the calendar").
            tgt = getattr(self, "_mic_active_target", None)
            pents = getattr(self, "_planner_entries", {}) or {}
            for _ds, _w in pents.items():
                if _w is tgt:
                    try:
                        self._planner_add_task(_ds)
                    except Exception:
                        pass
                    break
        # Restore the idle button.
        try:
            self.mic_btn.configure(text="🎤  Voice note", bg=ACCENT_MIC,
                                   activebackground=ACCENT_MIC)
        except Exception:
            pass
        for _attr in ("_matrix_mic_btn", "_study_notes_mic_btn",
                      "_journal_mic_btn", "_planner_mic_btn", "_goals_mic_btn"):
            _mmb = getattr(self, _attr, None)
            if _mmb is not None:
                try:
                    _mmb.configure(text="🎤 Voice", bg=ACCENT_MIC,
                                   activebackground=ACCENT_MIC)
                except tk.TclError:
                    pass
        for _ssb in getattr(self, "_session_start_mic_btns", []):
            try:
                _ssb.configure(text="🎤", bg=ACCENT_MIC,
                               activebackground=ACCENT_MIC)
            except tk.TclError:
                pass
        # Reset the per-day Planner mic (short label).
        _pam = getattr(self, "_planner_active_mic", None)
        if _pam is not None:
            try:
                _pam.configure(text="🎤", bg=ACCENT_MIC, activebackground=ACCENT_MIC)
            except tk.TclError:
                pass
            self._planner_active_mic = None
        if error:
            log_path = os.path.join(os.environ.get("TEMP", ""),
                                     "bookreader_mic.log")
            messagebox.showerror(
                "Microphone could not start",
                f"{error}\n\n"
                "Tips:\n"
                "  • Plug in a microphone and set it as the default input "
                "device in Windows Sound settings.\n"
                "  • Windows Settings → Time & Language → Speech: install "
                "an English (or your language) speech pack.\n"
                "  • Windows Settings → Privacy → Microphone: allow desktop "
                "apps to use the microphone.\n\n"
                f"Diagnostic log: {log_path}",
            )
            self.set_status("Microphone error.")
        else:
            self.set_status("Mic off.")

    # ====================================================================
    # STUDY MODE — five e-Sword-inspired companions for secular reading.
    # Design lift: source content (books) lives in one place; user content
    # (highlights, bookmarks, topics, glossary, journal) lives in a
    # separate SQLite database. Location-anchored items (highlights,
    # bookmarks) reference (book_key, char_offset). None of this is
    # religious — the schema, labels, and workflow are all general-purpose.
    # ====================================================================

    # ---- Database helpers (implementation in lyceum.db.study_db) -------
    def _init_study_db(self) -> None:
        init_study_db()

    def _db(self) -> sqlite3.Connection:
        return _db_connect()

    def _db_query(self, sql: str, params: tuple = ()) -> list[tuple]:
        return _db_query_fn(sql, params)

    def _db_exec(self, sql: str, params: tuple = ()) -> int:
        return _db_exec_fn(sql, params)

    # ---- Prompt Library (green-button window) ---------------------------
    # A standalone archive of prompt + response pairs, stored in the study
    # SQLite DB (table prompt_library). Deliberately separate from the Books
    # library (which is .md files in LIBRARY_DIR) — no mixing.
    def _board_text(self) -> str:
        """The reader's current selection if there is one, else the whole
        reading board."""
        try:
            sel = self.text_area.get("sel.first", "sel.last")
            if sel.strip():
                return sel
        except tk.TclError:
            pass
        return self.text_area.get("1.0", tk.END)

    def save_board_to_prompt_library(self) -> None:
        """Right-click action on the reader: save the selection (or the whole
        board) as a new Prompt Library entry, then open the window on it."""
        text = self._board_text().strip()
        if not text:
            messagebox.showinfo(
                "Prompt Library",
                "There's nothing on the reader to save yet.")
            return
        lines = [ln.strip() for ln in text.splitlines() if ln.strip()]
        title = (lines[0][:60] if lines else "") or "Saved from reader"
        now = datetime.now().isoformat(timespec="seconds")
        src = self.current_file or "(reader board)"
        new_id = self._db_exec(
            "INSERT INTO prompt_library "
            "(title, prompt, response, source, created_at, updated_at) "
            "VALUES (?,?,?,?,?,?)",
            (title, text, "", src, now, now))
        self.set_status(f"🗒 Saved to Prompt Library: {title}")
        self.open_prompt_library(select_id=new_id)

    def open_prompt_library(self, select_id: int | None = None) -> None:
        """Open (or focus) the Prompt Library window."""
        if self._prompt_lib_win is not None:
            try:
                if self._prompt_lib_win.winfo_exists():
                    self._prompt_lib_win.lift()
                    self._prompt_lib_win.focus_force()
                    self._prompt_lib_refresh(select_id=select_id)
                    return
            except tk.TclError:
                pass
            self._prompt_lib_win = None

        win = tk.Toplevel(self.root)
        self._prompt_lib_win = win
        win.title("🗒 Prompt Library")
        win.geometry("960x620")
        win.minsize(700, 460)
        win.configure(bg=BG_DARK)

        header = tk.Frame(win, bg=BG_PANEL, padx=14, pady=10)
        header.pack(fill=tk.X)
        tk.Label(header, text="🗒 Prompt Library", bg=BG_PANEL, fg=FG_TEXT,
                 font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        tk.Label(header,
                 text="Your saved prompts + responses — kept separate from "
                      "your Books library.",
                 bg=BG_PANEL, fg=FG_MUTED, font=("Segoe UI", 9)
                 ).pack(side=tk.LEFT, padx=12)

        panes = tk.PanedWindow(win, orient=tk.HORIZONTAL, bg=BG_DARK,
                               sashwidth=6, bd=0)
        panes.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)

        # Left: list of entries
        left = tk.Frame(panes, bg=BG_DARK)
        lb = tk.Listbox(left, bg=BG_INPUT, fg=FG_TEXT,
                        selectbackground=ACCENT_CYAN, selectforeground="white",
                        font=("Segoe UI", 10), relief=tk.FLAT, bd=0,
                        activestyle="none", highlightthickness=0)
        lb.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        lsb = tk.Scrollbar(left, command=lb.yview)
        lsb.pack(side=tk.RIGHT, fill=tk.Y)
        lb.configure(yscrollcommand=lsb.set)
        lb.bind("<<ListboxSelect>>", lambda _e: self._prompt_lib_on_select())
        self._prompt_lib_listbox = lb

        # Right-click an entry → New / Delete (in addition to the buttons).
        list_menu = tk.Menu(lb, tearoff=0, bg=BG_PANEL, fg=FG_TEXT,
                            activebackground=ACCENT_SLATE,
                            activeforeground="white")
        list_menu.add_command(label="➕  New entry",
                              command=self._prompt_lib_new)
        list_menu.add_command(label="🗑  Delete this entry",
                              command=self._prompt_lib_delete_current)

        def _pl_list_rclick(event):
            idx = lb.nearest(event.y)
            if 0 <= idx < len(self._prompt_lib_items):
                lb.selection_clear(0, tk.END)
                lb.selection_set(idx)
                self._prompt_lib_load(self._prompt_lib_items[idx][0])
            try:
                list_menu.tk_popup(event.x_root, event.y_root)
            finally:
                list_menu.grab_release()

        lb.bind("<Button-3>", _pl_list_rclick)
        panes.add(left, minsize=240, stretch="always")

        # Right: detail (title + prompt + response + buttons)
        right = tk.Frame(panes, bg=BG_DARK)
        tk.Label(right, text="Title", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 9, "bold")
                 ).pack(anchor=tk.W, padx=10, pady=(6, 2))
        self._prompt_lib_title_var = tk.StringVar()
        tk.Entry(right, textvariable=self._prompt_lib_title_var,
                 bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                 font=("Segoe UI", 11), relief=tk.FLAT, bd=0
                 ).pack(fill=tk.X, padx=10, ipady=5)

        _yellow = self.HIGHLIGHT_COLORS.get("Yellow", "#fde047")
        prow = tk.Frame(right, bg=BG_DARK)
        prow.pack(fill=tk.X, padx=10, pady=(10, 2))
        tk.Label(prow, text="Prompt  (your message)", bg=BG_DARK, fg=FG_TEXT,
                 font=("Segoe UI", 10, "bold")).pack(side=tk.LEFT)
        tk.Button(prow, text="🔊 Listen",
                  command=lambda: self._prompt_lib_read("prompt"),
                  bg=ACCENT_GREEN, fg="white", font=("Segoe UI", 9, "bold"),
                  relief=tk.FLAT, padx=8, pady=2, cursor="hand2", borderwidth=0
                  ).pack(side=tk.RIGHT)
        pt_frame = tk.Frame(right, bg=BG_DARK)
        pt_frame.pack(fill=tk.BOTH, expand=True, padx=10)
        pt = tk.Text(pt_frame, height=8, bg=BG_INPUT, fg=FG_TEXT,
                     insertbackground=FG_TEXT, font=("Segoe UI", 10),
                     relief=tk.FLAT, bd=0, wrap=tk.WORD)
        pt.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        pt_sb = tk.Scrollbar(pt_frame, command=pt.yview)
        pt_sb.pack(side=tk.RIGHT, fill=tk.Y)
        pt.configure(yscrollcommand=pt_sb.set)
        pt.tag_configure("reading", background=_yellow, foreground="#0f172a")
        pt.tag_raise("reading", "sel")
        self._prompt_lib_prompt_txt = pt
        self._attach_clipboard_menu(pt)

        rrow = tk.Frame(right, bg=BG_DARK)
        rrow.pack(fill=tk.X, padx=10, pady=(10, 2))
        tk.Label(rrow, text="Response  (the reply)", bg=BG_DARK, fg=FG_TEXT,
                 font=("Segoe UI", 10, "bold")).pack(side=tk.LEFT)
        tk.Button(rrow, text="🔊 Listen",
                  command=lambda: self._prompt_lib_read("response"),
                  bg=ACCENT_GREEN, fg="white", font=("Segoe UI", 9, "bold"),
                  relief=tk.FLAT, padx=8, pady=2, cursor="hand2", borderwidth=0
                  ).pack(side=tk.RIGHT)
        rt_frame = tk.Frame(right, bg=BG_DARK)
        rt_frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=(0, 6))
        rt = tk.Text(rt_frame, height=10, bg=BG_INPUT, fg=FG_TEXT,
                     insertbackground=FG_TEXT, font=("Segoe UI", 10),
                     relief=tk.FLAT, bd=0, wrap=tk.WORD)
        rt.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        rt_sb = tk.Scrollbar(rt_frame, command=rt.yview)
        rt_sb.pack(side=tk.RIGHT, fill=tk.Y)
        rt.configure(yscrollcommand=rt_sb.set)
        rt.tag_configure("reading", background=_yellow, foreground="#0f172a")
        rt.tag_raise("reading", "sel")
        self._prompt_lib_response_txt = rt
        self._attach_clipboard_menu(rt)

        br = tk.Frame(right, bg=BG_DARK)
        br.pack(fill=tk.X, padx=10, pady=(4, 10))

        def _mk(text, cmd, color):
            tk.Button(br, text=text, command=cmd, bg=color, fg="white",
                      font=("Segoe UI", 10, "bold"), relief=tk.FLAT,
                      padx=12, pady=6, cursor="hand2", borderwidth=0
                      ).pack(side=tk.LEFT, padx=(0, 6))

        _mk("💾 Save",            self._prompt_lib_save_current,  ACCENT_GREEN)
        _mk("+ New",             self._prompt_lib_new,           ACCENT_CYAN)
        _mk("📋 Paste → Response", self._prompt_lib_paste_response, ACCENT_AMBER)
        _mk("■ Stop",            self.stop_reading,              ACCENT_SLATE)
        _mk("🗑 Delete",          self._prompt_lib_delete_current, ACCENT_RED)
        panes.add(right, minsize=380, stretch="always")

        def _close():
            try:
                self._prompt_lib_save_current(silent=True)
            except Exception:
                pass
            self._prompt_lib_win = None
            try:
                win.destroy()
            except tk.TclError:
                pass

        win.protocol("WM_DELETE_WINDOW", _close)
        self._prompt_lib_refresh(select_id=select_id)

    def _prompt_lib_refresh(self, select_id: int | None = None) -> None:
        lb = self._prompt_lib_listbox
        if lb is None:
            return
        rows = self._db_query(
            "SELECT id, title, created_at FROM prompt_library "
            "ORDER BY updated_at DESC, id DESC")
        self._prompt_lib_items = rows
        lb.delete(0, tk.END)
        for _id, title, created in rows:
            stamp = (created or "")[:16].replace("T", " ")
            label = (title or "").strip() or "(untitled)"
            lb.insert(tk.END, f"{label}    ·    {stamp}")
        target = (select_id if select_id is not None
                  else self._prompt_lib_current_id)
        if target is not None:
            for i, r in enumerate(rows):
                if r[0] == target:
                    lb.selection_clear(0, tk.END)
                    lb.selection_set(i)
                    lb.see(i)
                    self._prompt_lib_load(target)
                    return
        if not rows:
            self._prompt_lib_current_id = None
            self._prompt_lib_clear_detail()

    def _prompt_lib_on_select(self) -> None:
        lb = self._prompt_lib_listbox
        if lb is None:
            return
        sel = lb.curselection()
        if not sel:
            return
        idx = sel[0]
        if idx >= len(self._prompt_lib_items):
            return
        new_id = self._prompt_lib_items[idx][0]
        if new_id == self._prompt_lib_current_id:
            return
        # Persist edits to the entry we're leaving before loading the next.
        self._prompt_lib_save_current(silent=True)
        self._prompt_lib_load(new_id)

    def _prompt_lib_load(self, pid: int) -> None:
        rows = self._db_query(
            "SELECT title, prompt, response FROM prompt_library WHERE id=?",
            (pid,))
        if not rows:
            return
        title, prompt, response = rows[0]
        self._prompt_lib_current_id = pid
        if self._prompt_lib_title_var is not None:
            self._prompt_lib_title_var.set(title or "")
        if self._prompt_lib_prompt_txt is not None:
            self._prompt_lib_prompt_txt.delete("1.0", tk.END)
            self._prompt_lib_prompt_txt.insert("1.0", prompt or "")
        if self._prompt_lib_response_txt is not None:
            self._prompt_lib_response_txt.delete("1.0", tk.END)
            self._prompt_lib_response_txt.insert("1.0", response or "")

    def _prompt_lib_clear_detail(self) -> None:
        if self._prompt_lib_title_var is not None:
            self._prompt_lib_title_var.set("")
        for t in (self._prompt_lib_prompt_txt, self._prompt_lib_response_txt):
            if t is not None:
                t.delete("1.0", tk.END)

    def _prompt_lib_save_current(self, silent: bool = False) -> None:
        if self._prompt_lib_current_id is None or self._prompt_lib_title_var is None:
            return
        title = self._prompt_lib_title_var.get().strip()
        prompt = (self._prompt_lib_prompt_txt.get("1.0", tk.END).strip()
                  if self._prompt_lib_prompt_txt is not None else "")
        response = (self._prompt_lib_response_txt.get("1.0", tk.END).strip()
                    if self._prompt_lib_response_txt is not None else "")
        now = datetime.now().isoformat(timespec="seconds")
        self._db_exec(
            "UPDATE prompt_library SET title=?, prompt=?, response=?, "
            "updated_at=? WHERE id=?",
            (title, prompt, response, now, self._prompt_lib_current_id))
        if not silent:
            self.set_status("🗒 Prompt Library entry saved.")
            self._prompt_lib_refresh(select_id=self._prompt_lib_current_id)

    def _prompt_lib_new(self) -> None:
        self._prompt_lib_save_current(silent=True)
        now = datetime.now().isoformat(timespec="seconds")
        new_id = self._db_exec(
            "INSERT INTO prompt_library "
            "(title, prompt, response, source, created_at, updated_at) "
            "VALUES (?,?,?,?,?,?)",
            ("New entry", "", "", "", now, now))
        self._prompt_lib_current_id = new_id
        self._prompt_lib_refresh(select_id=new_id)
        if self._prompt_lib_prompt_txt is not None:
            self._prompt_lib_prompt_txt.focus_set()

    def _prompt_lib_delete_current(self) -> None:
        if self._prompt_lib_current_id is None:
            return
        if not messagebox.askyesno(
                "Delete entry?",
                "Delete this Prompt Library entry? This can't be undone."):
            return
        self._db_exec("DELETE FROM prompt_library WHERE id=?",
                      (self._prompt_lib_current_id,))
        self._prompt_lib_current_id = None
        self._prompt_lib_clear_detail()
        self._prompt_lib_refresh()

    def _prompt_lib_paste_response(self) -> None:
        """Append the clipboard to the Response box — quick way to drop a
        copied reply in."""
        if self._prompt_lib_response_txt is None:
            return
        try:
            clip = self.root.clipboard_get()
        except tk.TclError:
            clip = ""
        if clip:
            self._prompt_lib_response_txt.insert(tk.END, clip)
            self._prompt_lib_response_txt.focus_set()

    def _prompt_lib_read(self, which: str) -> None:
        """Read the Prompt or Response box aloud, with the yellow
        follow-along highlight tracking inside that box."""
        widget = (self._prompt_lib_prompt_txt if which == "prompt"
                  else self._prompt_lib_response_txt)
        if widget is None:
            return
        if not widget.get("1.0", tk.END).strip():
            messagebox.showinfo(
                "Read aloud", f"There's no {which} text to read yet.")
            return
        if self.is_reading:
            self.stop_reading()
        # Route the reader + highlight into this box and read from the top.
        self._read_widget = widget
        try:
            widget.tag_remove(tk.SEL, "1.0", tk.END)
            widget.mark_set(tk.INSERT, "1.0")
            widget.focus_set()
        except tk.TclError:
            pass
        self.read_aloud()

    def _book_key(self, path: str | None) -> str | None:
        """Stable identifier for a book. Use a path relative to LIBRARY_DIR
        when possible so the whole library can be moved/renamed without
        breaking highlights and bookmarks; fall back to absolute path."""
        if not path:
            return None
        try:
            rel = os.path.relpath(path, LIBRARY_DIR)
            if not rel.startswith("..") and not os.path.isabs(rel):
                return "lib:" + rel.replace("\\", "/")
        except (ValueError, OSError):
            pass
        try:
            return "abs:" + os.path.abspath(path).replace("\\", "/")
        except Exception:
            return None

    def _book_path_for_key(self, key: str) -> str | None:
        if not key:
            return None
        if key.startswith("lib:"):
            return os.path.join(LIBRARY_DIR, key[4:].replace("/", os.sep))
        if key.startswith("abs:"):
            return key[4:].replace("/", os.sep)
        return key

    def _book_short_label(self, key: str | None) -> str:
        if not key:
            return "(no book)"
        if key.startswith("lib:"):
            return key[4:]
        if key.startswith("abs:"):
            return os.path.basename(key[4:])
        return key

    def _char_offset(self, tk_index: str) -> int:
        """Convert a Tk text index (e.g. '5.3') to an absolute char offset."""
        try:
            c = self.text_area.count("1.0", tk_index, "chars")
        except tk.TclError:
            return 0
        if c is None:
            return 0
        if isinstance(c, tuple):
            return int(c[0]) if c else 0
        return int(c)

    def _tk_index_for_offset(self, offset: int) -> str:
        return self.text_area.index(f"1.0 + {int(offset)} chars")

    # ---- 1. Highlights (persistent color overlay) ----------------------
    def _highlight_tag(self, color_name: str) -> str:
        """Return the tag name for `color_name`; configure it if needed."""
        tag = f"hl_{color_name.lower()}"
        color_hex = self.HIGHLIGHT_COLORS.get(color_name, "#fde047")
        try:
            self.text_area.tag_configure(tag, background=color_hex,
                                          foreground="#0f172a")
            # Reading guide must stay on top so audio-follow remains visible.
            self.text_area.tag_raise("reading", tag)
        except tk.TclError:
            pass
        return tag

    def highlight_selection(self, color_name: str | None = None) -> None:
        """Apply a persistent color highlight to the current selection."""
        try:
            s_idx = self.text_area.index(tk.SEL_FIRST)
            e_idx = self.text_area.index(tk.SEL_LAST)
            text = self.text_area.get(s_idx, e_idx)
        except tk.TclError:
            messagebox.showinfo(
                "Nothing selected",
                "Select some text in the reader first, then click 🖍 Highlight.",
            )
            return
        if not text.strip():
            return
        color = color_name or self.highlight_color_var.get() or "Yellow"
        tag = self._highlight_tag(color)
        self.text_area.tag_add(tag, s_idx, e_idx)
        book_key = self._book_key(self.current_file)
        if book_key:
            try:
                self._db_exec(
                    "INSERT INTO highlights "
                    "(book, start_offset, end_offset, text, color, created_at) "
                    "VALUES (?, ?, ?, ?, ?, ?)",
                    (book_key, self._char_offset(s_idx), self._char_offset(e_idx),
                     text, color, datetime.now().isoformat()),
                )
                self.set_status(f"🖍 Highlighted in {color} (saved).")
            except Exception as e:
                self.set_status(f"🖍 Highlighted in {color} (not saved: {e}).")
        else:
            self.set_status(
                f"🖍 Highlighted in {color} (session only — open a saved book to persist).")

    def remove_highlights_in_selection(self) -> None:
        """Clear color tags in the current selection AND delete matching
        rows in the database so they don't come back on reload."""
        try:
            s_idx = self.text_area.index(tk.SEL_FIRST)
            e_idx = self.text_area.index(tk.SEL_LAST)
        except tk.TclError:
            messagebox.showinfo("Nothing selected",
                                "Select the highlighted text first.")
            return
        for color in self.HIGHLIGHT_COLORS:
            try:
                self.text_area.tag_remove(f"hl_{color.lower()}", s_idx, e_idx)
            except tk.TclError:
                pass
        book_key = self._book_key(self.current_file)
        if not book_key:
            return
        s_off = self._char_offset(s_idx)
        e_off = self._char_offset(e_idx)
        try:
            self._db_exec(
                "DELETE FROM highlights WHERE book = ? "
                "AND NOT (end_offset <= ? OR start_offset >= ?)",
                (book_key, s_off, e_off),
            )
        except Exception:
            pass
        self.set_status("Highlight removed.")

    def _render_persisted_highlights(self) -> None:
        """Re-apply all stored highlights for the loaded book."""
        book_key = self._book_key(self.current_file)
        if not book_key:
            return
        try:
            rows = self._db_query(
                "SELECT start_offset, end_offset, color FROM highlights "
                "WHERE book = ?", (book_key,),
            )
        except Exception:
            return
        for s_off, e_off, color in rows:
            tag = self._highlight_tag(color)
            try:
                self.text_area.tag_add(
                    tag,
                    self._tk_index_for_offset(s_off),
                    self._tk_index_for_offset(e_off),
                )
            except tk.TclError:
                continue

    # ---- Reading timer (5 / 10 / 15 / 20 / 25 minute presets) ----------
    def toggle_timer(self) -> None:
        """Start or stop the countdown timer."""
        if self._timer_running:
            self._stop_timer(announce=False)
        else:
            self._start_timer()

    def _start_timer(self, duration_min: int | None = None,
                     phase: str = "work") -> None:
        """Start the Pomodoro timer.

        External callers (the topbar Start button and the Matrix's block
        "▶ Start" button) always invoke this with phase='work' (the
        default). The cycle then auto-transitions through 'short_break'
        and 'long_break' phases by calling this method recursively from
        `_timer_done` — those phases are not meant to be triggered by
        the user directly.

        If `duration_min` is omitted, the duration is chosen from the
        preset dropdown (for work) or the POMO_*_BREAK_MIN constants
        (for breaks)."""
        if duration_min is None:
            if phase == "work":
                preset = self.timer_preset_var.get()
                duration_min = self._timer_presets.get(preset, 10)
            elif phase == "short_break":
                duration_min = POMO_SHORT_BREAK_MIN
            elif phase == "long_break":
                duration_min = POMO_LONG_BREAK_MIN
            else:
                duration_min = 10
        # Starting a work phase captures that duration so subsequent
        # work phases in the same cycle use the same length.
        if phase == "work":
            self._pomo_work_duration_min = int(duration_min)
        self._pomo_phase = phase
        # Cancel any leftover pending tick from a previous phase so the
        # new countdown starts from a clean state.
        if self._timer_after_id is not None:
            try:
                self.root.after_cancel(self._timer_after_id)
            except Exception:
                pass
            self._timer_after_id = None
        self._timer_remaining_seconds = int(duration_min) * 60
        self._timer_running = True
        if self.timer_button is not None:
            self.timer_button.configure(text="Stop", bg=ACCENT_RED,
                                         activebackground=ACCENT_RED)
        self._update_timer_display()
        self._tick_timer()
        _vlog(
            f"pomo: start phase={phase!r} duration_min={duration_min} "
            f"cycles_done={self._pomo_work_cycles_done}"
        )
        label = self._pomo_phase_label()
        self.set_status(
            f"⏱ {label} started — {duration_min} minute"
            f"{'s' if duration_min != 1 else ''}.")
        # Mirror phase + remaining duration into the Do Now panel so the
        # user can see WHICH phase is running (work / break) without
        # having to look at the topbar. Only updates if the panel has
        # been built (it lives on the Matrix tab of the Study window).
        self._pomo_sync_do_now_panel(duration_min)

    def _pomo_phase_label(self) -> str:
        """Human-readable label for the current Pomodoro phase, used
        by the status bar and timer display."""
        if self._pomo_phase == "work":
            n = self._pomo_work_cycles_done + 1
            return f"🔥 Work {n}/{POMO_CYCLES_PER_LONG_BREAK}"
        if self._pomo_phase == "short_break":
            return "☕ Short break"
        if self._pomo_phase == "long_break":
            return "🛋 Long break"
        return ""

    def _pomo_sync_do_now_panel(self, duration_min: int) -> None:
        """Push the current Pomodoro phase + duration into the Do Now
        panel so it stops showing the original block's '25 minutes'
        line when a break is actually running. Silently no-ops if the
        panel hasn't been built yet (Study window not open / Matrix
        tab not visited)."""
        try:
            duration_var = getattr(self, "_do_now_duration_var", None)
            status_var   = getattr(self, "_do_now_status_var", None)
            if duration_var is None or status_var is None:
                return
            label = self._pomo_phase_label()
            if self._pomo_phase == "idle":
                # On Stop we let _refresh_do_now_panel drive the panel
                # back to the block's own duration; nothing to do here.
                return
            duration_var.set(
                f"{duration_min} min  ({label})"
                if label else f"{duration_min} min"
            )
            # Status line shows where we are in the cycle group so
            # the user can glance and see "1/4 work cycles done".
            done = self._pomo_work_cycles_done
            if self._pomo_phase == "work":
                status_var.set(
                    f"Cycle in progress · {done} work block"
                    f"{'s' if done != 1 else ''} done so far")
            else:
                status_var.set(
                    f"Break in progress · {done} work block"
                    f"{'s' if done != 1 else ''} done — next work block resumes after the break")
        except tk.TclError:
            pass

    def _tick_timer(self) -> None:
        if not self._timer_running:
            return
        if self._timer_remaining_seconds <= 0:
            self._timer_done()
            return
        self._timer_remaining_seconds -= 1
        self._update_timer_display()
        self._timer_after_id = self.root.after(1000, self._tick_timer)

    def _update_timer_display(self) -> None:
        secs = max(0, self._timer_remaining_seconds)
        m, s = divmod(secs, 60)
        icon = {"work": "🔥", "short_break": "☕",
                "long_break": "🛋"}.get(self._pomo_phase, "")
        if icon:
            self.timer_display_var.set(f"{icon} {m:02d}:{s:02d}")
        else:
            self.timer_display_var.set(f"{m:02d}:{s:02d}")

    def _stop_timer(self, announce: bool = True) -> None:
        """Cancel the countdown and reset the UI to idle. Also resets
        the Pomodoro cycle counter — stopping is an explicit user
        action that ends the cycle group."""
        self._timer_running = False
        self._pomo_phase = "idle"
        self._pomo_work_cycles_done = 0
        if self._timer_after_id is not None:
            try:
                self.root.after_cancel(self._timer_after_id)
            except Exception:
                pass
            self._timer_after_id = None
        try:
            self.timer_button.configure(text="Start", bg=ACCENT_GREEN,
                                         activebackground=ACCENT_GREEN)
            self.timer_display_var.set("00:00")
        except Exception:
            pass
        # Restore Do Now panel to whatever the active block actually says
        # (cleans up the "Cycle in progress" status the cycle wrote in).
        try:
            self._refresh_blocks_for_selected_day()
        except Exception:
            pass
        if announce:
            self.set_status("⏱ Timer stopped.")

    def _timer_done(self) -> None:
        """Countdown reached zero. Auto-transition to the next phase
        of the Pomodoro cycle (work → short break → … → long break
        after POMO_CYCLES_PER_LONG_BREAK work cycles → repeat). The
        Stop button breaks out of the cycle at any point."""
        self._timer_after_id = None
        finished_phase = self._pomo_phase
        _vlog(
            f"pomo: done phase={finished_phase!r} "
            f"cycles_done={self._pomo_work_cycles_done}"
        )
        # System chime — same one regardless of phase. Cheap audible
        # cue that the timer rolled over.
        try:
            import winsound
            winsound.MessageBeep(winsound.MB_ICONASTERISK)
        except Exception:
            pass

        if finished_phase == "work":
            self._pomo_work_cycles_done += 1
            if self._pomo_work_cycles_done >= POMO_CYCLES_PER_LONG_BREAK:
                self._pomo_work_cycles_done = 0
                self.set_status(
                    f"⏱ 🔥 Work done — long break "
                    f"({POMO_LONG_BREAK_MIN} min) starting now.")
                self._start_timer(phase="long_break")
            else:
                self.set_status(
                    f"⏱ 🔥 Work done — short break "
                    f"({POMO_SHORT_BREAK_MIN} min) starting now.")
                self._start_timer(phase="short_break")
            return

        if finished_phase in ("short_break", "long_break"):
            kind = "Long" if finished_phase == "long_break" else "Short"
            self.set_status(
                f"⏱ {kind} break over — back to work "
                f"({self._pomo_work_duration_min} min).")
            self._start_timer(
                duration_min=self._pomo_work_duration_min, phase="work")
            return

        # finished_phase == "idle" or anything unexpected: fall back to
        # the legacy single-shot behavior (beep + popup, no cycle).
        self._timer_running = False
        self._pomo_phase = "idle"
        try:
            self.timer_button.configure(text="Start", bg=ACCENT_GREEN,
                                         activebackground=ACCENT_GREEN)
            self.timer_display_var.set("00:00")
        except Exception:
            pass
        self.set_status("⏱ Time's up!")
        self.root.after(50, lambda: messagebox.showinfo(
            "⏱ Timer", "Time's up!"))

    # ---- 2. Topics (commonplace book) ----------------------------------
    def add_selection_to_topic(self, source_widget=None) -> None:
        """MOVE the current selection into a topic of the user's
        choice. Source is cleared on success when it's Notes or
        Study Notes. Reader keeps a COPY."""
        widget = source_widget if source_widget is not None else self.text_area
        text, sel_range, used_whole = self._capture_widget_text(widget)
        if not text:
            if widget is self.text_area:
                messagebox.showinfo(
                    "Nothing selected",
                    "Highlight some text first, then choose 📌 Add to topic.")
            else:
                messagebox.showinfo("Nothing to send",
                                     "There's no text in the panel to send.")
            return
        try:
            rows = self._db_query("SELECT id, title FROM topics "
                                  "ORDER BY title COLLATE NOCASE")
        except Exception as e:
            messagebox.showerror("Database error", str(e))
            return
        topic_id = self._pick_or_create_topic_dialog(rows)
        if topic_id is None:
            return
        # Source linkage only makes sense for reader selections — that's
        # what the (book_key, char_offset) anchor refers to.
        if widget is self.text_area and sel_range is not None:
            source_key = self._book_key(self.current_file)
            source_off = (self._char_offset(sel_range[0])
                          if source_key else None)
        else:
            source_key = None
            source_off = None
        try:
            self._db_exec(
                "INSERT INTO topic_entries "
                "(topic_id, text, source_book, source_offset, created_at) "
                "VALUES (?, ?, ?, ?, ?)",
                (topic_id, text, source_key, source_off,
                 datetime.now().isoformat()),
            )
        except Exception as e:
            messagebox.showerror("Could not save topic entry", str(e))
            return
        self._clear_moved_source(widget, sel_range, used_whole)
        self.set_status("📌 Moved to topic.")

    def _pick_or_create_topic_dialog(self, topics: list[tuple]) -> int | None:
        """Modal: pick an existing topic or type a new name. Returns the
        topic id, or None on cancel."""
        dlg = tk.Toplevel(self.root)
        dlg.title("Add to topic")
        dlg.configure(bg=BG_DARK)
        dlg.transient(self.root)
        dlg.grab_set()
        dlg.geometry("420x440")

        tk.Label(dlg, text="Pick an existing topic, or type a new one:",
                 bg=BG_DARK, fg=FG_TEXT, font=("Segoe UI", 11, "bold"),
                 padx=14, pady=10).pack(anchor=tk.W)

        listbox = tk.Listbox(
            dlg, bg=BG_INPUT, fg=FG_TEXT,
            selectbackground=ACCENT_CYAN, selectforeground="white",
            font=("Segoe UI", 11), relief=tk.FLAT, bd=0, highlightthickness=0,
            activestyle="none",
        )
        listbox.pack(fill=tk.BOTH, expand=True, padx=14, pady=(0, 8))
        ids = [t[0] for t in topics]
        for _id, title in topics:
            listbox.insert(tk.END, title)

        tk.Label(dlg, text="Or new topic:", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 10), padx=14).pack(anchor=tk.W)
        entry_var = tk.StringVar()
        entry = tk.Entry(dlg, textvariable=entry_var,
                         bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                         font=("Segoe UI", 11), relief=tk.FLAT, bd=0)
        entry.pack(fill=tk.X, padx=14, ipady=5, pady=(2, 10))

        out = {"id": None}

        def commit() -> None:
            new_name = entry_var.get().strip()
            if new_name:
                try:
                    tid = self._db_exec(
                        "INSERT INTO topics (title, created_at) VALUES (?, ?)",
                        (new_name, datetime.now().isoformat()),
                    )
                    out["id"] = tid
                except sqlite3.IntegrityError:
                    rows = self._db_query(
                        "SELECT id FROM topics WHERE title = ? COLLATE NOCASE",
                        (new_name,))
                    if rows:
                        out["id"] = rows[0][0]
                except Exception as e:
                    messagebox.showerror("Could not create topic",
                                          str(e), parent=dlg)
                    return
            else:
                sel = listbox.curselection()
                if not sel:
                    messagebox.showinfo(
                        "Pick or type a topic",
                        "Click an existing topic, or type a new name.",
                        parent=dlg,
                    )
                    return
                out["id"] = ids[sel[0]]
            dlg.destroy()

        btn_row = tk.Frame(dlg, bg=BG_DARK, padx=14, pady=10)
        btn_row.pack(fill=tk.X)
        tk.Button(btn_row, text="Add", command=commit,
                  font=("Segoe UI", 11, "bold"), bg=ACCENT_GREEN, fg="white",
                  activebackground=ACCENT_GREEN, relief=tk.FLAT,
                  padx=14, pady=6, cursor="hand2", borderwidth=0,
                  ).pack(side=tk.RIGHT, padx=(6, 0))
        tk.Button(btn_row, text="Cancel", command=dlg.destroy,
                  font=("Segoe UI", 11, "bold"), bg=ACCENT_SLATE, fg="white",
                  activebackground=ACCENT_SLATE, relief=tk.FLAT,
                  padx=14, pady=6, cursor="hand2", borderwidth=0,
                  ).pack(side=tk.RIGHT)

        entry.bind("<Return>", lambda _e: commit())
        listbox.bind("<Double-Button-1>", lambda _e: commit())
        listbox.focus_set()
        dlg.wait_window()
        return out["id"]

    # ---- 3. Bookmarks --------------------------------------------------
    def bookmark_here(self) -> None:
        """Save the current position with an auto-generated context label."""
        book_key = self._book_key(self.current_file)
        if not book_key:
            messagebox.showinfo(
                "Cannot bookmark",
                "Bookmarks need a saved book. Open one from 📂 Open or "
                "📚 Library first.",
            )
            return
        try:
            cursor_idx = self.text_area.index(tk.INSERT)
            top_idx    = self.text_area.index("@0,0")
            cursor_off = self._char_offset(cursor_idx)
            top_off    = self._char_offset(top_idx)
            visible_end = self._char_offset(self.text_area.index(
                f"@0,{self.text_area.winfo_height()}"))
            position = cursor_off if top_off <= cursor_off <= visible_end else top_off
        except tk.TclError:
            position = 0
        try:
            snippet_idx = self._tk_index_for_offset(position)
            snippet = self.text_area.get(snippet_idx, f"{snippet_idx} + 80 chars")
            snippet = " ".join(snippet.split())[:60]
        except tk.TclError:
            snippet = ""
        label = snippet or f"Position {position}"
        try:
            self._db_exec(
                "INSERT INTO bookmarks (book, position, label, created_at) "
                "VALUES (?, ?, ?, ?)",
                (book_key, position, label, datetime.now().isoformat()),
            )
            display = label[:40] + ("…" if len(label) > 40 else "")
            self.set_status(f"🔖 Bookmarked: {display}")
        except Exception as e:
            messagebox.showerror("Bookmark failed", str(e))

    def _jump_to_book_offset(self, book_key: str, position: int) -> None:
        """Open the book (if not already loaded) and scroll to position."""
        path = self._book_path_for_key(book_key)
        if not path or not os.path.exists(path):
            messagebox.showerror(
                "Book file missing",
                f"This pointer references a book that's no longer on disk:\n\n{path}",
            )
            return
        if self._book_key(self.current_file) != book_key:
            self._load_book(path)
        try:
            idx = self._tk_index_for_offset(position)
            self.text_area.mark_set(tk.INSERT, idx)
            self.text_area.see(idx)
            self.text_area.focus_set()
        except tk.TclError:
            pass

    # ---- 4a. Glossary --------------------------------------------------
    def lookup_selected_in_glossary(self, source_widget=None) -> None:
        """Look up the selected word/phrase; offer to define it if not
        present. `source_widget` defaults to the reader."""
        widget = source_widget if source_widget is not None else self.text_area
        try:
            term = widget.get(tk.SEL_FIRST, tk.SEL_LAST).strip()
        except tk.TclError:
            term = ""
        if not term:
            entered = self._prompt_for_text("Look up term", "Enter a term:")
            if not entered:
                return
            term = entered.strip()
            if not term:
                return
        rows = self._db_query(
            "SELECT term, definition, source FROM glossary "
            "WHERE term = ? COLLATE NOCASE", (term,),
        )
        if rows:
            t, d, src = rows[0]
            self._show_glossary_entry(t, d, src or "")
        else:
            if messagebox.askyesno(
                "Not in glossary",
                f"'{term}' isn't in your glossary yet.\n\nDefine it now?",
            ):
                self._edit_glossary_entry(
                    term=term, definition="",
                    source=self._book_key(self.current_file) or "",
                )

    def _prompt_for_text(self, title: str, prompt: str) -> str | None:
        """Tiny themed text-input dialog. Returns text or None on cancel."""
        dlg = tk.Toplevel(self.root)
        dlg.title(title)
        dlg.configure(bg=BG_DARK)
        dlg.transient(self.root)
        dlg.grab_set()
        dlg.geometry("400x150")
        tk.Label(dlg, text=prompt, bg=BG_DARK, fg=FG_TEXT,
                 font=("Segoe UI", 11), padx=14, pady=14).pack(anchor=tk.W)
        var = tk.StringVar()
        e = tk.Entry(dlg, textvariable=var, bg=BG_INPUT, fg=FG_TEXT,
                     insertbackground=FG_TEXT, font=("Segoe UI", 11),
                     relief=tk.FLAT, bd=0)
        e.pack(fill=tk.X, padx=14, ipady=5)
        e.focus_set()
        out = {"v": None}
        def ok():
            out["v"] = var.get(); dlg.destroy()
        row = tk.Frame(dlg, bg=BG_DARK, padx=14, pady=12)
        row.pack(fill=tk.X)
        tk.Button(row, text="OK", command=ok, font=("Segoe UI", 11, "bold"),
                  bg=ACCENT_GREEN, fg="white", activebackground=ACCENT_GREEN,
                  relief=tk.FLAT, padx=14, pady=6, cursor="hand2", borderwidth=0,
                  ).pack(side=tk.RIGHT, padx=(6, 0))
        tk.Button(row, text="Cancel", command=dlg.destroy,
                  font=("Segoe UI", 11, "bold"), bg=ACCENT_SLATE, fg="white",
                  activebackground=ACCENT_SLATE, relief=tk.FLAT,
                  padx=14, pady=6, cursor="hand2", borderwidth=0,
                  ).pack(side=tk.RIGHT)
        e.bind("<Return>", lambda _e: ok())
        dlg.wait_window()
        return out["v"]

    def _show_glossary_entry(self, term: str, definition: str, source: str) -> None:
        """Read-only popup showing a single glossary entry."""
        dlg = tk.Toplevel(self.root)
        dlg.title(f"📒 {term}")
        dlg.configure(bg=BG_DARK)
        dlg.transient(self.root)
        dlg.geometry("520x380")
        tk.Label(dlg, text=term, bg=BG_DARK, fg=FG_TEXT,
                 font=("Segoe UI", 16, "bold"), padx=16, pady=12,
                 anchor=tk.W).pack(fill=tk.X)
        body = scrolledtext.ScrolledText(
            dlg, wrap=tk.WORD, font=("Segoe UI", 12),
            bg=BG_INPUT, fg=FG_TEXT, padx=14, pady=12, relief=tk.FLAT,
        )
        body.pack(fill=tk.BOTH, expand=True, padx=14, pady=4)
        body.insert("1.0", definition)
        body.configure(state=tk.DISABLED)
        if source:
            src_label = (self._book_short_label(source)
                         if source.startswith(("lib:", "abs:")) else source)
            tk.Label(dlg, text=f"Source: {src_label}",
                     bg=BG_DARK, fg=FG_MUTED, font=("Segoe UI", 10),
                     padx=14).pack(anchor=tk.W)
        row = tk.Frame(dlg, bg=BG_DARK, padx=14, pady=10)
        row.pack(fill=tk.X)
        tk.Button(row, text="Edit",
                  command=lambda: (dlg.destroy(),
                                   self._edit_glossary_entry(
                                       term=term, definition=definition,
                                       source=source)),
                  font=("Segoe UI", 11, "bold"), bg=ACCENT_CYAN, fg="white",
                  activebackground=ACCENT_CYAN, relief=tk.FLAT, padx=14, pady=6,
                  cursor="hand2", borderwidth=0,
                  ).pack(side=tk.LEFT)
        tk.Button(row, text="Close", command=dlg.destroy,
                  font=("Segoe UI", 11, "bold"), bg=ACCENT_SLATE, fg="white",
                  activebackground=ACCENT_SLATE, relief=tk.FLAT,
                  padx=14, pady=6, cursor="hand2", borderwidth=0,
                  ).pack(side=tk.RIGHT)

    def _edit_glossary_entry(self, term: str = "", definition: str = "",
                              source: str = "",
                              existing_id: int | None = None) -> None:
        """Add or edit a glossary entry."""
        dlg = tk.Toplevel(self.root)
        dlg.title("📒 Glossary entry")
        dlg.configure(bg=BG_DARK)
        dlg.transient(self.root)
        dlg.grab_set()
        dlg.geometry("560x460")

        tk.Label(dlg, text="Term:", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 10), padx=14, pady=(12, 2)).pack(anchor=tk.W)
        term_var = tk.StringVar(value=term)
        term_e = tk.Entry(dlg, textvariable=term_var,
                          bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                          font=("Segoe UI", 12, "bold"), relief=tk.FLAT, bd=0)
        term_e.pack(fill=tk.X, padx=14, ipady=5)

        tk.Label(dlg, text="Definition:", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 10), padx=14, pady=(10, 2)).pack(anchor=tk.W)
        body = scrolledtext.ScrolledText(
            dlg, wrap=tk.WORD, font=("Segoe UI", 11),
            bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
            padx=12, pady=10, relief=tk.FLAT, undo=True,
        )
        body.pack(fill=tk.BOTH, expand=True, padx=14, pady=4)
        if definition:
            body.insert("1.0", definition)

        def save():
            t = term_var.get().strip()
            d = body.get("1.0", tk.END).strip()
            if not t:
                messagebox.showinfo("Term required",
                                     "Enter a term first.", parent=dlg)
                return
            if not d:
                messagebox.showinfo("Definition required",
                                     "Enter a definition.", parent=dlg)
                return
            now = datetime.now().isoformat()
            try:
                if existing_id is not None:
                    self._db_exec(
                        "UPDATE glossary SET term=?, definition=?, source=?, "
                        "updated_at=? WHERE id=?",
                        (t, d, source, now, existing_id),
                    )
                else:
                    rows = self._db_query(
                        "SELECT id FROM glossary WHERE term=? COLLATE NOCASE",
                        (t,))
                    if rows:
                        self._db_exec(
                            "UPDATE glossary SET definition=?, source=?, "
                            "updated_at=? WHERE id=?",
                            (d, source, now, rows[0][0]),
                        )
                    else:
                        self._db_exec(
                            "INSERT INTO glossary "
                            "(term, definition, source, created_at, updated_at) "
                            "VALUES (?, ?, ?, ?, ?)",
                            (t, d, source, now, now),
                        )
            except Exception as e:
                messagebox.showerror("Could not save", str(e), parent=dlg)
                return
            self.set_status(f"📒 Saved glossary entry: {t}")
            try:
                self._refresh_tab_glossary()
            except Exception:
                pass
            dlg.destroy()

        row = tk.Frame(dlg, bg=BG_DARK, padx=14, pady=10)
        row.pack(fill=tk.X)
        tk.Button(row, text="Save", command=save,
                  font=("Segoe UI", 11, "bold"), bg=ACCENT_GREEN, fg="white",
                  activebackground=ACCENT_GREEN, relief=tk.FLAT,
                  padx=14, pady=6, cursor="hand2", borderwidth=0,
                  ).pack(side=tk.RIGHT, padx=(6, 0))
        tk.Button(row, text="Cancel", command=dlg.destroy,
                  font=("Segoe UI", 11, "bold"), bg=ACCENT_SLATE, fg="white",
                  activebackground=ACCENT_SLATE, relief=tk.FLAT,
                  padx=14, pady=6, cursor="hand2", borderwidth=0,
                  ).pack(side=tk.RIGHT)

        (body if term else term_e).focus_set()

    # ---- 4b. Journal helpers (used by the workspace tab) ----------------
    # The Journal tab is fully built/refreshed inside the workspace; no
    # reader-side trigger method needed here.

    # ---- Study workspace (tabbed window) -------------------------------
    def open_study_workspace(self) -> None:
        """Open (or focus) the Study workspace. Acts as 'restore' too —
        if the window is iconified, this brings it back."""
        if self._study_win is not None:
            try:
                if self._study_win.winfo_exists():
                    # `deiconify` un-minimizes; `lift` + `focus_force`
                    # raise it above other windows.
                    try:
                        self._study_win.deiconify()
                    except Exception:
                        pass
                    self._study_win.lift()
                    self._study_win.focus_force()
                    return
            except Exception:
                pass
            self._study_win = None

        win = tk.Toplevel(self.root)
        self._study_win = win
        win.title("📓 Study workspace")
        # Fit the window to the screen and centre it, so the bottom button
        # rows (Delete / Clear / Save, etc.) never fall off the bottom edge.
        try:
            sw = win.winfo_screenwidth()
            sh = win.winfo_screenheight()
        except tk.TclError:
            sw, sh = 1280, 800
        w = min(1200, max(700, sw - 60))
        h = min(820, max(440, sh - 96))    # leave room for the taskbar
        x = max(0, (sw - w) // 2)
        y = max(0, (sh - h) // 2 - 30)
        win.geometry(f"{w}x{h}+{x}+{y}")
        win.minsize(560, 380)
        win.configure(bg=BG_DARK)
        # NOTE: do NOT call # win.transient(self.root)  # disabled: hides Min/Max buttons on Windows here. A transient
        # window on Windows doesn't get its own taskbar entry, so once
        # it's iconified there's no way for the user to restore it from
        # the taskbar. The Study window is rich enough to deserve a
        # proper top-level identity — separate taskbar button, normal
        # Alt+Tab participation, independent minimize/restore.

        def on_close():
            # The Study window is PERSISTENT: it hosts the reader, so we
            # never destroy it (that would tear down text_area / notes_area and
            # the ~150 references to them). Force-save any open editors, then
            # HIDE the window. Reopening just shows it again with all state.
            try:
                if self._eisenhower_widgets:
                    self._save_all_eisenhower()
            except Exception:
                pass
            try:
                if self._study_notes_widget is not None:
                    self._save_study_notes()
            except Exception:
                pass
            try:
                if (self._journal_current_id is not None and
                        hasattr(self, "_journal_body")):
                    self._save_current_journal_entry()
            except Exception:
                pass
            try:
                self._save_notes()      # the reader's quick Notes panel
            except Exception:
                pass
            try:
                win.withdraw()          # hide, don't destroy
            except Exception:
                pass
        win.protocol("WM_DELETE_WINDOW", on_close)

        tabbar = tk.Frame(win, bg=BG_PANEL, padx=10, pady=8)
        tabbar.pack(fill=tk.X)
        content = tk.Frame(win, bg=BG_DARK)
        content.pack(fill=tk.BOTH, expand=True, padx=10, pady=8)

        self._study_tab_frames = {}
        self._study_tab_buttons = {}

        tabs = [
            ("reader",      "📖 Reader",      self._build_tab_reader),
            ("study_notes", "📝 Study Notes", self._build_tab_study_notes),
            ("topics",      "📌 Topics",      self._build_tab_topics),
            ("glossary",    "📒 Glossary",    self._build_tab_glossary),
            ("commentary",  "📑 Commentary",  self._build_tab_commentary),
            ("journal",     "📅 Journal",     self._build_tab_journal),
            ("matrix",      "🎯 Matrix",      self._build_tab_eisenhower),
            ("planner",     "🗓 Planner",     self._build_tab_planner),
        ]
        for key, label, builder in tabs:
            b = tk.Button(
                tabbar, text=label,
                command=lambda k=key: self._show_study_tab(k),
                font=("Segoe UI", 9, "bold"),
                bg=BG_INPUT, fg=FG_TEXT,
                activebackground=ACCENT_SLATE, activeforeground="white",
                relief=tk.FLAT, padx=6, pady=5, cursor="hand2", borderwidth=0,
            )
            b.pack(side=tk.LEFT, padx=(0, 2))
            self._study_tab_buttons[key] = b
            f = tk.Frame(content, bg=BG_DARK)
            self._study_tab_frames[key] = f
            # Built once at startup (window is persistent). Guard each builder
            # so one failing tab can never stop the app from starting.
            try:
                builder(f)
            except Exception as e:
                print(f"[study] build tab {key}: {e}", file=sys.stderr)

        # Open + Library — packed right after the last tab (Matrix), at the
        # exact same compact size as the tab buttons so the row is uniform.
        tk.Button(tabbar, text="📂 Open", command=self.open_file,
                  font=("Segoe UI", 9, "bold"), bg=ACCENT_CYAN, fg="white",
                  activebackground=ACCENT_CYAN, relief=tk.FLAT, padx=6, pady=5,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT, padx=(0, 2))
        tk.Button(tabbar, text="📚 Library", command=self.open_library,
                  font=("Segoe UI", 9, "bold"), bg=ACCENT_PURPLE, fg="white",
                  activebackground=ACCENT_PURPLE, relief=tk.FLAT, padx=6, pady=5,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT, padx=(0, 2))
        # Prompts library — moved here from the top action bar so it lives
        # with the rest of the Study tools, at the same compact button size.
        tk.Button(tabbar, text="🗒 Prompts", command=self.open_prompt_library,
                  font=("Segoe UI", 9, "bold"), bg=ACCENT_GREEN, fg="white",
                  activebackground=ACCENT_GREEN, relief=tk.FLAT, padx=6, pady=5,
                  cursor="hand2", borderwidth=0).pack(side=tk.LEFT, padx=(0, 2))

        # Minimize button — sends the Study window to the taskbar.
        # (Expand/Restore removed; use the window's own title-bar controls.)
        min_btn = tk.Button(
            tabbar, text="—  Minimize",
            command=lambda: win.iconify(),
            font=("Segoe UI", 9, "bold"),
            bg=ACCENT_SLATE, fg="white", activebackground=ACCENT_SLATE,
            relief=tk.FLAT, padx=8, pady=5, cursor="hand2", borderwidth=0,
        )
        min_btn.pack(side=tk.RIGHT, padx=(4, 0))

        self._show_study_tab("reader")

    # ---- Audit tab ------------------------------------------------------
    # Matches the rubric structure shared by the Walkenbach Excel audits
    # in the A1 Form & System course (Parts XIX–XX, every Course-Week tab)
    # and the Sentinel Prime field_schema audit pattern. Five columns:
    # #  |  Finding  |  Where  |  Grade  |  Recommended fix
    # Plus an overall grade and a closing "Mentor's Note" — the warm,
    # italic register the A1 workbook closes every Part with.
    def _build_tab_audit(self, parent: tk.Frame) -> None:
        # Two-pane: left = audit list, right = selected audit detail.
        wrap = tk.Frame(parent, bg=BG_DARK)
        wrap.pack(fill=tk.BOTH, expand=True)

        # --- Left: audit list -----------------------------------------
        left = tk.Frame(wrap, bg=BG_DARK, padx=8, pady=8)
        left.pack(side=tk.LEFT, fill=tk.Y)
        tk.Label(left, text="Audits", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 10, "bold")).pack(anchor=tk.W)
        list_box = tk.Listbox(
            left, width=28, height=18,
            bg=BG_INPUT, fg=FG_TEXT,
            selectbackground=ACCENT_CYAN, selectforeground="white",
            font=("Segoe UI", 10), activestyle="none",
            relief=tk.FLAT, bd=0, highlightthickness=0,
        )
        list_box.pack(fill=tk.Y, expand=True, pady=(4, 6))
        list_box.bind("<<ListboxSelect>>", lambda _e: self._audit_on_list_select())
        self._audit_listbox = list_box
        list_btns = tk.Frame(left, bg=BG_DARK)
        list_btns.pack(fill=tk.X)
        def lb(text: str, cmd, color: str) -> tk.Button:
            return tk.Button(
                list_btns, text=text, command=cmd,
                font=("Segoe UI", 9, "bold"),
                bg=color, fg="white", activebackground=color,
                relief=tk.FLAT, padx=8, pady=4, cursor="hand2", borderwidth=0,
            )
        lb("+ New",   self._audit_new,             ACCENT_GREEN
           ).pack(side=tk.LEFT, padx=(0, 4))
        lb("Delete", self._audit_delete_current,   ACCENT_RED
           ).pack(side=tk.LEFT, padx=4)
        lb("Refresh", self._refresh_tab_audit,     ACCENT_SLATE
           ).pack(side=tk.LEFT, padx=4)

        # --- Right: audit detail --------------------------------------
        right = tk.Frame(wrap, bg=BG_DARK, padx=12, pady=8)
        right.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        # Title + Subject
        tk.Label(right, text="Title", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 9, "bold")).pack(anchor=tk.W)
        self._audit_title_var = tk.StringVar()
        tk.Entry(right, textvariable=self._audit_title_var,
                 bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                 font=("Segoe UI", 12, "bold"),
                 relief=tk.FLAT, bd=0
                 ).pack(fill=tk.X, ipady=6, pady=(2, 8))
        self._audit_title_var.trace_add("write",
                                         lambda *_: self._audit_schedule_save())

        tk.Label(right, text="Subject (book, chapter, note, project…)",
                 bg=BG_DARK, fg=FG_MUTED, font=("Segoe UI", 9)
                 ).pack(anchor=tk.W)
        self._audit_subject_var = tk.StringVar()
        tk.Entry(right, textvariable=self._audit_subject_var,
                 bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                 font=("Segoe UI", 10),
                 relief=tk.FLAT, bd=0
                 ).pack(fill=tk.X, ipady=4, pady=(2, 12))
        self._audit_subject_var.trace_add("write",
                                          lambda *_: self._audit_schedule_save())

        # Findings header
        head = tk.Frame(right, bg=BG_PANEL, padx=6, pady=4)
        head.pack(fill=tk.X)
        cols = [("#", 3), ("Finding", 28), ("Where", 14),
                ("Grade", 6), ("Recommended fix", 28), ("", 3)]
        for label, w in cols:
            tk.Label(head, text=label, bg=BG_PANEL, fg=FG_TEXT,
                     font=("Segoe UI", 9, "bold"), width=w, anchor=tk.W
                     ).pack(side=tk.LEFT, padx=2)

        # Scrollable findings container
        findings_scroll_holder = tk.Frame(right, bg=BG_DARK)
        findings_scroll_holder.pack(fill=tk.BOTH, expand=True, pady=(4, 8))
        canvas = tk.Canvas(findings_scroll_holder, bg=BG_DARK,
                            highlightthickness=0, borderwidth=0)
        fsb = tk.Scrollbar(findings_scroll_holder, command=canvas.yview)
        canvas.configure(yscrollcommand=fsb.set)
        fsb.pack(side=tk.RIGHT, fill=tk.Y)
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        inner = tk.Frame(canvas, bg=BG_DARK)
        inner_id = canvas.create_window((0, 0), window=inner, anchor="nw")
        def _on_inner_config(_e=None):
            canvas.configure(scrollregion=canvas.bbox("all"))
            canvas.itemconfigure(inner_id, width=canvas.winfo_width())
        inner.bind("<Configure>", _on_inner_config)
        canvas.bind("<Configure>", _on_inner_config)
        self._audit_findings_frame = inner

        # Action row + summary
        action_row = tk.Frame(right, bg=BG_DARK)
        action_row.pack(fill=tk.X)
        tk.Button(action_row, text="+ Add Finding",
                  command=self._audit_add_finding,
                  bg=ACCENT_CYAN, fg="white",
                  font=("Segoe UI", 10, "bold"),
                  relief=tk.FLAT, padx=10, pady=5,
                  cursor="hand2", borderwidth=0
                  ).pack(side=tk.LEFT)
        tk.Label(action_row, text="    Overall grade:",
                 bg=BG_DARK, fg=FG_MUTED, font=("Segoe UI", 10)
                 ).pack(side=tk.LEFT)
        self._audit_overall_var = tk.StringVar(value="")
        overall_menu = ttk.Combobox(action_row,
                                     textvariable=self._audit_overall_var,
                                     values=list(AUDIT_GRADES),
                                     width=5, state="readonly")
        overall_menu.pack(side=tk.LEFT, padx=4)
        self._audit_overall_var.trace_add("write",
                                          lambda *_: self._audit_schedule_save())

        # Mentor's Note (warm, italic register from the A1 workbook style)
        tk.Label(right, text="Mentor's Note (closing summary, plain language)",
                 bg=BG_DARK, fg=FG_MUTED, font=("Segoe UI", 9)
                 ).pack(anchor=tk.W, pady=(10, 2))
        note = tk.Text(right, height=4,
                       bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                       font=("Segoe UI", 10, "italic"),
                       relief=tk.FLAT, bd=0, wrap=tk.WORD)
        note.pack(fill=tk.X)
        self._audit_mentors_widget = note
        note.bind("<<Modified>>", self._audit_on_note_modified)

        self._refresh_tab_audit()

    # --- list / refresh ----------------------------------------------
    def _refresh_tab_audit(self) -> None:
        if self._audit_listbox is None:
            return
        try:
            rows = self._db_query(
                "SELECT id, title, updated_at FROM audits "
                "ORDER BY updated_at DESC"
            )
        except sqlite3.Error:
            rows = []
        self._audit_items = [(r[0], r[1] or "(untitled)") for r in rows]
        lb = self._audit_listbox
        lb.delete(0, tk.END)
        for _id, title in self._audit_items:
            lb.insert(tk.END, title[:30])
        # Restore selection if the current audit still exists; otherwise
        # clear the detail pane.
        if self._audit_current_id is not None:
            for i, (aid, _t) in enumerate(self._audit_items):
                if aid == self._audit_current_id:
                    lb.selection_clear(0, tk.END)
                    lb.selection_set(i)
                    lb.see(i)
                    return
        self._audit_current_id = None
        self._audit_clear_detail()

    def _audit_on_list_select(self) -> None:
        if self._audit_listbox is None:
            return
        sel = self._audit_listbox.curselection()
        if not sel:
            return
        idx = sel[0]
        if idx >= len(self._audit_items):
            return
        self._audit_load(self._audit_items[idx][0])

    # --- CRUD --------------------------------------------------------
    def _audit_new(self) -> None:
        now = datetime.now().isoformat(timespec="seconds")
        try:
            new_id = self._db_exec(
                "INSERT INTO audits "
                "(title, subject, overall_grade, mentors_note, "
                "findings_json, created_at, updated_at) "
                "VALUES (?, ?, ?, ?, ?, ?, ?)",
                ("New audit", "", "", "", "[]", now, now),
            )
        except sqlite3.Error as e:
            messagebox.showerror("Audit error", str(e))
            return
        self._audit_current_id = new_id
        self._refresh_tab_audit()
        self._audit_load(new_id)
        if self._audit_title_var is not None:
            try:
                # Pre-select the placeholder title so the user can just
                # start typing.
                pass
            except tk.TclError:
                pass

    def _audit_delete_current(self) -> None:
        if self._audit_current_id is None:
            messagebox.showinfo("Nothing selected",
                                "Pick an audit on the left first.")
            return
        title = next((t for i, t in self._audit_items
                      if i == self._audit_current_id), "this audit")
        if not messagebox.askyesno("Delete audit?",
                                    f"Permanently delete \"{title}\"?"):
            return
        try:
            self._db_exec("DELETE FROM audits WHERE id=?",
                          (self._audit_current_id,))
        except sqlite3.Error as e:
            messagebox.showerror("Delete failed", str(e))
            return
        self._audit_current_id = None
        self._refresh_tab_audit()

    def _audit_load(self, audit_id: int) -> None:
        try:
            rows = self._db_query(
                "SELECT title, subject, overall_grade, mentors_note, "
                "findings_json FROM audits WHERE id=?",
                (audit_id,),
            )
        except sqlite3.Error:
            rows = []
        if not rows:
            return
        title, subject, overall, mentors, findings_json = rows[0]
        # Pause autosave while we re-hydrate the widgets to avoid a
        # spurious write triggered by the StringVar updates below.
        prev = self._audit_save_after_id
        self._audit_save_after_id = "__loading__"
        self._audit_current_id = audit_id
        if self._audit_title_var is not None:
            self._audit_title_var.set(title or "")
        if self._audit_subject_var is not None:
            self._audit_subject_var.set(subject or "")
        if self._audit_overall_var is not None:
            self._audit_overall_var.set(overall or "")
        if self._audit_mentors_widget is not None:
            self._audit_mentors_widget.delete("1.0", tk.END)
            if mentors:
                self._audit_mentors_widget.insert("1.0", mentors)
            self._audit_mentors_widget.edit_modified(False)
        try:
            findings = json.loads(findings_json or "[]")
            if not isinstance(findings, list):
                findings = []
        except json.JSONDecodeError:
            findings = []
        self._audit_render_findings(findings)
        # Resume normal autosave behavior
        self._audit_save_after_id = (
            None if prev == "__loading__" else prev
        )

    def _audit_clear_detail(self) -> None:
        if self._audit_title_var is not None:
            self._audit_title_var.set("")
        if self._audit_subject_var is not None:
            self._audit_subject_var.set("")
        if self._audit_overall_var is not None:
            self._audit_overall_var.set("")
        if self._audit_mentors_widget is not None:
            try:
                self._audit_mentors_widget.delete("1.0", tk.END)
                self._audit_mentors_widget.edit_modified(False)
            except tk.TclError:
                pass
        self._audit_render_findings([])

    # --- findings rendering -------------------------------------------
    def _audit_render_findings(self, findings: list[dict]) -> None:
        """Rebuild the findings rows from a list of dicts. Each row is a
        small frame with four widgets (finding entry, location entry,
        grade combobox, fix entry) + a delete button. We rebuild rather
        than patch — the list is short, the cost is negligible."""
        frame = self._audit_findings_frame
        if frame is None:
            return
        for child in frame.winfo_children():
            child.destroy()
        self._audit_finding_widgets = []
        for i, item in enumerate(findings):
            self._audit_make_finding_row(i, item)

    def _audit_make_finding_row(self, position: int,
                                 data: dict | None = None) -> None:
        if self._audit_findings_frame is None:
            return
        data = data or {}
        row = tk.Frame(self._audit_findings_frame, bg=BG_DARK)
        row.pack(fill=tk.X, pady=1)

        tk.Label(row, text=str(position + 1),
                 bg=BG_DARK, fg=FG_MUTED, font=("Segoe UI", 10),
                 width=3, anchor=tk.W
                 ).pack(side=tk.LEFT, padx=2)

        f_var = tk.StringVar(value=data.get("finding", ""))
        l_var = tk.StringVar(value=data.get("location", ""))
        g_var = tk.StringVar(value=data.get("grade", ""))
        x_var = tk.StringVar(value=data.get("fix", ""))

        def _on_change(*_a):
            self._audit_schedule_save()

        for var in (f_var, l_var, g_var, x_var):
            var.trace_add("write", _on_change)

        tk.Entry(row, textvariable=f_var,
                 bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                 font=("Segoe UI", 10),
                 relief=tk.FLAT, bd=0, width=28
                 ).pack(side=tk.LEFT, padx=2, ipady=2)
        tk.Entry(row, textvariable=l_var,
                 bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                 font=("Segoe UI", 10),
                 relief=tk.FLAT, bd=0, width=14
                 ).pack(side=tk.LEFT, padx=2, ipady=2)
        ttk.Combobox(row, textvariable=g_var,
                      values=list(AUDIT_GRADES),
                      width=5, state="readonly"
                      ).pack(side=tk.LEFT, padx=2)
        tk.Entry(row, textvariable=x_var,
                 bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                 font=("Segoe UI", 10),
                 relief=tk.FLAT, bd=0, width=28
                 ).pack(side=tk.LEFT, padx=2, ipady=2)

        widget_ref = {
            "row": row,
            "finding_var":  f_var,
            "location_var": l_var,
            "grade_var":    g_var,
            "fix_var":      x_var,
        }

        def _remove():
            try:
                row.destroy()
            except tk.TclError:
                pass
            if widget_ref in self._audit_finding_widgets:
                self._audit_finding_widgets.remove(widget_ref)
            # Re-number the remaining rows so the # column stays sensible.
            self._audit_renumber_findings()
            self._audit_schedule_save()

        tk.Button(row, text="🗑",
                  command=_remove,
                  bg=ACCENT_SLATE, fg="white",
                  font=("Segoe UI", 9, "bold"),
                  relief=tk.FLAT, padx=4, pady=2,
                  cursor="hand2", borderwidth=0
                  ).pack(side=tk.LEFT, padx=2)

        self._audit_finding_widgets.append(widget_ref)

    def _audit_renumber_findings(self) -> None:
        """Walk the existing rows and update the # label on each one."""
        for i, w in enumerate(self._audit_finding_widgets):
            row = w["row"]
            try:
                # First child of the row is the number label
                children = row.winfo_children()
                if children:
                    children[0].configure(text=str(i + 1))
            except tk.TclError:
                pass

    def _audit_add_finding(self) -> None:
        if self._audit_current_id is None:
            self._audit_new()
            return
        self._audit_make_finding_row(len(self._audit_finding_widgets), {})
        self._audit_schedule_save()

    # --- autosave -----------------------------------------------------
    def _audit_on_note_modified(self, _event=None) -> None:
        w = self._audit_mentors_widget
        if w is None:
            return
        try:
            if not w.edit_modified():
                return
            w.edit_modified(False)
        except tk.TclError:
            return
        self._audit_schedule_save()

    def _audit_schedule_save(self) -> None:
        if self._audit_save_after_id == "__loading__":
            return  # don't autosave during _audit_load re-hydration
        if self._audit_current_id is None:
            return
        if self._audit_save_after_id:
            try:
                self.root.after_cancel(self._audit_save_after_id)
            except (tk.TclError, ValueError):
                pass
        self._audit_save_after_id = self.root.after(900, self._audit_save_now)

    def _audit_save_now(self) -> None:
        self._audit_save_after_id = None
        if self._audit_current_id is None:
            return
        findings = []
        for w in self._audit_finding_widgets:
            try:
                findings.append({
                    "finding":  w["finding_var"].get(),
                    "location": w["location_var"].get(),
                    "grade":    w["grade_var"].get(),
                    "fix":      w["fix_var"].get(),
                })
            except tk.TclError:
                continue
        title    = self._audit_title_var.get()    if self._audit_title_var    else ""
        subject  = self._audit_subject_var.get()  if self._audit_subject_var  else ""
        overall  = self._audit_overall_var.get()  if self._audit_overall_var  else ""
        mentors  = ""
        if self._audit_mentors_widget is not None:
            try:
                mentors = self._audit_mentors_widget.get("1.0", tk.END).rstrip()
            except tk.TclError:
                mentors = ""
        try:
            self._db_exec(
                "UPDATE audits SET title=?, subject=?, overall_grade=?, "
                "mentors_note=?, findings_json=?, updated_at=? WHERE id=?",
                (title, subject, overall, mentors,
                 json.dumps(findings, ensure_ascii=False),
                 datetime.now().isoformat(timespec="seconds"),
                 self._audit_current_id),
            )
        except sqlite3.Error as e:
            self.set_status(f"🔍 Audit save failed: {e}")
            return
        # Refresh the left list so a renamed title shows up immediately.
        if self._audit_listbox is not None:
            try:
                rows = self._db_query(
                    "SELECT id, title FROM audits "
                    "ORDER BY updated_at DESC"
                )
                self._audit_items = [(r[0], r[1] or "(untitled)") for r in rows]
                self._audit_listbox.delete(0, tk.END)
                for i, (aid, t) in enumerate(self._audit_items):
                    self._audit_listbox.insert(tk.END, t[:30])
                    if aid == self._audit_current_id:
                        self._audit_listbox.selection_set(i)
            except sqlite3.Error:
                pass

    # ---- Prompt journal tab --------------------------------------------
    # Schema matches docs/prompt-library/prompt-library-template.md
    # verbatim. The Iterations field is the unique value — captures the
    # refinement chain of a prompt, not just the final form.
    _PROMPT_FIELDS = (
        ("prompt",      "Prompt",         "multiline"),
        ("purpose",     "Purpose",        "single"),
        ("refs",        "References",     "single"),
        ("iterations",  "Iterations",     "multiline"),
        ("ai_tools",    "AI tools used",  "single"),
        ("input_type",  "Input Type",     "single"),
        ("output_type", "Output Type",    "single"),
        ("notes",       "Notes",          "multiline"),
    )

    def _build_tab_prompts(self, parent: tk.Frame) -> None:
        wrap = tk.Frame(parent, bg=BG_DARK)
        wrap.pack(fill=tk.BOTH, expand=True)

        # --- Left: prompt list ---------------------------------------
        left = tk.Frame(wrap, bg=BG_DARK, padx=8, pady=8)
        left.pack(side=tk.LEFT, fill=tk.Y)
        tk.Label(left, text="Prompts", bg=BG_DARK, fg=FG_MUTED,
                 font=("Segoe UI", 10, "bold")).pack(anchor=tk.W)
        list_box = tk.Listbox(
            left, width=32, height=20,
            bg=BG_INPUT, fg=FG_TEXT,
            selectbackground=ACCENT_CYAN, selectforeground="white",
            font=("Segoe UI", 10), activestyle="none",
            relief=tk.FLAT, bd=0, highlightthickness=0,
        )
        list_box.pack(fill=tk.Y, expand=True, pady=(4, 6))
        list_box.bind("<<ListboxSelect>>",
                       lambda _e: self._prompts_on_list_select())
        self._prompts_listbox = list_box

        list_btns = tk.Frame(left, bg=BG_DARK)
        list_btns.pack(fill=tk.X)
        def lb(text: str, cmd, color: str) -> tk.Button:
            return tk.Button(
                list_btns, text=text, command=cmd,
                font=("Segoe UI", 9, "bold"),
                bg=color, fg="white", activebackground=color,
                relief=tk.FLAT, padx=8, pady=4,
                cursor="hand2", borderwidth=0,
            )
        lb("+ New",     self._prompts_new,           ACCENT_GREEN
           ).pack(side=tk.LEFT, padx=(0, 4))
        lb("Delete",   self._prompts_delete_current, ACCENT_RED
           ).pack(side=tk.LEFT, padx=4)
        lb("Refresh",  self._refresh_tab_prompts,    ACCENT_SLATE
           ).pack(side=tk.LEFT, padx=4)
        # Export below — full-width row to stand apart from list actions
        tk.Button(left, text="⤓ Export CSV",
                  command=self._prompts_export_csv,
                  bg=ACCENT_CYAN, fg="white",
                  font=("Segoe UI", 9, "bold"),
                  relief=tk.FLAT, padx=8, pady=4,
                  cursor="hand2", borderwidth=0
                  ).pack(fill=tk.X, pady=(8, 0))

        # --- Right: detail pane (scrollable) -------------------------
        right_holder = tk.Frame(wrap, bg=BG_DARK, padx=8, pady=8)
        right_holder.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        canvas = tk.Canvas(right_holder, bg=BG_DARK,
                            highlightthickness=0, borderwidth=0)
        psb = tk.Scrollbar(right_holder, command=canvas.yview)
        canvas.configure(yscrollcommand=psb.set)
        psb.pack(side=tk.RIGHT, fill=tk.Y)
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        right = tk.Frame(canvas, bg=BG_DARK)
        right_id = canvas.create_window((0, 0), window=right, anchor="nw")
        def _on_right_config(_e=None):
            canvas.configure(scrollregion=canvas.bbox("all"))
            canvas.itemconfigure(right_id, width=canvas.winfo_width())
        right.bind("<Configure>", _on_right_config)
        canvas.bind("<Configure>", _on_right_config)

        self._prompts_fields = {}
        for key, label, mode in self._PROMPT_FIELDS:
            tk.Label(right, text=label, bg=BG_DARK, fg=FG_MUTED,
                     font=("Segoe UI", 9, "bold")
                     ).pack(anchor=tk.W, pady=(6, 2))
            if mode == "multiline":
                # Prompt/Iterations/Notes deserve room to breathe.
                height = 6 if key == "iterations" else (5 if key == "prompt" else 3)
                w = tk.Text(right, height=height,
                            bg=BG_INPUT, fg=FG_TEXT,
                            insertbackground=FG_TEXT,
                            font=("Segoe UI", 10),
                            relief=tk.FLAT, bd=0, wrap=tk.WORD)
                w.pack(fill=tk.X)
                w.bind("<<Modified>>",
                        lambda _e, k=key: self._prompts_on_text_modified(k))
                self._prompts_fields[key] = w
            else:
                v = tk.StringVar()
                tk.Entry(right, textvariable=v,
                         bg=BG_INPUT, fg=FG_TEXT, insertbackground=FG_TEXT,
                         font=("Segoe UI", 11),
                         relief=tk.FLAT, bd=0
                         ).pack(fill=tk.X, ipady=4)
                v.trace_add("write",
                             lambda *_a, _k=key: self._prompts_schedule_save())
                self._prompts_fields[key] = v

        self._refresh_tab_prompts()

    def _prompts_on_text_modified(self, key: str) -> None:
        w = self._prompts_fields.get(key)
        if w is None:
            return
        try:
            if not w.edit_modified():
                return
            w.edit_modified(False)
        except tk.TclError:
            return
        self._prompts_schedule_save()

    def _refresh_tab_prompts(self) -> None:
        if self._prompts_listbox is None:
            return
        try:
            rows = self._db_query(
                "SELECT id, prompt, purpose FROM prompts "
                "ORDER BY updated_at DESC"
            )
        except sqlite3.Error:
            rows = []
        self._prompts_items = [(r[0], r[1] or "", r[2] or "") for r in rows]
        lb = self._prompts_listbox
        lb.delete(0, tk.END)
        for _id, prompt, purpose in self._prompts_items:
            head = (prompt[:30] + "…") if len(prompt) > 30 else prompt
            tag  = f" [{purpose}]" if purpose else ""
            lb.insert(tk.END, (head or "(empty)") + tag)
        if self._prompts_current_id is not None:
            for i, (pid, _p, _q) in enumerate(self._prompts_items):
                if pid == self._prompts_current_id:
                    lb.selection_clear(0, tk.END)
                    lb.selection_set(i)
                    lb.see(i)
                    return
        self._prompts_current_id = None
        self._prompts_clear_detail()

    def _prompts_on_list_select(self) -> None:
        if self._prompts_listbox is None:
            return
        sel = self._prompts_listbox.curselection()
        if not sel:
            return
        idx = sel[0]
        if idx >= len(self._prompts_items):
            return
        self._prompts_load(self._prompts_items[idx][0])

    def _prompts_new(self) -> None:
        now = datetime.now().isoformat(timespec="seconds")
        try:
            new_id = self._db_exec(
                "INSERT INTO prompts (prompt, purpose, refs, iterations, "
                "ai_tools, input_type, output_type, notes, "
                "created_at, updated_at) "
                "VALUES (?,?,?,?,?,?,?,?,?,?)",
                ("", "", "", "", "", "Text", "Text", "", now, now),
            )
        except sqlite3.Error as e:
            messagebox.showerror("Prompt error", str(e))
            return
        self._prompts_current_id = new_id
        self._refresh_tab_prompts()
        self._prompts_load(new_id)

    def _prompts_delete_current(self) -> None:
        if self._prompts_current_id is None:
            messagebox.showinfo("Nothing selected",
                                "Pick a prompt on the left first.")
            return
        if not messagebox.askyesno("Delete prompt?",
                                    "Permanently delete this prompt entry?"):
            return
        try:
            self._db_exec("DELETE FROM prompts WHERE id=?",
                          (self._prompts_current_id,))
        except sqlite3.Error as e:
            messagebox.showerror("Delete failed", str(e))
            return
        self._prompts_current_id = None
        self._refresh_tab_prompts()

    def _prompts_load(self, pid: int) -> None:
        try:
            rows = self._db_query(
                "SELECT prompt, purpose, refs, iterations, ai_tools, "
                "input_type, output_type, notes FROM prompts WHERE id=?",
                (pid,),
            )
        except sqlite3.Error:
            rows = []
        if not rows:
            return
        prev = self._prompts_save_after_id
        self._prompts_save_after_id = "__loading__"
        self._prompts_current_id = pid
        keys = [k for k, _l, _m in self._PROMPT_FIELDS]
        for key, value in zip(keys, rows[0]):
            w = self._prompts_fields.get(key)
            if w is None:
                continue
            if isinstance(w, tk.StringVar):
                w.set(value or "")
            else:
                try:
                    w.delete("1.0", tk.END)
                    if value:
                        w.insert("1.0", value)
                    w.edit_modified(False)
                except tk.TclError:
                    pass
        self._prompts_save_after_id = (
            None if prev == "__loading__" else prev
        )

    def _prompts_clear_detail(self) -> None:
        for key, w in self._prompts_fields.items():
            if isinstance(w, tk.StringVar):
                w.set("")
            else:
                try:
                    w.delete("1.0", tk.END)
                    w.edit_modified(False)
                except tk.TclError:
                    pass

    def _prompts_schedule_save(self) -> None:
        if self._prompts_save_after_id == "__loading__":
            return
        if self._prompts_current_id is None:
            return
        if self._prompts_save_after_id:
            try:
                self.root.after_cancel(self._prompts_save_after_id)
            except (tk.TclError, ValueError):
                pass
        self._prompts_save_after_id = self.root.after(
            900, self._prompts_save_now)

    def _prompts_save_now(self) -> None:
        self._prompts_save_after_id = None
        if self._prompts_current_id is None:
            return
        values: dict[str, str] = {}
        for key, _label, mode in self._PROMPT_FIELDS:
            w = self._prompts_fields.get(key)
            if w is None:
                values[key] = ""
                continue
            try:
                if isinstance(w, tk.StringVar):
                    values[key] = w.get()
                else:
                    values[key] = w.get("1.0", tk.END).rstrip()
            except tk.TclError:
                values[key] = ""
        try:
            self._db_exec(
                "UPDATE prompts SET prompt=?, purpose=?, refs=?, "
                "iterations=?, ai_tools=?, input_type=?, output_type=?, "
                "notes=?, updated_at=? WHERE id=?",
                (values["prompt"], values["purpose"], values["refs"],
                 values["iterations"], values["ai_tools"], values["input_type"],
                 values["output_type"], values["notes"],
                 datetime.now().isoformat(timespec="seconds"),
                 self._prompts_current_id),
            )
        except sqlite3.Error as e:
            self.set_status(f"💬 Prompt save failed: {e}")
            return
        # Refresh the listbox so a renamed prompt's preview updates.
        if self._prompts_listbox is not None:
            try:
                rows = self._db_query(
                    "SELECT id, prompt, purpose FROM prompts "
                    "ORDER BY updated_at DESC"
                )
                self._prompts_items = [(r[0], r[1] or "", r[2] or "")
                                       for r in rows]
                self._prompts_listbox.delete(0, tk.END)
                for i, (pid, prompt, purpose) in enumerate(self._prompts_items):
                    head = (prompt[:30] + "…") if len(prompt) > 30 else prompt
                    tag  = f" [{purpose}]" if purpose else ""
                    self._prompts_listbox.insert(tk.END,
                                                  (head or "(empty)") + tag)
                    if pid == self._prompts_current_id:
                        self._prompts_listbox.selection_set(i)
            except sqlite3.Error:
                pass

    def _prompts_export_csv(self) -> None:
        """Export all prompts to a CSV matching the Google Prompting
        Essentials template header row exactly. Single-column heading
        names; data rows below."""
        try:
            rows = self._db_query(
                "SELECT prompt, purpose, refs, iterations, ai_tools, "
                "input_type, output_type, notes FROM prompts "
                "ORDER BY updated_at DESC"
            )
        except sqlite3.Error as e:
            messagebox.showerror("Export failed", str(e))
            return
        if not rows:
            messagebox.showinfo("Nothing to export",
                                 "No prompts saved yet.")
            return
        out = filedialog.asksaveasfilename(
            title="Export prompts to CSV",
            defaultextension=".csv",
            initialfile="prompt-library.csv",
            filetypes=[("CSV", "*.csv"), ("All files", "*.*")],
        )
        if not out:
            return
        # Header must match the template exactly so the export round-trips
        # back into Google Sheets / Excel without column-name drift.
        headers = ["Prompt", "Purpose", "References", "Iterations",
                    "AI tools used", "Input Type", "Output Type", "Notes"]
        try:
            import csv as _csv
            with open(out, "w", newline="", encoding="utf-8") as f:
                w = _csv.writer(f)
                w.writerow(headers)
                for row in rows:
                    w.writerow(row)
        except OSError as e:
            messagebox.showerror("Export failed", str(e))
            return
        messagebox.showinfo(
            "Export complete",
            f"Exported {len(rows)} prompt{'s' if len(rows) != 1 else ''} "
            f"to:\n\n{out}",
        )
        self.set_status(f"💬 Exported {len(rows)} prompts → {os.path.basename(out)}")

    def _show_study_tab(self, key: str) -> None:
        for k, frame in self._study_tab_frames.items():
            frame.pack_forget()
            self._study_tab_buttons[k].configure(bg=BG_INPUT, fg=FG_TEXT)
        self._study_tab_frames[key].pack(fill=tk.BOTH, expand=True)
        self._study_tab_buttons[key].configure(bg=ACCENT_CYAN, fg="white")
        if key == "reader":
            # Now that the Reader tab is visible it has a real size — lay out
            # its text/chapters/notes panes.
            self._place_reader_sashes()
        refresh = getattr(self, f"_refresh_tab_{key}", None)
        if refresh:
            try:
                refresh()
            except Exception as e:
                print(f"[study] refresh {key}: {e}", file=sys.stderr)

